import { useCallback } from 'react'
import { useTranslation } from 'react-i18next'
import { useExpireChatbotSession } from './useExpireChatbotSession'
import { clearInbentaAuthCache } from '../chatbot-services/getInbentaAuth'

/**
 * Custom hook to encapsulate session expiration and warning logic for HelpChatbot.
 * Handles warning and expiration messages, and resets timers on user activity.
 */
export default function useChatbotSessionExpiration({
  sessionStarted,
  isOpen,
  loading,
  error,
  lastApiInteraction,
  addBotMessage,
  endSession,
  expireSession,
  setWarningShown,
  warningShown,
  clearChatbotSession,
  resetAuthentication,
}) {
  const { t } = useTranslation()
  const expirationMessage = t(
    'help-chatbot.bot-message.expiration-message',
    'This chat session has expired. To continue, please start a new chat.'
  )
  const expirationWarningMessage = t(
    'help-chatbot.bot-message.expiration-warning',
    'Are you still there? Inactive chats expire after 2 minutes.'
  )
  const handleExpire = useCallback(async () => {
    if (sessionStarted) {
      if (expireSession) {
        expireSession(expirationMessage)
      } else {
        // Fallback to old behavior if expireSession is not available
        endSession()
        clearChatbotSession()
        addBotMessage && addBotMessage(expirationMessage)
      }

      // Clear auth cache first before resetting authentication state, so that
      // any re-initialization triggered by resetAuthentication() starts fresh
      // rather than rehydrating the just-invalidated token
      await clearInbentaAuthCache()

      if (resetAuthentication) {
        resetAuthentication()
      }
    }
  }, [
    sessionStarted,
    expireSession,
    expirationMessage,
    endSession,
    clearChatbotSession,
    addBotMessage,
    resetAuthentication,
  ])

  // Show warning message 2 minutes before expiration
  const handleWarning = useCallback(() => {
    if (!warningShown && sessionStarted) {
      addBotMessage && addBotMessage(expirationWarningMessage)
      setWarningShown(true)
    }
  }, [warningShown, sessionStarted, addBotMessage, setWarningShown, expirationWarningMessage])

  useExpireChatbotSession(
    handleExpire,
    sessionStarted && isOpen && !loading && !error,
    lastApiInteraction,
    handleWarning,
    sessionStarted
  )
}
