import zionDebug from '@fs/zion-debug'
import { i18n } from '@fs/zion-locale'
import { translateChatbot } from '../chatbot-services/chatbot-services'

const debug = zionDebug('help:utils:translationHelpers')

/**
 * Maps FamilySearch locale codes to chatbot translation API compatible codes
 * @param {string} fsLocale - FamilySearch locale code
 * @returns {string} Mapped locale code for translation API
 */
export function mapLocaleForChatbot(fsLocale) {
  switch (fsLocale) {
    case 'zh':
      return 'zh-hant' // FamilySearch 'zh' represents Traditional Chinese
    case 'zh-hans':
      return 'zh-hans' // Explicit Simplified Chinese
    default:
      return fsLocale
  }
}

/**
 * Check if translation is needed (current language is not English)
 * @returns {boolean} True if current language is not English
 */
export function shouldTranslate() {
  return i18n.language !== 'en'
}

/**
 * Get the current language code
 * @returns {string} Current language code
 */
export function getCurrentLanguage() {
  return i18n.language
}

/**
 * Extract translated message from translation response
 * @param {Object} translationResponse - Response from translateChatbot
 * @param {string} fallback - Fallback message if translation fails
 * @returns {string} Translated message or fallback
 */
export function extractTranslatedMessage(translationResponse, fallback) {
  return translationResponse?.translation?.message || translationResponse?.translatedText || fallback
}

/**
 * Create options from related contents
 * @param {Array} relatedContents - Array of related content strings
 * @param {string} prefix - Prefix for option IDs
 * @returns {Array} Array of option objects
 */
export function createOptionsFromRelatedContents(relatedContents, prefix = 'option') {
  return relatedContents.map((content, index) => ({
    label: content,
    value: content,
    directCall: content,
    id: `${prefix}-${index}`,
    source: 'relatedContents',
  }))
}

/**
 * Map translated option labels to original option structure
 * @param {Array} originalOptions - Original options array
 * @param {Array} translatedLabels - Translated labels array
 * @returns {Array} Options with translated labels
 */
export function mapTranslatedLabels(originalOptions, translatedLabels) {
  return originalOptions.map((originalOption, index) => {
    // If we have a translated label for this option, use it
    if (index < translatedLabels.length && translatedLabels[index]) {
      return {
        ...originalOption,
        label: translatedLabels[index],
      }
    }
    return originalOption
  })
}

/**
 * Create options from translated labels
 * @param {Array} translatedLabels - Array of translated label strings
 * @param {Array} originalOptions - Original options for fallback values
 * @param {string} prefix - Prefix for option IDs
 * @returns {Array} Array of option objects
 */
export function createOptionsFromTranslatedLabels(
  translatedLabels,
  originalOptions = [],
  prefix = 'translated-option'
) {
  return translatedLabels.map((translatedLabel, index) => {
    // Try to find the corresponding original option
    const originalOption = originalOptions[index] || {}
    return {
      ...originalOption,
      label: translatedLabel,
      value: originalOption.value || translatedLabel,
      id: `${prefix}-${index}`,
      source: 'translated-options',
    }
  })
}

/**
 * Process translated options from translation response
 * @param {Object} translationResponse - Response from translateChatbot
 * @param {Array} originalOptions - Original options array
 * @param {string} prefix - Prefix for option IDs
 * @returns {Array} Processed options array
 */
export function processTranslatedOptions(translationResponse, originalOptions = [], prefix = 'translated-option') {
  let translatedOptions = []
  // Use translated related contents as options if available
  if (translationResponse?.translation?.relatedContents?.length > 0) {
    translatedOptions = translatedOptions.concat(
      createOptionsFromRelatedContents(translationResponse.translation.relatedContents, prefix)
    )
  }

  // Handle translated options from response
  if (translationResponse?.translation?.options?.length > 0) {
    const translatedLabels = translationResponse.translation.options

    if (originalOptions.length > 0) {
      // Map translated option labels back to original option structure
      // Combine with relatedContents options if present
      return [...translatedOptions, ...mapTranslatedLabels(originalOptions, translatedLabels)]
    }
    // Create options from translated labels
    translatedOptions = translatedOptions.concat(
      createOptionsFromTranslatedLabels(translatedLabels, originalOptions, prefix)
    )
  }

  // If we have any translated options (from relatedContents or options), return them
  if (translatedOptions.length > 0) {
    return translatedOptions
  }
  // Return original options if no translation available
  return originalOptions
}

/**
 * Process translated subAnswers from translation response
 * @param {Object} translationResponse - Response from translateChatbot
 * @param {Array} originalSubAnswers - Original subAnswers array
 * @returns {Array} Processed subAnswers array
 */
export function processTranslatedSubAnswers(translationResponse, originalSubAnswers = []) {
  if (translationResponse?.translation?.subAnswers?.length > 0) {
    const translatedSubAnswers = translationResponse.translation.subAnswers

    // Map translated subAnswer messages back to original subAnswer structure
    return originalSubAnswers.map((originalSubAnswer, index) => {
      if (index < translatedSubAnswers.length && translatedSubAnswers[index]) {
        return {
          ...originalSubAnswer,
          // Update both messageList (current API standard) and message field (for compatibility)
          messageList: [translatedSubAnswers[index]],
          message: translatedSubAnswers[index], // Keep message field in sync with messageList
        }
      }
      return originalSubAnswer
    })
  }

  // Return original subAnswers if no translation available
  return originalSubAnswers
}

/**
 * Translate user message (source language to English)
 * @param {string} message - User message to translate
 * @param {Object} translationParams - Translation parameters
 * @returns {Promise<{messageToSend: string, displayMessage: string}>}
 */
export async function translateUserMessage(message, translationParams) {
  if (!shouldTranslate()) {
    return { messageToSend: message, displayMessage: message }
  }

  try {
    const translatedUserMessage = await translateChatbot({
      messageData: message,
      sourceLang: i18n.language, // Keep original language for source
      targetLang: 'en',
      isUserQuestion: true,
      ...translationParams,
    })

    const messageToSend = extractTranslatedMessage(translatedUserMessage, message)

    return {
      messageToSend,
      displayMessage: message, // Keep original for display
    }
  } catch (translationError) {
    debug('Failed to translate user message, using original:', translationError)
    return { messageToSend: message, displayMessage: message }
  }
}

/**
 * Translate bot response (English to target language)
 * @param {Object} response - Bot response data
 * @param {string} originalMessage - Original bot message
 * @param {Array} originalOptions - Original options array
 * @param {Array} originalSubAnswers - Original subAnswers array
 * @param {Object} translationParams - Translation parameters
 * @param {string} optionPrefix - Prefix for translated option IDs
 * @returns {Promise<{message: string, options: Array, subAnswers: Array}>}
 */
export async function translateBotResponse(
  response,
  originalMessage,
  originalOptions = [],
  originalSubAnswers = [],
  translationParams,
  optionPrefix = 'translated-option'
) {
  if (!shouldTranslate()) {
    return { message: originalMessage, options: originalOptions, subAnswers: originalSubAnswers }
  }

  try {
    const translatedBotMessage = await translateChatbot({
      messageData: response,
      sourceLang: 'en',
      targetLang: mapLocaleForChatbot(i18n.language),
      isUserQuestion: false,
      ...translationParams,
    })

    const finalMessage = extractTranslatedMessage(translatedBotMessage, originalMessage)
    const finalOptions = processTranslatedOptions(translatedBotMessage, originalOptions, optionPrefix)
    const finalSubAnswers = processTranslatedSubAnswers(translatedBotMessage, originalSubAnswers)

    return { message: finalMessage, options: finalOptions, subAnswers: finalSubAnswers }
  } catch (translationError) {
    debug('Failed to translate bot response, using original:', translationError)
    return { message: originalMessage, options: originalOptions, subAnswers: originalSubAnswers }
  }
}
