import React, { createContext, useCallback, useContext, useMemo } from 'react'
import PropTypes from 'prop-types'
import { useTextToSpeech } from '../hooks/useTextToSpeech'
import { useSpeechToText } from '../hooks/useSpeechToText'
import { useHelpChatbotApi } from './useHelpChatbotApi'
import { useHelpChatbotConversation } from './useHelpChatbotConversation'

export const HelpChatbotAudioContext = createContext()

export function HelpChatbotAudioProvider({ children }) {
  const { accessToken, apiKey, sessionToken, chatApiUrl, speechToTextKey } = useHelpChatbotApi()
  const {
    messages,
    actions: { handleTranscript, keepAlive },
  } = useHelpChatbotConversation()

  const textToSpeechProps = useMemo(
    () => ({
      messages,
      accessToken,
      apiKey,
      sessionToken,
      chatApiUrl,
      isSTTActive: false, // Will be set after speechToTextHook is created
    }),
    [messages, accessToken, apiKey, sessionToken, chatApiUrl]
  )

  const speechToTextProps = useMemo(
    () => ({
      speechToTextKey,
      onTranscript: handleTranscript,
      showStatusOverlay: () => {}, // Could be expanded if needed
    }),
    [speechToTextKey, handleTranscript]
  )

  const speechToTextHook = useSpeechToText(speechToTextProps)

  // Update text-to-speech props with speech-to-text listening state
  const textToSpeechPropsWithSTT = useMemo(
    () => ({
      ...textToSpeechProps,
      isSTTActive: speechToTextHook.isListening,
    }),
    [textToSpeechProps, speechToTextHook.isListening]
  )

  const { isTextToSpeechEnabled, toggleTextToSpeech, handleStopAudio, disableTextToSpeech, isLoadingAudio } =
    useTextToSpeech(textToSpeechPropsWithSTT)

  const { startListening, stopListening, toggleListening } = speechToTextHook

  // Wrap user-initiated audio actions with keepAlive to ping Inbenta's server-side session timer
  const handleToggleTextToSpeech = useCallback(() => {
    keepAlive()
    toggleTextToSpeech()
  }, [keepAlive, toggleTextToSpeech])

  const handleStartListening = useCallback(() => {
    keepAlive()
    startListening()
  }, [keepAlive, startListening])

  const handleStopListening = useCallback(() => {
    keepAlive()
    stopListening()
  }, [keepAlive, stopListening])

  const handleToggleListening = useCallback(() => {
    keepAlive()
    toggleListening()
  }, [keepAlive, toggleListening])

  const contextValue = useMemo(
    () => ({
      textToSpeech: {
        isEnabled: isTextToSpeechEnabled,
        isLoading: isLoadingAudio,
        toggle: handleToggleTextToSpeech,
        disable: disableTextToSpeech,
        stopAudio: handleStopAudio,
      },
      speechToText: {
        isListening: speechToTextHook.isListening,
        isSupported: speechToTextHook.isSupported,
        transcriptionText: speechToTextHook.transcriptionText,
        usingAdvancedRecognition: speechToTextHook.usingAdvancedRecognition,
        startListening: handleStartListening,
        stopListening: handleStopListening,
        toggleListening: handleToggleListening,
      },
    }),
    [
      isTextToSpeechEnabled,
      isLoadingAudio,
      handleToggleTextToSpeech,
      disableTextToSpeech,
      handleStopAudio,
      speechToTextHook.isListening,
      speechToTextHook.isSupported,
      speechToTextHook.transcriptionText,
      speechToTextHook.usingAdvancedRecognition,
      handleStartListening,
      handleStopListening,
      handleToggleListening,
    ]
  )

  return <HelpChatbotAudioContext.Provider value={contextValue}>{children}</HelpChatbotAudioContext.Provider>
}

export function useHelpChatbotAudio() {
  const context = useContext(HelpChatbotAudioContext)

  if (!context) {
    throw new Error('useHelpChatbotAudio must be used within a HelpChatbotAudioProvider')
  }

  return context
}

HelpChatbotAudioProvider.propTypes = {
  children: PropTypes.node.isRequired,
}
