import React, { useRef, forwardRef, useImperativeHandle } from 'react'
import PropTypes from 'prop-types'
import { LayoutBand, Row, Paragraph, Separator } from '@fs/zion-ui'
import { HelpAi } from '@fs/zion-icon'
import { useTranslation } from 'react-i18next'
import ChatTextInput from './ChatTextInput'

const HelpChatbotFooter = forwardRef(({ isWelcomeState }, ref) => {
  const footerInputRef = useRef()
  const { t, i18n } = useTranslation()

  // Expose focus method to parent components
  useImperativeHandle(
    ref,
    () => ({
      focus: () => {
        if (footerInputRef.current?.focus) {
          footerInputRef.current.focus()
        }
      },
    }),
    []
  )

  return (
    <LayoutBand marginY="none" marginX="lg" maxWidth="xxs" style={{ marginTop: '-10px' }}>
      {!isWelcomeState && (
        <>
          <Separator size="xs" />
          <ChatTextInput ref={footerInputRef} />
          <Separator size="xxs" />
        </>
      )}
      <Row alignX="center" alignY="bottom" guttersX="xxs">
        <HelpAi size="xs" aria-label="Help AI icon" />
        <Paragraph size="xs" secondary>
          {/* Remove this condition to show the new footer text in all languages when the translations are in */}
          {i18n.language === 'en'
            ? t('help-chatbot.footer2', 'AI can make mistakes. Chats are not saved.')
            : t('help-chatbot.footer', 'This tool is powered by AI. Responses may be incorrect.')}
        </Paragraph>
      </Row>
    </LayoutBand>
  )
})

HelpChatbotFooter.displayName = 'HelpChatbotFooter'

HelpChatbotFooter.propTypes = {
  isWelcomeState: PropTypes.bool.isRequired,
}

export default HelpChatbotFooter
