/**
 * Screen Reader Detection and Adaptive Behavior Utilities
 *
 * Detects when screen readers are active and calculates appropriate timing
 * for focus management and content announcements.
 */
import zionDebug from '@fs/zion-debug'

const debug = zionDebug('help:utils:screenReaderDetection')

/**
 * Detects if a screen reader is likely active
 * Uses multiple detection methods for better accuracy
 * @returns {boolean} True if screen reader is likely active
 */
export function detectScreenReader() {
  // Check for common screen reader indicators
  const indicators = [
    // NVDA, JAWS, and other Windows screen readers
    () => navigator.userAgent.includes('NVDA') || navigator.userAgent.includes('JAWS'),

    // VoiceOver detection (macOS/iOS)
    () => globalThis.speechSynthesis && globalThis.speechSynthesis.getVoices().length > 0,

    // Check for assistive technology APIs
    () => 'ontouchstart' in globalThis && navigator.maxTouchPoints === 0, // iOS VoiceOver

    // Browser accessibility features
    () => globalThis.navigator.userAgent.includes('Accessibility'),

    // Reduced motion preference (common with screen reader users)
    () => globalThis.matchMedia('(prefers-reduced-motion: reduce)').matches,

    // High contrast mode (often used with screen readers)
    () => globalThis.matchMedia('(prefers-contrast: high)').matches,

    // Check for virtual cursor (screen reader navigation mode)
    () => document.activeElement && document.activeElement.tagName === 'BODY' && document.querySelector('[aria-live]'),
  ]

  // If any indicator is true, likely using screen reader
  return indicators.some((check) => {
    try {
      return check()
    } catch (error) {
      // Log detection failures for debugging - some checks may fail in certain environments
      debug('Screen reader detection check failed:', error)
      return false
    }
  })
}

/**
 * More reliable screen reader detection using focus and interaction patterns
 * This method observes user behavior to detect screen reader usage
 * @returns {Promise<boolean>} Promise that resolves with detection result
 */
export function detectScreenReaderAdvanced() {
  return new Promise((resolve) => {
    let screenReaderDetected = false
    let interactionCount = 0
    const maxChecks = 5

    // Check for screen reader specific navigation patterns
    const checkNavigation = () => {
      interactionCount++

      // Screen readers often navigate with Tab key rapidly
      const rapidTabNavigation = performance.now() - (globalThis.lastTabTime || 0) < 100

      // Screen readers use focus on non-interactive elements
      const focusOnNonInteractive =
        document.activeElement &&
        !['INPUT', 'BUTTON', 'A', 'SELECT', 'TEXTAREA'].includes(document.activeElement.tagName) &&
        document.activeElement.tabIndex === -1

      // Screen readers often trigger focus events without mouse movement
      const focusWithoutMouse = !globalThis.mouseMovementDetected && document.activeElement !== document.body

      if (rapidTabNavigation || focusOnNonInteractive || focusWithoutMouse) {
        screenReaderDetected = true
        resolve(true)
        return
      }

      if (interactionCount >= maxChecks) {
        resolve(screenReaderDetected)
      }
    }

    // Track mouse movement
    const mouseHandler = () => {
      globalThis.mouseMovementDetected = true
      document.removeEventListener('mousemove', mouseHandler)
    }

    // Track tab key timing
    const keyHandler = (e) => {
      if (e.key === 'Tab') {
        globalThis.lastTabTime = performance.now()
        checkNavigation()
      }
    }

    // Track focus changes
    const focusHandler = () => {
      checkNavigation()
    }

    document.addEventListener('mousemove', mouseHandler, { once: true })
    document.addEventListener('keydown', keyHandler)
    document.addEventListener('focusin', focusHandler)

    // Cleanup after 3 seconds
    setTimeout(() => {
      document.removeEventListener('keydown', keyHandler)
      document.removeEventListener('focusin', focusHandler)
      document.removeEventListener('mousemove', mouseHandler)
      resolve(screenReaderDetected)
    }, 3000)

    // Initial check
    setTimeout(checkNavigation, 100)
  })
}

/**
 * Calculate appropriate reading time for text content
 * Based on average reading speeds and screen reader speech rates
 * @param {string} text - Text content to calculate reading time for
 * @param {boolean} isScreenReader - Whether screen reader is detected
 * @returns {number} Estimated reading time in milliseconds
 */
export function calculateReadingTime(text, isScreenReader = false) {
  if (!text || typeof text !== 'string') return 500

  // Clean text for calculation
  const cleanText = text.replaceAll(/<[^>]*>/g, '').trim()
  const wordCount = cleanText.split(/\s+/).filter((word) => word.length > 0).length

  if (wordCount === 0) return 500

  if (isScreenReader) {
    // Screen reader users typically listen at 200-400 WPM
    // Conservative estimate: 250 WPM for comfortable listening
    const wordsPerMinute = 250
    const readingTimeMs = (wordCount / wordsPerMinute) * 60 * 1000

    // Add buffer time for processing and navigation
    const bufferTime = Math.min(1000, wordCount * 50) // 50ms per word buffer

    return Math.max(2000, readingTimeMs + bufferTime) // Minimum 2 seconds
  }

  // Visual users scan much faster
  // Conservative estimate: 300 WPM for visual scanning
  const wordsPerMinute = 300
  const readingTimeMs = (wordCount / wordsPerMinute) * 60 * 1000

  return Math.max(1000, readingTimeMs) // Minimum 1 second
}

/**
 * Enhanced reading time calculation considering message complexity
 * @param {Object} message - Message object with text, options, sources, etc.
 * @param {boolean} isScreenReader - Whether screen reader is detected
 * @returns {number} Estimated reading time in milliseconds
 */
export function calculateMessageReadingTime(message, isScreenReader = false) {
  if (!message) return 500

  let totalText = message.text || ''
  let complexityMultiplier = 1

  // Add time for options (user needs to process choices)
  if (message.options && message.options.length > 0) {
    const optionsText = message.options.map((opt) => opt.label || opt.value || '').join(' ')
    totalText += ` ${optionsText}`
    complexityMultiplier += 0.5 // Extra time to process options
  }

  // Add time for sources
  if (message.sources && message.sources.length > 0) {
    complexityMultiplier += 0.3 // Extra time to process sources
  }

  // Add time for related content
  if (message.relatedTitle) {
    totalText += ` ${message.relatedTitle}`
  }

  const baseReadingTime = calculateReadingTime(totalText, isScreenReader)
  const adjustedTime = baseReadingTime * complexityMultiplier

  // Cap maximum time to prevent excessively long delays
  const maxTime = isScreenReader ? 15000 : 8000 // 15s for SR, 8s for visual

  return Math.min(adjustedTime, maxTime)
}

/**
 * Smart focus management strategy based on screen reader detection
 * @param {boolean} isScreenReader - Whether screen reader is detected
 * @param {Object} message - Message object to calculate timing for
 * @returns {Object} Focus management strategy
 */
export function getFocusStrategy(isScreenReader, message) {
  if (!isScreenReader) {
    // Visual users get fast, efficient focus management
    return {
      shouldDelay: false,
      focusDelay: 300,
      strategy: 'immediate',
    }
  }

  // Screen reader users get content-aware timing
  const readingTime = calculateMessageReadingTime(message, true)

  return {
    shouldDelay: true,
    focusDelay: readingTime,
    strategy: 'content-aware',
    estimatedReadingTime: readingTime,
  }
}

/**
 * Initialize screen reader detection and store result
 * @returns {Promise<boolean>} Promise that resolves with detection result
 */
export async function initializeScreenReaderDetection() {
  // Combine multiple detection methods
  const basicDetection = detectScreenReader()
  const advancedDetection = await detectScreenReaderAdvanced()

  const isScreenReader = basicDetection || advancedDetection

  // Store result for other components
  globalThis.screenReaderDetected = isScreenReader

  return isScreenReader
}

/**
 * Get cached screen reader detection result
 * @returns {boolean} Whether screen reader was detected
 */
export function isScreenReaderActive() {
  return globalThis.screenReaderDetected || false
}
