// Expires chatbot session after 5 minutes of inactivity for signed-out users
import { useEffect, useRef } from 'react'
import { useUser } from '@fs/zion-user'
import { SESSION_CONFIG } from '../config/session-config'

export function useExpireChatbotSession(onExpire, isSessionActive, lastApiInteraction, onWarning, sessionStarted) {
  const { userLoading, signedIn } = useUser()
  const timerRef = useRef()
  const warningTimeoutRef = useRef()
  const warningShownRef = useRef(false)

  // Reset warningShown when lastApiInteraction or sessionStarted changes (i.e., user reactivates or new session)
  useEffect(() => {
    warningShownRef.current = false
  }, [lastApiInteraction, sessionStarted])

  useEffect(() => {
    const clearAll = () => {
      if (timerRef.current) clearTimeout(timerRef.current)
      if (warningTimeoutRef.current) clearTimeout(warningTimeoutRef.current)
    }

    if (userLoading || !isSessionActive) {
      clearAll()
      return clearAll
    }

    // Configure timeout based on user authentication status
    const timeoutMs = signedIn ? SESSION_CONFIG.SIGNED_IN_TIMEOUT_MS : SESSION_CONFIG.GUEST_TIMEOUT_MS
    const warningMs = SESSION_CONFIG.WARNING_TIME_MS
    const now = Date.now()
    const msSinceLastApi = lastApiInteraction ? now - lastApiInteraction : 0
    const msToExpire = Math.max(timeoutMs - msSinceLastApi, 0)
    const msToWarn = Math.max(msToExpire - warningMs, 0)

    clearAll()

    if (onWarning && msToWarn > 0) {
      warningTimeoutRef.current = setTimeout(() => {
        if (!warningShownRef.current) {
          warningShownRef.current = true
          onWarning()
        }
      }, msToWarn)
    }

    timerRef.current = setTimeout(() => {
      onExpire()
    }, msToExpire)

    return clearAll
  }, [userLoading, signedIn, isSessionActive, lastApiInteraction, onExpire, onWarning])
}
