import zionDebug from '@fs/zion-debug'
import {
  sendMessage,
  extractSourcesFromResponse,
  isResponseInTargetLanguage,
} from '../chatbot-services/chatbot-services'
import { handleAnswerType } from '../chatbot-services/handleAnswerType'
import { translateBotResponse, shouldTranslate, getCurrentLanguage } from './translationHelpers'
import { trackGenerativeAiEvent } from './generativeAiHelpers'

const debug = zionDebug('help:utils:conversationHelpers')

/**
 * Process bot response with generative AI sources and smart translation
 * @param {Object} response - Bot response from API
 * @param {Object} translationParams - Translation parameters
 * @returns {Promise<Object>} Processed response with sources, translation, and combined message
 */
export async function processBotResponseWithGenAI(response, translationParams) {
  const { mainMessage, options, subAnswers, hasRatings, rateCode, isAiGenerated } = handleAnswerType(response)
  const originalMessage = mainMessage
  const originalOptions = options || []
  const originalSubAnswers = subAnswers || []

  // Extract sources from RAG 2.0 embedded context (replaces old getSources API call)
  const sources = extractSourcesFromResponse(response)

  // Determine if translation is needed based on source language detection
  const needsTranslation = shouldTranslate() && !isResponseInTargetLanguage(sources, getCurrentLanguage())

  let finalMessage = originalMessage
  let finalOptions = originalOptions
  let finalSubAnswers = originalSubAnswers

  if (needsTranslation) {
    const {
      message: translatedMessage,
      options: translatedOptions,
      subAnswers: translatedSubAnswers,
    } = await translateBotResponse(
      response,
      finalMessage,
      originalOptions,
      originalSubAnswers,
      translationParams,
      'translated-option'
    )

    finalMessage = translatedMessage
    finalOptions = translatedOptions
    finalSubAnswers = translatedSubAnswers
  } else {
    debug(`Skipping translation - response already in target language: ${getCurrentLanguage()}`)
  }

  // Combine subAnswers with main message for display
  let displayMessageWithSubAnswers = finalMessage
  if (finalSubAnswers.length > 0) {
    const subAnswerTexts = finalSubAnswers
      .map((subAnswer) => {
        // Only use messageList, no fallback to deprecated message field
        if (Array.isArray(subAnswer.messageList) && subAnswer.messageList.length > 0) {
          return subAnswer.messageList.join('')
        }
        return ''
      })
      .filter(Boolean)
    if (subAnswerTexts.length > 0) {
      // If main message is empty, use subAnswers as the main content
      // If main message has content, append subAnswers to it
      if (!finalMessage.trim()) {
        displayMessageWithSubAnswers = subAnswerTexts.join('')
      } else {
        displayMessageWithSubAnswers = finalMessage + subAnswerTexts.join('')
      }
    }
  }

  return {
    displayMessage: displayMessageWithSubAnswers,
    finalOptions,
    finalSubAnswers,
    sources, // RAG 2.0 sources from embedded context
    hasGenerativeAi: sources.length > 0, // Has AI content if sources present
    response,
    apiParams: translationParams,
    hasRatings,
    rateCode,
    isAiGenerated,
    translationSkipped: !needsTranslation, // Flag for debugging
  }
}

/**
 * Send message and process response with generative AI support
 * @param {Object} messagePayload - Message to send
 * @param {Object} translationParams - Translation parameters
 * @param {Function} safeDispatch - Dispatch function
 * @param {Object} actionTypes - Action types for dispatching
 * @returns {Promise<void>}
 */
export async function sendMessageAndProcess(messagePayload, translationParams, safeDispatch, actionTypes) {
  const { accessToken, sessionToken, chatApiUrl, apiKey } = translationParams

  const response = await sendMessage({
    accessToken,
    sessionToken,
    message: messagePayload,
    chatApiUrl,
    apiKey,
  })

  const {
    displayMessage,
    finalOptions,
    finalSubAnswers,
    sources,
    hasGenerativeAi,
    response: originalResponse,
    apiParams,
    hasRatings,
    rateCode,
    isAiGenerated,
  } = await processBotResponseWithGenAI(response, translationParams)

  safeDispatch({
    type: actionTypes.SEND_MESSAGE_SUCCESS,
    payload: {
      message: displayMessage,
      options: finalOptions,
      subAnswers: finalSubAnswers,
      sources,
      hasRatings,
      rateCode,
      isAiGenerated,
    },
  })

  // Track generative AI events if applicable
  // Possibly causing scrolling issue
  if (hasGenerativeAi) {
    await trackGenerativeAiEvent(originalResponse, apiParams)
  }
}
