import Cache from '@fs/zion-cache'
import zionDebug from '@fs/zion-debug'
import { getSpeechToTextKey } from './chatbot-services'

const debug = zionDebug('help:services:speechToTextKeyCache')
const speechCache = new Cache({ storeName: 'speechToTextKey' })

/**
 * Get cached speech-to-text key or fetch a new one if expired
 * @param {Object} params - Parameters for fetching the key
 * @param {string} params.accessToken - Access token
 * @param {string} params.apiKey - API key
 * @param {string} params.sessionToken - Session token
 * @param {string} params.chatApiUrl - Chat API URL
 * @returns {Promise<string|null>} Speech-to-text key or null if failed
 */
export async function getCachedSpeechToTextKey({ accessToken, apiKey, sessionToken, chatApiUrl }) {
  try {
    // Check cache first
    const cachedData = await speechCache.getItem('speechToTextKey')

    // Add buffer time to prevent edge cases with token expiration
    const bufferSeconds = 30 // 30 second buffer
    const currentTime = Date.now()

    if (cachedData?.key && cachedData.expiresAt > currentTime + bufferSeconds * 1000) {
      return cachedData.key
    }

    // Fetch new key
    const response = await getSpeechToTextKey({
      accessToken,
      apiKey,
      sessionToken,
      chatApiUrl,
    })

    // Cache the new key if it has the expected structure
    if (response?.data?.key && response?.data?.expiresAt) {
      const cacheData = {
        key: response.data.key,
        expiresAt: response.data.expiresAt,
      }
      await speechCache.setItem('speechToTextKey', cacheData)
      return response.data.key
    }

    // If response doesn't have expected structure, return it as is for backward compatibility
    return response
  } catch (error) {
    debug('Error getting speech-to-text key:', error)
    throw error
  }
}

/**
 * Clear the cached speech-to-text key
 */
export async function clearCachedSpeechToTextKey() {
  try {
    await speechCache.removeItem('speechToTextKey')
  } catch (error) {
    debug('Error clearing cached speech-to-text key:', error)
  }
}
