/**
 * Extracts standalone links from HTML content and returns cleaned HTML + link data
 * A "standalone link" is a link that appears on its own line or paragraph,
 * not embedded within other text.
 *
 * @param {string} html - The HTML content to process
 * @returns {{ cleanedHtml: string, links: Array<{url: string, text: string}> }}
 */
export function extractStandaloneLinks(html) {
  if (!html) {
    return { cleanedHtml: html, links: [] }
  }

  const links = []
  const matchesToRemove = []

  // Pattern to match paragraphs or divs that contain only a link (with optional whitespace)
  // This matches: <p><a href="...">text</a></p> or <p>  <a href="...">text</a>  </p>
  const standaloneLinksPattern = /<(p|div)[^>]*>\s*<a\s+href=["']([^"']+)["'][^>]*>([^<]+)<\/a>\s*<\/(p|div)>/gi

  // Collect all standalone link matches
  const standaloneMatches = Array.from(html.matchAll(standaloneLinksPattern))
  standaloneMatches.forEach((match) => {
    const [fullMatch, , url, text] = match
    links.push({ url, text: text.trim() })
    matchesToRemove.push(fullMatch)
  })

  // Also match bare links not wrapped in paragraphs
  // Pattern: <a href="...">text</a> when surrounded by newlines or at start/end
  // Note: Input is trusted HTML from Inbenta API, not user-provided
  const bareLinksPattern = /(^|\n)[ \t]*<a[ \t]+href=["']([^"']+)["'][^>]*?>([^<]+)<\/a>[ \t]*($|\n)/gi
  const bareMatches = Array.from(html.matchAll(bareLinksPattern))
  bareMatches.forEach((match) => {
    const [fullMatch, before, url, text, after] = match
    // Only extract if we haven't already found this URL
    if (!links.some((link) => link.url === url)) {
      links.push({ url, text: text.trim() })
      matchesToRemove.push({ fullMatch, replacement: before + after })
    }
  })

  // Remove all matched patterns from the HTML
  let cleanedHtml = html
  matchesToRemove.forEach((item) => {
    if (typeof item === 'string') {
      cleanedHtml = cleanedHtml.replace(item, '')
    } else {
      cleanedHtml = cleanedHtml.replace(item.fullMatch, item.replacement)
    }
  })

  // Clean up any resulting empty paragraphs or multiple consecutive line breaks
  cleanedHtml = cleanedHtml.replaceAll(/<p[^>]*>\s*<\/p>/gi, '')
  cleanedHtml = cleanedHtml.replaceAll(/\n\s*\n\s*\n/g, '\n\n')
  cleanedHtml = cleanedHtml.trim()

  return { cleanedHtml, links }
}
