import React, { createContext, useCallback, useContext, useEffect, useMemo, useRef, useReducer } from 'react'
import PropTypes from 'prop-types'
import zionDebug from '@fs/zion-debug'
import { useFeatureFlag } from '@fs/zion-flags'
import getInbentaAuth from '../chatbot-services/getInbentaAuth'
import { getChatApiUrl, scheduleTokenRefresh } from '../chatbot-services/chatbot-services'

const debug = zionDebug('help:context:HelpChatbotApiContext')

const API_ACTION_TYPES = {
  INITIALIZE_START: 'INITIALIZE_START',
  INITIALIZE_SUCCESS: 'INITIALIZE_SUCCESS',
  INITIALIZE_ERROR: 'INITIALIZE_ERROR',
  UPDATE_ACCESS_TOKEN: 'UPDATE_ACCESS_TOKEN',
  SET_SESSION_TOKEN: 'SET_SESSION_TOKEN',
  SET_SPEECH_TO_TEXT_KEY: 'SET_SPEECH_TO_TEXT_KEY',
  CLEAR_SESSION: 'CLEAR_SESSION',
  RESET_AUTHENTICATION: 'RESET_AUTHENTICATION',
}

const initialApiState = {
  apiKey: '',
  accessToken: '',
  chatApiUrl: '',
  sessionToken: '',
  speechToTextKey: null,
  initialized: false,
  initializing: false,
  error: null,
}

function apiReducer(state, action) {
  switch (action.type) {
    case API_ACTION_TYPES.INITIALIZE_START:
      return {
        ...state,
        initializing: true,
        error: null,
      }

    case API_ACTION_TYPES.INITIALIZE_SUCCESS:
      return {
        ...state,
        apiKey: action.payload.apiKey,
        accessToken: action.payload.accessToken,
        chatApiUrl: action.payload.chatApiUrl,
        initialized: true,
        initializing: false,
        error: null,
      }

    case API_ACTION_TYPES.INITIALIZE_ERROR:
      return {
        ...state,
        initializing: false,
        error: action.payload.error,
      }

    case API_ACTION_TYPES.UPDATE_ACCESS_TOKEN:
      return {
        ...state,
        accessToken: action.payload.accessToken,
      }

    case API_ACTION_TYPES.SET_SESSION_TOKEN:
      return {
        ...state,
        sessionToken: action.payload.sessionToken,
      }

    case API_ACTION_TYPES.SET_SPEECH_TO_TEXT_KEY:
      return {
        ...state,
        speechToTextKey: action.payload.speechToTextKey,
      }

    case API_ACTION_TYPES.CLEAR_SESSION:
      return {
        ...state,
        sessionToken: '',
        speechToTextKey: null,
      }

    case API_ACTION_TYPES.RESET_AUTHENTICATION:
      return {
        ...initialApiState,
      }

    default:
      throw new Error(`Unhandled action type: ${action.type}`)
  }
}

export const HelpChatbotApiContext = createContext()

export function HelpChatbotApiProvider({ children }) {
  const [state, dispatch] = useReducer(apiReducer, initialApiState)
  const isMountedRef = useRef(true)
  const initializationAttemptedRef = useRef(false)

  // Feature flag controls three member-related features:
  // 1. Whether to use Zendesk test instance for English (when ON, tests member-only content)
  // 2. Whether to send isMember variable to Inbenta for content filtering (useHelpChatbotConversation)
  // 3. Whether to apply member filtering logic (useHelpChatbotConversation)
  const memberFilterFlag = useFeatureFlag('help_chatbot_member_filter')

  const safeDispatch = useCallback((action) => {
    if (isMountedRef.current) {
      dispatch(action)
    }
  }, [])

  useEffect(() => {
    return () => {
      isMountedRef.current = false
    }
  }, [])

  // Initialize APIs (auth, chat URL) - called once on mount
  const initializeApis = useCallback(async () => {
    safeDispatch({ type: API_ACTION_TYPES.INITIALIZE_START })

    try {
      // Get auth token and chat API URL
      const auth = await getInbentaAuth(false, memberFilterFlag.isOn)
      const chatApiUrl = await getChatApiUrl(auth.accessToken, auth.apiKey)

      safeDispatch({
        type: API_ACTION_TYPES.INITIALIZE_SUCCESS,
        payload: {
          apiKey: auth.apiKey,
          accessToken: auth.accessToken,
          chatApiUrl,
        },
      })

      scheduleTokenRefresh(auth, (newAccessToken) => {
        safeDispatch({
          type: API_ACTION_TYPES.UPDATE_ACCESS_TOKEN,
          payload: { accessToken: newAccessToken },
        })
      })

      return true
    } catch (error) {
      debug('Error initializing chatbot APIs:', error)
      safeDispatch({
        type: API_ACTION_TYPES.INITIALIZE_ERROR,
        payload: {
          error: `Failed to initialize chatbot: ${error.response?.status || error.message}`,
        },
      })
      return false
    }
  }, [safeDispatch, memberFilterFlag.isOn])

  const setSessionToken = useCallback(
    (sessionToken) => {
      safeDispatch({
        type: API_ACTION_TYPES.SET_SESSION_TOKEN,
        payload: { sessionToken },
      })
    },
    [safeDispatch]
  )

  const setSpeechToTextKey = useCallback(
    (speechToTextKey) => {
      safeDispatch({
        type: API_ACTION_TYPES.SET_SPEECH_TO_TEXT_KEY,
        payload: { speechToTextKey },
      })
    },
    [safeDispatch]
  )

  const clearSession = useCallback(() => {
    safeDispatch({ type: API_ACTION_TYPES.CLEAR_SESSION })
  }, [safeDispatch])

  const resetAuthentication = useCallback(() => {
    safeDispatch({ type: API_ACTION_TYPES.RESET_AUTHENTICATION })
    initializationAttemptedRef.current = false
  }, [safeDispatch])

  // Initialize APIs on mount - insures only runs once unless reset
  useEffect(() => {
    if (!state.initialized && !state.initializing && !initializationAttemptedRef.current) {
      initializationAttemptedRef.current = true
      initializeApis()
    }
  }, [state.initialized, state.initializing, initializeApis])

  const contextValue = useMemo(
    () => ({
      ...state,
      actions: {
        initializeApis,
        setSessionToken,
        setSpeechToTextKey,
        clearSession,
        resetAuthentication,
      },
    }),
    [state, initializeApis, setSessionToken, setSpeechToTextKey, clearSession, resetAuthentication]
  )

  return <HelpChatbotApiContext.Provider value={contextValue}>{children}</HelpChatbotApiContext.Provider>
}

export function useHelpChatbotApi() {
  const context = useContext(HelpChatbotApiContext)

  if (!context) {
    throw new Error('useHelpChatbotApi must be used within a HelpChatbotApiProvider')
  }

  return context
}

HelpChatbotApiProvider.propTypes = {
  children: PropTypes.node.isRequired,
}
