/* The AiMessageRating is separate from MessageRating because:
 * They serve different business purposes with different data requirements
 * API contracts are fundamentally different (structured vs. custom)
 * Future evolution paths will likely diverge
 * Testing and maintenance is cleaner with separation
 * Code is more readable with clear component responsibilities
 */

import React, { useState } from 'react'
import PropTypes from 'prop-types'
import { useTranslation } from 'react-i18next'
import { ActionChip, Cell, IconButton, MultilineTextField, Paragraph, Row } from '@fs/zion-ui'
import { css } from '@linaria/core'
import { SocialLike } from '@fs/zion-icon'
import { trackAiRatingEvent } from '../chatbot-services/chatbot-services'

const FEEDBACK_TYPE = {
  POSITIVE: 'positive',
  NEGATIVE: 'negative',
}

const TEXT_MAX_LENGTH = 256
const CHAR_COUNT_THRESHOLD = 230

const charCountWarningCss = css`
  color: var(--yellow60);
`

export default function AiMessageRating({ apiParams }) {
  const { t } = useTranslation()
  const [feedbackSubmitted, setFeedbackSubmitted] = useState(false)
  const [showFeedbackForm, setShowFeedbackForm] = useState(false)
  const [sentiment, setSentiment] = useState('')
  const [feedbackText, setFeedbackText] = useState('')
  const [isSubmitting, setIsSubmitting] = useState(false)

  const handleSubmit = async () => {
    if (!sentiment) return

    setIsSubmitting(true)

    try {
      await trackAiRatingEvent({
        ...apiParams,
        value: sentiment,
        comment: feedbackText.trim(),
      })
    } catch (error) {
      console.error('Failed to submit AI rating:', error)
      // For now, we'll still mark as submitted even if the API call fails
    } finally {
      setFeedbackSubmitted(true)
      setShowFeedbackForm(false)
      setIsSubmitting(false)
    }
  }

  const handleRatingClick = (type) => {
    if (feedbackSubmitted) {
      return // Already submitted feedback
    }

    setSentiment(type)
    setShowFeedbackForm(true)
  }

  const characterCount = feedbackText.length
  const showCharCount = characterCount >= CHAR_COUNT_THRESHOLD
  const isAtLimit = characterCount >= TEXT_MAX_LENGTH

  if (feedbackSubmitted) {
    return (
      <Paragraph size="sm">
        <strong>{t('help-chatbot.rating.thank-you', 'Thanks for your feedback!')}</strong>
      </Paragraph>
    )
  }

  return (
    <div>
      {!showFeedbackForm ? (
        <Row guttersX="xxs">
          <IconButton
            size="sm"
            Icon={SocialLike}
            onClick={() => handleRatingClick(FEEDBACK_TYPE.POSITIVE)}
            aria-label={t('help-chatbot.rating.positive-aria-label', 'Positive feedback')}
            color="gray"
            emphasis="low"
          />
          <IconButton
            size="sm"
            Icon={SocialLike}
            iconDirection="backward"
            onClick={() => handleRatingClick(FEEDBACK_TYPE.NEGATIVE)}
            aria-label={t('help-chatbot.rating.negative-aria-label', 'Negative feedback')}
            color="gray"
            emphasis="low"
          />
        </Row>
      ) : (
        <Row guttersX="xxs">
          <IconButton
            size="sm"
            Icon={SocialLike}
            iconToggle={sentiment === FEEDBACK_TYPE.POSITIVE}
            disabled
            aria-label={t('help-chatbot.rating.positive-aria-label', 'Positive feedback')}
            color="gray"
            emphasis="low"
          />
          <IconButton
            size="sm"
            Icon={SocialLike}
            iconDirection="backward"
            iconToggle={sentiment === FEEDBACK_TYPE.NEGATIVE}
            disabled
            aria-label={t('help-chatbot.rating.negative-aria-label', 'Negative feedback')}
            color="gray"
            emphasis="low"
          />

          <Cell growX>
            <MultilineTextField
              placeholder={t('help-chatbot.rating.specific-feedback-placeholder', 'Any specific feedback?')}
              rows={2}
              maxLength={TEXT_MAX_LENGTH}
              value={feedbackText}
              onChange={(e) => setFeedbackText(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && !e.shiftKey) {
                  e.preventDefault()
                  handleSubmit()
                }
              }}
              charactersRemainingLevel="never"
              multiline
            />
            <Row alignX="end">
              {showCharCount && (
                <Paragraph size="xs" secondary={!isAtLimit} growX>
                  <span className={isAtLimit ? charCountWarningCss : undefined}>
                    {characterCount}/{TEXT_MAX_LENGTH}
                  </span>
                </Paragraph>
              )}
              <ActionChip
                onClick={handleSubmit}
                disabled={isSubmitting}
                color="gray"
                label={
                  isSubmitting
                    ? t('help-chatbot.rating.submitting', 'Submitting...')
                    : t('common-ui:submit.action', 'Submit')
                }
              />
            </Row>
          </Cell>
        </Row>
      )}
    </div>
  )
}

AiMessageRating.propTypes = {
  apiParams: PropTypes.shape({
    accessToken: PropTypes.string.isRequired,
    apiKey: PropTypes.string.isRequired,
    sessionToken: PropTypes.string.isRequired,
    chatApiUrl: PropTypes.string.isRequired,
  }).isRequired,
}
