import React, { useEffect, useRef, useState } from 'react'
import { useTranslation } from 'react-i18next'
import { VisuallyHidden } from '@reach/visually-hidden'
import zionDebug from '@fs/zion-debug'
import useHelpChatbot from './context/useHelpChatbot'

const debug = zionDebug('help:HelpChatbotMessageAnnouncer')

/**
 * Extract clean text from HTML for screen reader announcements.
 * Uses DOMParser for secure HTML parsing without script execution.
 * @param {string} html - HTML content to extract text from
 * @returns {string} Clean text without HTML tags
 */
function extractTextForScreenReader(html) {
  if (!html) return ''

  try {
    // Use DOMParser instead of innerHTML for security
    const parser = new DOMParser()
    const doc = parser.parseFromString(html, 'text/html')

    // Extract text content safely
    return doc.body.textContent || doc.body.innerText || ''
  } catch (error) {
    // Fallback: return empty string instead of using vulnerable regex
    debug('Failed to parse HTML for screen reader:', error)
    return ''
  }
}

/**
 * Formats option titles for announcement
 * @param {Array} options - Array of option objects
 * @param {Function} t - Translation function
 * @returns {Object} Formatted options info
 */
function formatOptionsForAnnouncement(options, t) {
  const optionTitles = options
    .map((option) => option.title || option.label || option.value)
    .filter(Boolean)
    .slice(0, 3) // Limit to first 3 options to avoid overly long announcements

  const optionsText = optionTitles.join(', ')
  const hasMoreOptions = options.length > 3

  let announcement = t(
    'help-chatbot.announcer.bot-with-options-detailed',
    'Chatbot responded with {optionCount} options: {optionsText}',
    {
      optionCount: options.length,
      optionsText,
    }
  )

  if (hasMoreOptions) {
    announcement += t('help-chatbot.announcer.and-more', ' and {count} more', {
      count: options.length - 3,
    })
  }

  return announcement
}

/**
 * Formats sources for announcement
 * @param {Array} sources - Array of source objects
 * @param {Function} t - Translation function
 * @returns {string} Formatted sources announcement
 */
function formatSourcesForAnnouncement(sources, t) {
  const sourceTitles = sources
    .map((source) => source.title)
    .filter(Boolean)
    .slice(0, 2) // Limit source announcements
    .join(', ')

  return t('help-chatbot.announcer.bot-with-sources-detailed', 'Chatbot responded with sources: {sourceTitles}', {
    sourceTitles,
  })
}

/**
 * Determines appropriate text length based on message characteristics
 * @param {Object} message - The message object
 * @returns {number} Maximum characters to include
 */
function getTextLengthForMessage(message) {
  // Messages with options should be short summaries (user needs to focus on choices)
  if (message.options && message.options.length > 0) {
    return 80
  }

  // Messages with sources should be moderate length
  if (message.sources && message.sources.length > 0) {
    return 120
  }

  // Regular bot answers without options can be longer to provide full context
  if (message.from === 'bot' && !message.options) {
    return 300
  }

  // User messages stay short
  if (message.from === 'user') {
    return 60
  }

  return 120 // Default
}

/**
 * Handles user message announcements using enhanced announcement creation
 * @param {Object} message - The message object
 * @param {Function} t - Translation function
 * @returns {string} Formatted announcement text
 */
function formatUserMessage(message, t) {
  const announcement = createAnnouncementText('user', message, t)

  // Apply length controls for accessibility
  const maxLength = getTextLengthForMessage(message)
  if (announcement.length > maxLength + 20) {
    // +20 for "You asked: " prefix
    const cleanText = extractTextForScreenReader(message.text || '')
    const truncatedText = cleanText.substring(0, maxLength) + (cleanText.length > maxLength ? '...' : '')
    return t('help-chatbot.accessibility.user-message-announcement', 'You asked: {message}', {
      message: truncatedText,
    })
  }

  return announcement
}

/**
 * Handles bot message announcements with context
 * @param {Object} message - The message object
 * @param {Function} t - Translation function
 * @returns {string} Formatted announcement text
 */
function formatBotMessage(message, t) {
  const messageText = extractTextForScreenReader(message.text)
  const maxLength = getTextLengthForMessage(message)

  // Handle bot messages with options - keep them short and focused on options
  if (message.options && message.options.length > 0) {
    return formatBotMessageWithOptions(message, messageText, maxLength, t)
  }

  // Handle bot messages with sources
  if (message.sources && message.sources.length > 0) {
    return formatBotMessageWithSources(message, messageText, maxLength, t)
  }

  // Handle related content title
  if (message.relatedTitle && message.relatedTitle.trim()) {
    return formatBotMessageWithRelated(message, messageText, maxLength, t)
  }

  // Regular bot message - can be longer for full context
  if (messageText && messageText.length > 0) {
    const truncatedText = messageText.substring(0, maxLength) + (messageText.length > maxLength ? '...' : '')
    return t('help-chatbot.announcer.bot-message', 'Chatbot: {text}', {
      text: truncatedText,
    })
  }

  return t('help-chatbot.announcer.bot-response', 'Chatbot responded')
}

/**
 * Formats bot message with options
 * @param {Object} message - The message object
 * @param {string} messageText - Clean message text
 * @param {number} maxLength - Maximum length for this message type
 * @param {Function} t - Translation function
 * @returns {string} Formatted announcement text
 */
function formatBotMessageWithOptions(message, messageText, maxLength, t) {
  // For messages with options, prioritize the option information
  let announcement = formatOptionsForAnnouncement(message.options, t)

  // Add brief message context if available
  if (messageText && messageText.length > 0) {
    const truncatedMessage = messageText.substring(0, maxLength) + (messageText.length > maxLength ? '...' : '')
    announcement = t('help-chatbot.announcer.bot-message-with-options', 'Chatbot: {messageText}. {announcement}', {
      messageText: truncatedMessage,
      announcement,
    })
  }

  return announcement
}

/**
 * Formats bot message with sources
 * @param {Object} message - The message object
 * @param {string} messageText - Clean message text
 * @param {number} maxLength - Maximum length for this message type
 * @param {Function} t - Translation function
 * @returns {string} Formatted announcement text
 */
function formatBotMessageWithSources(message, messageText, maxLength, t) {
  let announcement = formatSourcesForAnnouncement(message.sources, t)

  if (messageText && messageText.length > 0) {
    const truncatedMessage = messageText.substring(0, maxLength) + (messageText.length > maxLength ? '...' : '')
    announcement = t('help-chatbot.announcer.bot-message-with-sources', 'Chatbot: {messageText}. {announcement}', {
      messageText: truncatedMessage,
      announcement,
    })
  }

  return announcement
}

/**
 * Formats bot message with related content
 * @param {Object} message - The message object
 * @param {string} messageText - Clean message text
 * @param {number} maxLength - Maximum length for this message type
 * @param {Function} t - Translation function
 * @returns {string} Formatted announcement text
 */
function formatBotMessageWithRelated(message, messageText, maxLength, t) {
  const relatedTitle = extractTextForScreenReader(message.relatedTitle)
  if (messageText && messageText.length > 0) {
    const truncatedMessage = messageText.substring(0, maxLength) + (messageText.length > maxLength ? '...' : '')
    return t('help-chatbot.announcer.bot-with-related', 'Chatbot: {messageText}. {relatedTitle}', {
      messageText: truncatedMessage,
      relatedTitle,
    })
  }
  return t('help-chatbot.announcer.bot-related-only', '{relatedTitle}', {
    relatedTitle,
  })
}

/**
 * Create announcement text for screen readers with message type context
 * @param {string} messageType - Type of message ('welcome', 'response', 'user', 'loading')
 * @param {string|Object} content - The message content (string) or message object
 * @param {Function} t - Translation function
 * @returns {string} Formatted announcement text
 */
function createAnnouncementText(messageType, content, t) {
  const textContent = typeof content === 'string' ? content : content?.text || ''
  const cleanText = extractTextForScreenReader(textContent)

  switch (messageType) {
    case 'welcome':
      return t('help-chatbot.accessibility.welcome-announcement', 'Welcome: {message}', { message: cleanText })
    case 'user':
      return t('help-chatbot.accessibility.user-message-announcement', 'You asked: {message}', { message: cleanText })
    case 'loading':
      return t('help-chatbot.accessibility.loading-announcement', '{message}', { message: cleanText })
    case 'response':
    default:
      return t('help-chatbot.accessibility.new-response-announcement', 'Chatbot: {message}', { message: cleanText })
  }
}

/**
 * Determines whether a message should use assertive or polite announcement
 * @param {Object} message - The message object
 * @param {boolean} isLoadingState - Whether this is a loading state announcement
 * @returns {string} 'assertive' or 'polite'
 */
function getAnnouncementLevel(message, isLoadingState = false) {
  // Loading states are informational, use polite
  if (isLoadingState) {
    return 'polite'
  }

  // User messages need immediate confirmation - use assertive
  if (message && message.from === 'user') {
    return 'assertive'
  }

  // Bot messages (including welcome) should be polite to avoid interrupting other content
  if (message && message.from === 'bot') {
    return 'polite'
  }

  // Default to polite for unknown message types
  return 'polite'
}

/**
 * Formats announcement text for screen readers with context
 * @param {Object} message - The message object
 * @param {Function} t - Translation function
 * @returns {string} Formatted announcement text
 */
function formatAnnouncement(message, t) {
  if (message.from === 'user') {
    return formatUserMessage(message, t)
  }

  if (message.from === 'bot') {
    return formatBotMessage(message, t)
  }

  return ''
}

/**
 * Component that provides accessibility announcements for help chatbot messages
 * Uses dynamic aria-live levels and contextual formatting
 */
export default function HelpChatbotMessageAnnouncer() {
  const { t } = useTranslation()
  const {
    conversationState: { messages, sending, sessionStarting },
  } = useHelpChatbot()

  const lastAnnouncedMessageRef = useRef(null)
  const [politeAnnouncement, setPoliteAnnouncement] = useState('')
  const [assertiveAnnouncement, setAssertiveAnnouncement] = useState('')
  const lastAnnouncementTextRef = useRef('')
  const isMountedRef = useRef(true)

  useEffect(() => {
    return () => {
      isMountedRef.current = false
    }
  }, [])

  useEffect(() => {
    if (messages.length === 0) return

    const lastMessage = messages.at(-1)

    // Avoid announcing the same message twice
    if (lastMessage.id === lastAnnouncedMessageRef.current) {
      return
    }

    const announcementText = formatAnnouncement(lastMessage, t)

    if (announcementText && announcementText !== lastAnnouncementTextRef.current) {
      // Set both refs immediately to prevent any duplicates
      lastAnnouncedMessageRef.current = lastMessage.id
      lastAnnouncementTextRef.current = announcementText

      // Route to appropriate aria-live region based on message type
      const announcementLevel = getAnnouncementLevel(lastMessage, false)

      if (isMountedRef.current) {
        if (announcementLevel === 'assertive') {
          setAssertiveAnnouncement(announcementText)
          setPoliteAnnouncement('')
        } else {
          setPoliteAnnouncement(announcementText)
          setAssertiveAnnouncement('')
        }
      }
    }
  }, [messages, t])

  useEffect(() => {
    if (sending) {
      const loadingText = t('help-chatbot.announcer.sending', 'Sending message...')
      if (loadingText !== lastAnnouncementTextRef.current && isMountedRef.current) {
        // Loading states are informational, use polite region
        setPoliteAnnouncement(loadingText)
        setAssertiveAnnouncement('') // Clear assertive to avoid conflicts
        lastAnnouncementTextRef.current = loadingText
      }
    } else if (sessionStarting) {
      const startingText = t('help-chatbot.announcer.starting', 'Starting conversation...')
      if (startingText !== lastAnnouncementTextRef.current && isMountedRef.current) {
        setPoliteAnnouncement(startingText)
        lastAnnouncementTextRef.current = startingText
      }
    }
  }, [sending, sessionStarting, t])

  return (
    <>
      <div aria-live="polite" data-testid="help-chatbot-announcer-polite">
        <VisuallyHidden>{politeAnnouncement}</VisuallyHidden>
      </div>
      <div aria-live="assertive" data-testid="help-chatbot-announcer-assertive">
        <VisuallyHidden>{assertiveAnnouncement}</VisuallyHidden>
      </div>
    </>
  )
}
