import Cache from '@fs/zion-cache'
import axios from '@fs/zion-axios'
import zionDebug, { debugVerbose } from '@fs/zion-debug'
import { getAnonSession } from '@fs/zion-session'

const debug = zionDebug('help:services:getInbentaAuth')
const verbose = debugVerbose('help:services:getInbentaAuth')

const cache = new Cache({ storeName: 'inbentaChat' })

let authPromise = null

export async function clearInbentaAuthCache() {
  try {
    await cache.removeItem('inbentaAuth')
  } catch (cacheError) {
    // Storage access may fail in some environments (e.g., private browsing)
    // This is not critical, so we continue without authentication cache clearing
    debug('Failed to clear Inbenta auth cache:', cacheError)
  }
}

export default async function getInbentaAuth(forceRefresh = false, useZendesk = false) {
  const session = await getAnonSession()

  // If there's already a request in progress, wait for it
  if (authPromise && !forceRefresh) {
    verbose('Auth request already in progress, waiting for it')
    return authPromise
  }
  if (session) {
    authPromise = performAuth(forceRefresh, useZendesk)

    try {
      const result = await authPromise
      return result
    } catch (error) {
      // If authentication fails completely, clear any cached data
      try {
        await cache.removeItem('inbentaAuth')
      } catch (cacheError) {
        debug('Failed to clear cache after auth failure:', cacheError)
      }
      throw error
    } finally {
      authPromise = null
    }
  }
  return null
}

async function getCachedAuthData() {
  const cachedData = await cache.getItem('inbentaAuth')

  // Add buffer time to prevent edge cases with token expiration
  const bufferSeconds = 30 // 30 second buffer
  if (cachedData?.accessToken && cachedData.expiration > Date.now() / 1000 + bufferSeconds) {
    verbose('Using cached Inbenta auth token')
    return cachedData
  }

  return null
}

function checkSessionInfo() {
  let sessionId
  if (typeof window !== 'undefined' && window.sessionStorage) {
    try {
      sessionId = window.sessionStorage.getItem('sessionId')
    } catch (e) {
      debug('SessionStorage not available:', e.message)
    }
  }
  if (!sessionId) {
    debug('No sessionId found - user may not be logged in')
  }
  return sessionId
}

async function fetchAndProcessAuthData(useZendesk = false) {
  // Use zendesk parameter when feature flag is enabled, otherwise use rag
  const queryParam = useZendesk ? 'zendesk=true' : 'rag=true'
  debug('Fetching Inbenta auth with query parameter:', queryParam)
  const response = await axios.get(`/service/help/ai-search/inbenta/chat?${queryParam}`)
  const { accessToken, expiration, apiKey } = response.data

  if (accessToken && expiration && apiKey) {
    const newAuthData = { accessToken, expiration, apiKey }
    await cache.setItem('inbentaAuth', newAuthData)
    return newAuthData
  }

  verbose('Invalid authentication response: %O', response.data)
  throw new Error('Invalid authentication response')
}

// Helper function to handle retry logic
async function handleRetry(err, retryAttempt, maxRetries, useZendesk) {
  debug('Error fetching Inbenta authentication (attempt %d): %O', retryAttempt + 1, err)

  // Add detailed error logging for 401s
  if (err.response?.status === 401) {
    debug('401 Unauthorized on FamilySearch endpoint:', {
      url: err.config?.url,
      method: err.config?.method,
      headers: err.config?.headers,
      status: err.response?.status,
      statusText: err.response?.statusText,
      responseData: err.response?.data,
      message: err.message,
    })
  }

  // Retry on 401 errors with exponential backoff
  if (err.response?.status === 401 && retryAttempt < maxRetries) {
    const delay = 2 ** retryAttempt * 1000 // 1s, 2s, 4s delays
    verbose('Retrying auth request in %dms (attempt %d/%d)', delay, retryAttempt + 1, maxRetries)

    await new Promise((resolve) => {
      setTimeout(resolve, delay)
    })
    return performAuth(true, useZendesk, retryAttempt + 1) // Force refresh on retry
  }

  throw err
}

async function performAuth(forceRefresh, useZendesk = false, retryAttempt = 0) {
  const maxRetries = 3

  try {
    // Check cache unless forcing refresh
    if (!forceRefresh) {
      const cachedData = await getCachedAuthData()
      if (cachedData) {
        return cachedData
      }
      verbose('Cached token expired or missing, fetching new one')
    } else {
      verbose('Forcing token refresh.')
    }

    // Check session info for debugging
    checkSessionInfo()

    // Make auth request and process response
    return await fetchAndProcessAuthData(useZendesk)
  } catch (err) {
    return handleRetry(err, retryAttempt, maxRetries, useZendesk)
  }
}
