import React, { useState, useRef, useEffect, useCallback, forwardRef, useImperativeHandle } from 'react'
import { useTranslation } from 'react-i18next'
import { Row, MultilineTextField, IconButton, Separator, Paragraph } from '@fs/zion-ui'
import { Arrow, MediaMicrophone, MediaVolume, NoticeLoading } from '@fs/zion-icon'
import { css } from '@linaria/core'
import zionDebug from '@fs/zion-debug'
import useHelpChatbot from './context/useHelpChatbot'

const debug = zionDebug('help:zion:help-chatbot:chat-text-input')

const TEXT_MAX_LENGTH = 256
const VISIBLE_ROWS = 4
const CHAR_COUNT_THRESHOLD = 230

const inputCardCss = css`
  border: 1px solid var(--gray40);
  border-radius: 16px;
  padding: 12px;
`

const inputCss = css`
  & div:has(div > textarea) {
    border: none;
  }
  & textarea {
    padding: 0 !important;
  }
`

const touchOptimizedCss = css`
  touch-action: manipulation;
`

const ChatTextInput = forwardRef((props, ref) => {
  const [input, setInput] = useState('')
  const { t } = useTranslation()
  const isMountedRef = useRef(true)
  const textareaRef = useRef()

  const {
    conversationState: { sending, sessionStarted, welcome },
    actions: { sendUserMessage, toggleTextToSpeech, speechToText: speechToTextActions },
    uiState: { isTextToSpeechEnabled, isLoadingAudio, speechToText },
  } = useHelpChatbot()

  useEffect(() => {
    return () => {
      isMountedRef.current = false
    }
  }, [])

  const handleSend = useCallback(async () => {
    // Use transcription text if available, otherwise use input
    const messageToSend = speechToText.transcriptionText || input
    if (!messageToSend.trim() || !sendUserMessage) return

    const currentInput = input
    setInput('')

    try {
      await sendUserMessage(messageToSend.trim())
    } catch (error) {
      // Restore input on error
      if (isMountedRef.current) {
        setInput(currentInput)
      }
      debug('Error sending message:', error)
    }
  }, [input, speechToText.transcriptionText, sendUserMessage])

  const handleSpeechToText = useCallback(async () => {
    if (!speechToText.isSupported) {
      return
    }

    if (!speechToTextActions) {
      return
    }

    try {
      await speechToTextActions.toggleListening()
    } catch (error) {
      debug('Speech recognition error:', error)
    }
  }, [speechToText.isSupported, speechToTextActions])

  // Expose focus method to parent components
  useImperativeHandle(
    ref,
    () => ({
      focus: () => {
        if (textareaRef.current) {
          textareaRef.current.focus()
        }
      },
    }),
    []
  )

  const currentLength = (speechToText.transcriptionText || input).length
  const showCharCount = currentLength >= CHAR_COUNT_THRESHOLD
  const isAtLimit = currentLength >= TEXT_MAX_LENGTH

  // Disable input until conversation is ready (session started AND welcome message received)
  const isConversationReady = sessionStarted && welcome
  const isInputDisabled = !isConversationReady || sending

  return (
    <div className={inputCardCss}>
      <div className={inputCss}>
        <MultilineTextField
          ref={textareaRef}
          dense
          placeholder={
            speechToText.isListening
              ? t('help-chatbot.listening-placeholder', 'Listening...')
              : t('help-chatbot.input-placeholder', 'Ask anything')
          }
          value={speechToText.transcriptionText || input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === 'Enter' && !e.shiftKey) {
              e.preventDefault()
              handleSend()
            }
          }}
          disabled={isInputDisabled}
          rows={1}
          maxHeight={VISIBLE_ROWS * 28}
          maxLength={TEXT_MAX_LENGTH}
          disableResize
          charactersRemainingLevel="never"
          multiline
          aria-label="Type your question or message"
        />
        <Separator size="nano" />
        <Row gutters="xxs" alignY="middle" alignX="end" className={touchOptimizedCss}>
          {showCharCount && (
            <Paragraph size="xs" secondary={!isAtLimit} growX>
              <span>
                {currentLength}/{TEXT_MAX_LENGTH}
              </span>
            </Paragraph>
          )}
          <IconButton
            title={t('help-chatbot.text-to-speech', 'Text to speech')}
            onClick={toggleTextToSpeech}
            data-testid="help-chatbot-text-to-speech"
            Icon={isLoadingAudio ? NoticeLoading : MediaVolume}
            iconToggle={!isTextToSpeechEnabled || speechToText.isListening}
            color="gray"
            size="sm"
            linkName="help-chatbot:text-to-speech"
            disabled={isLoadingAudio}
          />
          <IconButton
            onClick={handleSpeechToText}
            title={
              speechToText.isListening
                ? t('help-chatbot.stop-listening', 'Stop listening')
                : t('help-chatbot.speech-to-text', 'Speech to Text')
            }
            data-testid="help-chatbot-speech-to-text"
            Icon={MediaMicrophone}
            iconToggle={!speechToText.isListening}
            color={speechToText.isListening ? 'primary' : 'gray'}
            emphasis={speechToText.isListening ? 'high' : 'medium'}
            disabled={!speechToText.isSupported || isInputDisabled}
            linkName="help-chatbot:open-mic"
            size="sm"
          />
          <IconButton
            title={t('help-chatbot.send', 'Send')}
            onClick={handleSend}
            linkName="help-chatbot:send-message"
            data-testid="help-chatbot-send"
            Icon={Arrow}
            iconDirection="up"
            color="gray"
            emphasis="high"
            size="sm"
            disabled={!(speechToText.transcriptionText || input).trim() || isInputDisabled}
          />
        </Row>
      </div>
    </div>
  )
})

ChatTextInput.displayName = 'ChatTextInput'

export default ChatTextInput
