import zionDebug from '@fs/zion-debug'

const debug = zionDebug('help:zion:help-chatbot:AudioManager')

// Simple module state
let currentAudio = null
let currentAudioUrl = null
let currentCleanup = null

export async function playAudio(audioData) {
  // Stop any currently playing audio first
  stopAudio()

  if (!audioData || audioData.byteLength === 0) {
    return false
  }

  // Check browser compatibility for audio features
  if (typeof Audio === 'undefined' || typeof URL === 'undefined' || typeof URL.createObjectURL !== 'function') {
    debug('Browser does not support required audio APIs')
    return false
  }

  try {
    const audioBlob = new Blob([audioData], { type: 'audio/mpeg' })
    const audioUrl = URL.createObjectURL(audioBlob)
    const audio = new Audio(audioUrl)

    currentAudio = audio
    currentAudioUrl = audioUrl

    // Set up cleanup when audio ends or errors
    const cleanup = () => {
      if (currentAudioUrl) {
        URL.revokeObjectURL(currentAudioUrl)
        currentAudioUrl = null
      }
      currentAudio = null
      currentCleanup = null
    }

    // Store cleanup reference for later removal
    currentCleanup = cleanup

    audio.addEventListener('ended', cleanup)
    audio.addEventListener('error', (error) => {
      debug('Audio playback error:', error)
      cleanup()
    })

    const playPromise = audio.play()
    if (playPromise) {
      playPromise.catch((playError) => {
        debug('Failed to play audio:', playError)
        cleanup()
      })
    }

    return true
  } catch (error) {
    debug('Error creating audio:', error)
    stopAudio()
    return false
  }
}

export function stopAudio() {
  if (currentAudio && currentCleanup && typeof currentAudio.removeEventListener === 'function') {
    // Remove event listeners to prevent memory leaks
    currentAudio.removeEventListener('ended', currentCleanup)
    currentAudio.removeEventListener('error', currentCleanup)
  }

  if (currentAudio) {
    currentAudio.pause()
    currentAudio.currentTime = 0

    if (currentAudioUrl && typeof URL !== 'undefined' && typeof URL.revokeObjectURL === 'function') {
      URL.revokeObjectURL(currentAudioUrl)
      currentAudioUrl = null
    }
    currentAudio = null
  }

  currentCleanup = null
}

export function isPlaying() {
  return currentAudio && !currentAudio.paused && !currentAudio.ended
}

export function resetAudioState() {
  stopAudio()
}

// Cleanup on page unload
if (typeof window !== 'undefined') {
  window.addEventListener('beforeunload', stopAudio)
}
