import { css } from '@linaria/core'

/**
 * Shared styles for AI-generated message content
 *
 * This is needed because the AI agent that provides text is unaware of Zion UI.
 * It often creates <p> tags and other html, which is unstyled. These styles
 * provided will mimic what <Paragraph> would do.
 */
export const aiResponseCss = css`
  h1 {
    font-family: var(--font-families-body);
    font-size: var(--text-size-d);
    font-weight: 600;
    margin: 0;
    word-break: break-word;
    line-height: 1.2;
    max-width: 70ch;
    text-align: center;
    margin-inline-start: auto;
    margin-inline-end: auto;
  }
  p {
    font-family: var(--font-families-body);
    font-size: var(--text-size-b);
    margin: 0;
    word-break: break-word;
    line-height: 1.5;
    max-width: 80ch;
  }
  p + p,
  p + ol,
  p + ul,
  ol + p,
  ul + p {
    margin-top: 0.9em;
  }
  a {
    color: var(--blue70a);
    text-decoration: underline;
    text-decoration-thickness: 0.08em;
    text-underline-offset: 0.08em;
  }
`
