/**
 * Function to handle different answer types and structure them for display
 * @param {Object} response - The response object from the chatbot API
 * @returns {Object} - Structured response with mainMessage, options, subAnswers, etc.
 */
export const handleAnswerType = (response) => {
  if (!response?.answers?.length) {
    return {
      mainMessage: '',
      options: [],
      subAnswers: [],
      hasContent: false,
      answerType: undefined,
      attributes: {},
      trackingCode: {},
      hasRatings: false,
      rateCode: undefined,
      isAiGenerated: false,
    }
  }

  const allMessages = []
  const allOptions = []
  const allSubAnswers = []

  // First, extract content titles from answers that DON'T have displayable content
  // (These represent actionable options to load content, not labels for current content)
  // response.answers.forEach((answer) => {
  //   if (answer?.type === 'answer') {
  //     const hasDisplayableContent =
  //       (answer?.messageList?.length > 0 && answer.messageList.some((msg) => msg && msg.trim()))

  //     // Only extract content title as option if there's no displayable content
  //     // This means it's an actionable option, not a label for current content
  //     // if (!hasDisplayableContent) {
  //     //   const contentTitle = answer?.parameters?.contents?.title
  //     //   if (contentTitle && contentTitle.trim()) {
  //     //     allOptions.push({
  //     //       label: contentTitle,
  //     //       value: contentTitle,
  //     //       directCall: contentTitle,
  //     //       source: 'contents',
  //     //       // Include title for accessibility (ARIA Feed Pattern, live announcements)
  //     //       title: contentTitle,
  //     //     })
  //     //   }
  //     // }
  //   }
  // })

  // Filter answers that have non-empty content for message processing
  const answersWithContent = response.answers.filter(
    (answer) =>
      (answer?.messageList?.length > 0 && answer.messageList.some((msg) => msg && msg.trim())) ||
      answer?.options?.length > 0 ||
      answer?.subAnswers?.length > 0
  )

  if (!answersWithContent.length) {
    return { mainMessage: '', options: allOptions, subAnswers: [], hasContent: allOptions.length > 0 }
  }

  // Process each answer with content
  answersWithContent.forEach((answer) => {
    // Extract message
    const message = answer?.messageList?.join('')
    if (message) allMessages.push(message)

    // Extract options
    if (answer?.options) {
      allOptions.push(...answer.options.map((option) => ({ ...option, source: answer.type || 'options' })))
    }

    // Extract subAnswers
    if (answer?.subAnswers) {
      allSubAnswers.push(
        ...answer.subAnswers.map((subAnswer) => ({
          ...subAnswer,
          message: subAnswer.messageList?.join(''),
        }))
      )
    }

    // Handle related content and parameters for 'answer' types
    if (answer?.type === 'answer') {
      // Related content options
      const relatedContents = answer?.parameters?.contents?.related?.relatedContents
      if (relatedContents) {
        allOptions.push(
          ...relatedContents.map((content) => ({
            label: content.title,
            value: content.title,
            source: 'relatedContents',
            ...content,
          }))
        )
      }

      // Parameter options (excluding contents)
      if (answer?.parameters) {
        const parameterOptions = Object.entries(answer.parameters)
          .filter(([key]) => key !== 'contents')
          .map(([key, value]) => ({
            label: typeof value === 'string' ? value : key,
            value: key,
            source: 'parameters',
          }))
        allOptions.push(...parameterOptions)
      }
    }
  })

  // Combine all content into final message
  const finalMessage = allMessages.join('')

  // Extract rating attributes and tracking codes
  const firstAnswer = response.answers[0]
  const attributes = firstAnswer?.attributes || {}
  const trackingCode = firstAnswer?.parameters?.contents?.trackingCode || {}
  const hasRatings = attributes.RATINGS === 'TRUE'
  const rateCode = trackingCode.rateCode

  // Check if this is an AI-generated answer (extendedContentsAnswer type)
  const isAiGenerated = firstAnswer?.type === 'extendedContentsAnswer'

  return {
    mainMessage: finalMessage,
    options: allOptions,
    subAnswers: allSubAnswers,
    answerType: firstAnswer?.type,
    hasContent: !!(finalMessage || allOptions.length || allSubAnswers.length),
    attributes,
    trackingCode,
    hasRatings,
    rateCode,
    isAiGenerated,
  }
}
