import React, { useEffect, useRef } from 'react'
import PropTypes from 'prop-types'
import { LayoutBand, FlowGrid, Row, colors, ActionChip, Skeleton } from '@fs/zion-ui'
import { HelpAi } from '@fs/zion-icon'
import { SafeInnerHtml } from '@fs/zion-frontend-friends'
import { VisuallyHidden } from '@reach/visually-hidden'
import ChatTextInput from './ChatTextInput'
import { aiResponseCss } from './styles/aiMessageStyles'
import { isScreenReaderActive, getFocusStrategy } from './utils/screenReaderDetection'

/**
 * Skeleton version of the WelcomeScreen for loading states.
 * Shows the same structure but with skeleton placeholders for content.
 */
export function WelcomeScreenSkeleton() {
  return (
    <LayoutBand
      marginY="xs"
      marginX="sm"
      maxWidth="xxs"
      color={colors.gray00}
      growY
      alignY="middle"
      data-testid="welcome-screen-skeleton"
    >
      <FlowGrid gutters="sm">
        <Row alignX="center">
          <HelpAi size="md" color={colors.gray00} background={colors.gray100} aria-hidden="true" />
        </Row>

        <Row alignX="center">
          <Skeleton.H3 />
        </Row>

        <ChatTextInput disabled />

        <Row gutters="xs" wrap alignX="center">
          <Skeleton.Chip />
          <Skeleton.Chip />
          <Skeleton.Chip />
        </Row>
      </FlowGrid>
    </LayoutBand>
  )
}

export default function WelcomeScreen({ welcomeMessage, options, onSelectOption }) {
  const textInputRef = useRef()
  const welcomeAnnouncerRef = useRef()

  // Focus management for welcome state with screen reader detection
  useEffect(() => {
    // Announce welcome message to screen readers
    if (welcomeAnnouncerRef.current && welcomeMessage) {
      welcomeAnnouncerRef.current.textContent = `Welcome to Help Chat. ${welcomeMessage.replaceAll(/<[^>]*>/g, '')}. You can now type your question or select from the options below.`
    }

    // Calculate adaptive focus delay based on screen reader detection
    const screenReaderDetected = isScreenReaderActive()
    const { focusDelay } = getFocusStrategy(screenReaderDetected, {
      text: welcomeMessage,
      options: options || [],
    })

    // Set focus on text input after adaptive delay to allow full announcement
    const focusTimer = setTimeout(() => {
      if (textInputRef?.current?.focus) {
        textInputRef.current.focus()
      }
    }, focusDelay)

    return () => clearTimeout(focusTimer)
  }, [welcomeMessage, options])

  return (
    <LayoutBand marginY="xs" marginX="sm" maxWidth="xxs" color={colors.gray00} growY alignY="middle">
      <FlowGrid gutters="sm">
        {/* Screen Reader Live Announcer */}
        <VisuallyHidden>
          <output ref={welcomeAnnouncerRef} aria-live="polite" aria-atomic="true" />
        </VisuallyHidden>

        <Row alignX="center">
          <HelpAi size="md" color={colors.gray00} background={colors.gray100} aria-hidden="true" />
        </Row>

        {welcomeMessage ? (
          <Row alignX="center">
            <section aria-label="AI assistant welcome message">
              <SafeInnerHtml
                dirtyInput={welcomeMessage}
                className={aiResponseCss}
                options={{
                  ALLOWED_TAGS: ['h1', 'p', 'a', 'strong', 'em', 'b', 'i', 'br', 'ul', 'ol', 'li'],
                  ALLOWED_ATTR: ['href', 'target'],
                  ALLOW_DATA_ATTR: false,
                }}
              />
            </section>
          </Row>
        ) : (
          <Row alignX="center">
            <Skeleton.H3 />
          </Row>
        )}

        <ChatTextInput ref={textInputRef} />

        {options && options.length > 0 ? (
          <Row
            gutters="xs"
            wrap
            alignX="center"
            alignY="middle"
            role="region"
            aria-label={`${options.length} quick options available`}
            aria-describedby="quick-options-hint"
            data-testid="chatbot-message-options"
            data-option-count={options.length}
          >
            <VisuallyHidden id="quick-options-hint">
              Quick option buttons. Press Enter or Space to select, or Tab to navigate between options.
            </VisuallyHidden>
            {options
              .filter((option) => option && (option.label || option.value))
              .map((option, index) => (
                <ActionChip
                  key={option.value || option.label || `option-${index}`}
                  label={option.label || option.value || 'Option'}
                  onClick={() => onSelectOption(option)}
                  data-testid={`chatbot-message-option-${index}`}
                  color="gray"
                  aria-describedby={index === 0 ? 'quick-options-hint' : undefined}
                />
              ))}
          </Row>
        ) : (
          <Row gutters="xs" wrap alignX="center" alignY="middle">
            <Skeleton.Chip />
            <Skeleton.Chip />
            <Skeleton.Chip />
          </Row>
        )}
      </FlowGrid>
    </LayoutBand>
  )
}

WelcomeScreen.propTypes = {
  welcomeMessage: PropTypes.string,
  options: PropTypes.arrayOf(
    PropTypes.shape({
      label: PropTypes.string,
      value: PropTypes.string,
    })
  ),
  onSelectOption: PropTypes.func.isRequired,
}
