import zionDebug from '@fs/zion-debug'
import { trackInbentaEvent } from '../chatbot-services/chatbot-services'

const debug = zionDebug('help:utils:generativeAiHelpers')

/**
 * Helper function to extract click code from response
 * @param {Object} response - Bot response from API
 * @returns {string|undefined} Click code for tracking
 */
export function extractClickCode(response) {
  return response.answers?.[0]?.subAnswers?.[0]?.parameters?.contents?.trackingCode?.clickCode
}

/**
 * Helper function to track Inbenta events
 * @param {Object} response - Bot response from API
 * @param {Object} apiParams - API parameters (accessToken, apiKey, sessionToken, chatApiUrl)
 * @returns {Promise<void>}
 */
export async function trackGenerativeAiEvent(response, apiParams) {
  try {
    const clickCode = extractClickCode(response)
    if (clickCode) {
      await trackInbentaEvent({
        ...apiParams,
        clickCode,
      })
    }
  } catch (trackError) {
    debug('Failed to track Inbenta event:', trackError)
  }
}
