import { useEffect, useRef, useCallback } from 'react'
import zionDebug from '@fs/zion-debug'

const debug = zionDebug('help:hooks:useChatbotSessionBroadcast')

const CHANNEL_NAME = 'help-chatbot-session'

// Fingerprint messages by content (length + last message id) rather than object reference.
// BroadcastChannel.postMessage uses structured clone, so reference equality always fails across tabs.
// This fingerprint is identical on both sides of the serialization boundary.
const getMessagesFingerprint = (msgs) => {
  if (!msgs?.length) return ''
  return `${msgs.length}:${msgs[msgs.length - 1]?.id ?? ''}`
}

export const BROADCAST_EVENTS = {
  MESSAGES_UPDATED: 'MESSAGES_UPDATED',
  SESSION_EXPIRED: 'SESSION_EXPIRED',
  SESSION_STARTED: 'SESSION_STARTED',
  KEEPALIVE: 'KEEPALIVE',
  SIGNED_OUT: 'SIGNED_OUT',
}

/**
 * Cross-tab session synchronization via BroadcastChannel.
 *
 * Broadcasting tab sends events when its session state changes.
 * All other open tabs receive and mirror the state (last-writer-wins).
 *
 * @param {Object} params
 * @param {Array}    params.messages           - Current message list (to broadcast on change)
 * @param {boolean}  params.sessionStarted     - Whether the session is active in this tab
 * @param {number}   params.lastApiInteraction - Timestamp of last API call
 * @param {boolean}  params.signedIn           - Whether the user is signed in
 * @param {Function} params.syncMessages       - Dispatch SYNC_MESSAGES to update message list from another tab
 * @param {Function} params.expireSession      - Expire session in this tab when another tab expires
 * @param {Function} params.setLastApiInteraction - Sync timer from another tab's keepalive
 */
export default function useChatbotSessionBroadcast({
  messages,
  sessionStarted,
  lastApiInteraction,
  syncMessages,
  expireSession,
  setLastApiInteraction,
}) {
  const channelRef = useRef(null)
  const isMountedRef = useRef(true)
  // Track the fingerprint of the last messages we broadcast or received, to avoid re-broadcasting
  // received syncs. Fingerprint-based so it survives postMessage serialization (reference equality
  // would always fail across the structured clone boundary).
  const lastBroadcastFingerprintRef = useRef('')
  const lastBroadcastInteractionRef = useRef(null)
  // Mirror of the lastApiInteraction prop for use inside the mount-only onmessage handler.
  // Allows the handler to compare incoming timestamps against the current live value.
  const lastApiInteractionRef = useRef(lastApiInteraction)

  // Refs for mutable values used inside the onmessage handler.
  // The handler is set in a mount-only effect; without refs it would capture stale values
  // from the first render and never see updates to sessionStarted or the callbacks.
  const sessionStartedRef = useRef(sessionStarted)
  const syncMessagesRef = useRef(syncMessages)
  const expireSessionRef = useRef(expireSession)
  const setLastApiInteractionRef = useRef(setLastApiInteraction)

  useEffect(() => {
    sessionStartedRef.current = sessionStarted
  }, [sessionStarted])

  useEffect(() => {
    syncMessagesRef.current = syncMessages
  }, [syncMessages])

  useEffect(() => {
    expireSessionRef.current = expireSession
  }, [expireSession])

  useEffect(() => {
    setLastApiInteractionRef.current = setLastApiInteraction
  }, [setLastApiInteraction])

  useEffect(() => {
    lastApiInteractionRef.current = lastApiInteraction
  }, [lastApiInteraction])

  useEffect(() => {
    return () => {
      isMountedRef.current = false
    }
  }, [])

  // Open the channel once on mount, close on unmount
  useEffect(() => {
    if (!globalThis.BroadcastChannel) {
      debug('BroadcastChannel not supported in this environment')
      return undefined
    }

    const channel = new globalThis.BroadcastChannel(CHANNEL_NAME)
    channelRef.current = channel

    channel.onmessage = (event) => {
      if (!isMountedRef.current) return
      const { type, payload } = event.data || {}
      debug('Received broadcast:', type, payload)

      switch (type) {
        case BROADCAST_EVENTS.MESSAGES_UPDATED: {
          // Set the fingerprint BEFORE calling syncMessages so the subsequent broadcast
          // effect (which fires after the state update) sees it already tracked and skips
          // re-broadcasting the received messages back out — breaking the echo loop.
          if (payload?.messages) {
            const incomingFingerprint = getMessagesFingerprint(payload.messages)
            if (incomingFingerprint !== lastBroadcastFingerprintRef.current) {
              lastBroadcastFingerprintRef.current = incomingFingerprint
              syncMessagesRef.current?.(payload.messages)
            }
          }
          // Only advance the timer — never regress it. Receiving a stale timestamp (e.g. from
          // a tab that just added a warning/expiration message) must not reset warningShownRef
          // in other tabs and cause cascading re-fires. Also update the broadcast ref so this
          // timestamp is not re-broadcast back out as a KEEPALIVE echo.
          if (payload?.lastApiInteraction && payload.lastApiInteraction > (lastApiInteractionRef.current ?? 0)) {
            lastBroadcastInteractionRef.current = payload.lastApiInteraction
            setLastApiInteractionRef.current?.(payload.lastApiInteraction)
          }
          break
        }

        case BROADCAST_EVENTS.SESSION_EXPIRED: {
          if (sessionStartedRef.current) {
            expireSessionRef.current?.(payload?.expirationMessage)
          }
          break
        }

        case BROADCAST_EVENTS.KEEPALIVE: {
          // Same "only newer" rule as MESSAGES_UPDATED. Update the broadcast ref so the KEEPALIVE
          // broadcast effect doesn't echo this timestamp back out to the sending tab.
          if (payload?.lastApiInteraction && payload.lastApiInteraction > (lastApiInteractionRef.current ?? 0)) {
            lastBroadcastInteractionRef.current = payload.lastApiInteraction
            setLastApiInteractionRef.current?.(payload.lastApiInteraction)
          }
          break
        }

        case BROADCAST_EVENTS.SIGNED_OUT: {
          // Session cleanup for sign-out is handled by the existing signedIn watcher in
          // useHelpChatbotConversation.js; this broadcast just ensures all tabs get the signal promptly
          debug('Received SIGNED_OUT broadcast from another tab')
          break
        }

        default:
          break
      }
    }

    return () => {
      channel.close()
      channelRef.current = null
    }
  }, [])

  // Broadcast helper — sends to all OTHER open tabs (never to itself)
  const broadcast = useCallback((type, payload = {}) => {
    if (!channelRef.current) return
    try {
      channelRef.current.postMessage({ type, payload })
      debug('Broadcast sent:', type, payload)
    } catch (error) {
      debug('Broadcast failed:', error)
    }
  }, [])

  // Broadcast MESSAGES_UPDATED whenever messages change in this tab
  useEffect(() => {
    if (!messages || messages.length === 0) return
    const fingerprint = getMessagesFingerprint(messages)
    if (fingerprint === lastBroadcastFingerprintRef.current) return

    lastBroadcastFingerprintRef.current = fingerprint
    lastBroadcastInteractionRef.current = lastApiInteraction

    broadcast(BROADCAST_EVENTS.MESSAGES_UPDATED, { messages, lastApiInteraction })
  }, [messages, lastApiInteraction, broadcast])

  // Broadcast KEEPALIVE when lastApiInteraction changes without a full message sync
  // (e.g., from the pageshow keepAlive ping)
  useEffect(() => {
    if (!lastApiInteraction) return
    if (lastApiInteraction === lastBroadcastInteractionRef.current) return

    lastBroadcastInteractionRef.current = lastApiInteraction
    broadcast(BROADCAST_EVENTS.KEEPALIVE, { lastApiInteraction })
  }, [lastApiInteraction, broadcast])

  // Broadcast SESSION_EXPIRED when this tab expires
  const broadcastExpire = useCallback(
    (expirationMessage) => {
      broadcast(BROADCAST_EVENTS.SESSION_EXPIRED, { expirationMessage })
    },
    [broadcast]
  )

  // Broadcast SIGNED_OUT when this tab detects sign-out
  const broadcastSignedOut = useCallback(() => {
    broadcast(BROADCAST_EVENTS.SIGNED_OUT)
  }, [broadcast])

  return { broadcast, broadcastExpire, broadcastSignedOut }
}
