import React, { createContext, useCallback, useContext, useMemo, useRef, useReducer, useEffect, useState } from 'react'
import PropTypes from 'prop-types'
import zionDebug from '@fs/zion-debug'
import { useTranslation } from 'react-i18next'
import { useUser } from '@fs/zion-user'
import { usePermission } from '@fs/zion-permissions'
import { useFeatureFlag } from '@fs/zion-flags'
import {
  saveChatbotSession,
  getCachedChatbotSession,
  clearChatbotSession,
  clearLocalChatbotCache,
  LAST_INTERACTION_STORAGE_KEY,
} from '../chatbot-services/chatbotSessionCache'
import { clearInbentaAuthCache } from '../chatbot-services/getInbentaAuth'
import {
  startConversation,
  sendMessage,
  updateConversationVariable,
  getLanguageFilter,
  isCore10Language,
} from '../chatbot-services/chatbot-services'
import { handleAnswerType } from '../chatbot-services/handleAnswerType'
import { getCachedSpeechToTextKey } from '../chatbot-services/speechToTextKeyCache'
import { translateBotResponse, translateUserMessage } from '../utils/translationHelpers'
import { sendMessageAndProcess } from '../utils/conversationHelpers'
import { useHelpChatbotApi } from './useHelpChatbotApi'

const debug = zionDebug('help:context:HelpChatbotConversationContext')

const CONVERSATION_ACTION_TYPES = {
  // Session Management
  START_SESSION_LOADING: 'START_SESSION_LOADING',
  START_SESSION: 'START_SESSION',
  END_SESSION: 'END_SESSION',
  EXPIRE_SESSION: 'EXPIRE_SESSION',
  SET_SESSION_ERROR: 'SET_SESSION_ERROR',
  SET_LANGUAGE_MISMATCH: 'SET_LANGUAGE_MISMATCH',
  CLEAR_LANGUAGE_MISMATCH: 'CLEAR_LANGUAGE_MISMATCH',

  // Messages
  SEND_MESSAGE_START: 'SEND_MESSAGE_START',
  SEND_MESSAGE_SUCCESS: 'SEND_MESSAGE_SUCCESS',
  SEND_MESSAGE_ERROR: 'SEND_MESSAGE_ERROR',
  ADD_WELCOME_MESSAGE: 'ADD_WELCOME_MESSAGE',
  ADD_BOT_MESSAGE: 'ADD_BOT_MESSAGE',
  SYNC_MESSAGES: 'SYNC_MESSAGES',

  // Error Handling
  SET_ERROR: 'SET_ERROR',
  CLEAR_ERROR: 'CLEAR_ERROR',
}

const initialConversationState = {
  messages: [],
  welcome: null,
  sessionStarted: false,
  sessionStarting: false,
  sending: false,
  error: null,
  languageMismatch: null,
}

function normalizeFrom(msg) {
  let from = (msg.from || '').toLowerCase().trim()
  if (from !== 'user' && from !== 'bot') {
    from = 'bot'
  }
  return { ...msg, from }
}

function normalizeMessages(messages) {
  return (messages || []).map(normalizeFrom)
}

function conversationReducer(state, action) {
  switch (action.type) {
    case 'RESTORE_CACHED_MESSAGES': {
      const normalizedMessages = normalizeMessages(action.payload.messages)
      // Set welcome state from the first bot message when restoring from cache
      const firstBotMessage = normalizedMessages.find((msg) => msg.from === 'bot')
      const welcomeState = firstBotMessage
        ? {
            message: firstBotMessage.text,
            relatedContent: firstBotMessage.options || [],
            relatedTitle: firstBotMessage.relatedTitle,
            hasRatings: firstBotMessage.hasRatings,
            rateCode: firstBotMessage.rateCode,
            isAiGenerated: firstBotMessage.isAiGenerated,
          }
        : null
      return {
        ...state,
        messages: normalizedMessages,
        welcome: welcomeState,
      }
    }
    case CONVERSATION_ACTION_TYPES.START_SESSION_LOADING:
      return {
        ...state,
        sessionStarting: true,
        error: null,
      }
    case CONVERSATION_ACTION_TYPES.START_SESSION:
      return {
        ...state,
        sessionStarted: true,
        sessionStarting: false,
        error: null,
      }
    case CONVERSATION_ACTION_TYPES.END_SESSION:
      return {
        ...state,
        messages: [],
        welcome: null,
        sessionStarted: false,
        sessionStarting: false,
        sending: false,
        error: null,
      }
    case CONVERSATION_ACTION_TYPES.EXPIRE_SESSION: {
      const expirationMessage = normalizeFrom({
        id: `bot-expired-${Date.now()}`,
        text: action.payload.message,
        from: 'bot',
        timestamp: new Date().toISOString(),
      })
      return {
        ...state,
        messages: [expirationMessage], // Only show the expiration message
        welcome: null,
        sessionStarted: false,
        sessionStarting: false,
        sending: false,
        error: null,
      }
    }
    case CONVERSATION_ACTION_TYPES.SET_SESSION_ERROR:
      return {
        ...state,
        sessionStarting: false,
        error: action.payload.error,
      }
    case CONVERSATION_ACTION_TYPES.ADD_WELCOME_MESSAGE: {
      const welcomeMessage = normalizeFrom({
        id: `bot-${Date.now()}`,
        text: action.payload.message,
        from: 'bot',
        timestamp: new Date().toISOString(),
        options: action.payload.relatedContent || [],
        relatedTitle: action.payload.relatedTitle,
        subAnswers: [],
        hasRatings: action.payload.hasRatings,
        rateCode: action.payload.rateCode,
        isAiGenerated: action.payload.isAiGenerated,
      })
      return {
        ...state,
        messages: [welcomeMessage],
        welcome: action.payload,
      }
    }
    case CONVERSATION_ACTION_TYPES.ADD_BOT_MESSAGE: {
      const botMessage = normalizeFrom({
        id: `bot-${Date.now()}`,
        text: action.payload.message,
        from: 'bot',
        timestamp: new Date().toISOString(),
      })
      return {
        ...state,
        messages: [...state.messages, botMessage],
      }
    }
    case CONVERSATION_ACTION_TYPES.SYNC_MESSAGES: {
      // Update messages from another tab (last-writer-wins cross-tab sync)
      const normalizedMessages = normalizeMessages(action.payload.messages)
      return {
        ...state,
        messages: normalizedMessages,
      }
    }
    case CONVERSATION_ACTION_TYPES.SEND_MESSAGE_START: {
      const userMessage = normalizeFrom({
        id: `user-${Date.now()}`,
        text: action.payload.message,
        from: 'user',
        timestamp: new Date().toISOString(),
      })
      return {
        ...state,
        messages: [...state.messages, userMessage],
        sending: true,
        error: null,
      }
    }
    case CONVERSATION_ACTION_TYPES.SEND_MESSAGE_SUCCESS: {
      const botMessage = normalizeFrom({
        id: `bot-${Date.now()}`,
        text: action.payload.message,
        from: 'bot',
        timestamp: new Date().toISOString(),
        options: action.payload.options || [],
        subAnswers: action.payload.subAnswers || [],
        sources: action.payload.sources || [],
        hasRatings: action.payload.hasRatings,
        rateCode: action.payload.rateCode,
        isAiGenerated: action.payload.isAiGenerated,
      })
      return {
        ...state,
        messages: [...state.messages, botMessage],
        sending: false,
      }
    }
    case CONVERSATION_ACTION_TYPES.SEND_MESSAGE_ERROR:
      return {
        ...state,
        sending: false,
        error: action.payload.error,
      }
    case CONVERSATION_ACTION_TYPES.SET_ERROR:
      return {
        ...state,
        error: action.payload.error,
      }
    case CONVERSATION_ACTION_TYPES.CLEAR_ERROR:
      return {
        ...state,
        error: null,
      }
    case CONVERSATION_ACTION_TYPES.SET_LANGUAGE_MISMATCH:
      return {
        ...state,
        languageMismatch: {
          previousLanguage: action.payload.previousLanguage,
          currentLanguage: action.payload.currentLanguage,
          cachedSession: action.payload.cachedSession,
        },
        sessionStarting: false, // Stop loading indicator
      }
    case CONVERSATION_ACTION_TYPES.CLEAR_LANGUAGE_MISMATCH:
      return {
        ...state,
        languageMismatch: null,
      }
    default:
      throw new Error(`Unhandled action type: ${action.type}`)
  }
}

export const HelpChatbotConversationContext = createContext()

export function HelpChatbotConversationProvider({ children }) {
  const { t, i18n } = useTranslation()
  const { signedIn } = useUser()
  const [isMemberPermission] = usePermission('FtMemberUiPermission')
  // Feature flag controls member-related features:
  // 1. Whether to use Zendesk test instance (useHelpChatbotApi)
  // 2. Whether to send isMember and isAuthenticated variables to Inbenta
  // 3. Whether to apply member permission filtering
  // When OFF: sends null for both variables (they won't be sent to API)
  const memberFilterFlag = useFeatureFlag('help_chatbot_member_filter')
  const isMember = memberFilterFlag.isOn ? Boolean(isMemberPermission) : null
  const [state, dispatch] = useReducer(conversationReducer, initialConversationState)

  // Debug logging for member filter
  debug('🔍 Member filter debug:', {
    flagIsOn: memberFilterFlag.isOn,
    isMemberPermission,
    resultingIsMember: isMember,
    signedIn,
  })
  const [lastApiInteraction, setLastApiInteraction] = useState(Date.now())
  const isMountedRef = useRef(true)
  const previousSignedInRef = useRef(signedIn)
  // Per-tab ref tracking the last page_url this tab successfully sent to Inbenta.
  // Using a ref (not shared cache) prevents cross-tab URL contamination.
  const lastSentPageUrlRef = useRef(null)
  const previousMemberFilterFlagRef = useRef(memberFilterFlag.isOn)
  const {
    apiKey,
    accessToken,
    chatApiUrl,
    sessionToken,
    initializing,
    actions: { initializeApis, setSessionToken, setSpeechToTextKey, clearSession, resetAuthentication },
  } = useHelpChatbotApi()

  // Safe dispatch wrapper that checks if component is still mounted
  const safeDispatch = useCallback((action) => {
    if (isMountedRef.current) {
      dispatch(action)
    }
  }, [])

  const isAuthenticationError = useCallback((error) => {
    const status = error.response?.status
    return (
      status === 401 ||
      status === 403 ||
      (status === 400 && JSON.stringify(error.response?.data)?.includes('token')) ||
      error.message?.toLowerCase().includes('unauthorized') ||
      error.message?.toLowerCase().includes('forbidden')
    )
  }, [])

  const handleAuthenticationError = useCallback(
    async (error, operation = 'Unknown operation') => {
      debug(`Authentication error in ${operation}:`, error)

      try {
        await clearInbentaAuthCache()
        resetAuthentication()
        return t(
          'help-chatbot.error.connection-expired',
          'Connection expired. Please close and reopen the chat to continue.'
        )
      } catch (recoveryError) {
        debug('Failed to recover from authentication error:', recoveryError)
        return t(
          'help-chatbot.error.unable-to-recover',
          'Unable to recover from connection error. Please refresh the page.'
        )
      }
    },
    [resetAuthentication, t]
  )

  // Write lastApiInteraction to localStorage so other tabs and bfcache restores can sync the timer
  useEffect(() => {
    if (!lastApiInteraction) return
    try {
      globalThis.localStorage?.setItem(LAST_INTERACTION_STORAGE_KEY, String(lastApiInteraction))
    } catch (e) {
      debug('Failed to sync lastApiInteraction to localStorage:', e)
    }
  }, [lastApiInteraction])

  // Cache all messages after every change (use sessionToken from API context)
  // For signed-in users: saves to both local cache AND server preferences
  useEffect(() => {
    if (sessionToken && state.messages.length > 0) {
      const currentPageUrl = globalThis?.window?.location?.href || ''
      saveChatbotSession({
        sessionId: sessionToken,
        messages: state.messages,
        pageUrl: currentPageUrl,
        signedIn, // Enable server-side storage for signed-in users
      })
    }
  }, [sessionToken, state.messages, signedIn])

  // Detect sign-in/sign-out and handle session state changes
  useEffect(() => {
    const wasSignedIn = previousSignedInRef.current
    const isSignedOut = wasSignedIn && !signedIn
    const isSignedIn = !wasSignedIn && signedIn

    if (isSignedOut) {
      debug('Sign-out detected - clearing local cache and session state for security')
      clearLocalChatbotCache()

      // Clear React state to remove messages from UI
      // This handles both SPA scenarios (component stays mounted) and page reloads
      safeDispatch({ type: CONVERSATION_ACTION_TYPES.END_SESSION })

      // Update isAuthenticated variable in Inbenta (only when member filter flag is ON)
      if (sessionToken && memberFilterFlag.isOn) {
        updateConversationVariable({
          accessToken,
          sessionToken,
          chatApiUrl,
          apiKey,
          variableName: 'isAuthenticated',
          variableValue: '0',
          overwrite: true,
        }).catch((error) => {
          debug('Failed to update isAuthenticated variable after sign-out:', error)
        })
      }
    }

    // Update isMember and isAuthenticated variables when user signs in mid-session
    if (isSignedIn && sessionToken && memberFilterFlag.isOn) {
      debug('Sign-in detected - updating isAuthenticated variable')
      updateConversationVariable({
        accessToken,
        sessionToken,
        chatApiUrl,
        apiKey,
        variableName: 'isAuthenticated',
        variableValue: '1',
        overwrite: true,
      }).catch((error) => {
        debug('Failed to update isAuthenticated variable after sign-in:', error)
      })

      if (isMember !== null) {
        debug('Sign-in detected - updating isMember variable:', isMember)
        updateConversationVariable({
          accessToken,
          sessionToken,
          chatApiUrl,
          apiKey,
          variableName: 'isMember',
          variableValue: isMember ? '1' : '0',
          overwrite: true,
        }).catch((error) => {
          debug('Failed to update isMember variable after sign-in:', error)
        })
      }
    }

    previousSignedInRef.current = signedIn
  }, [signedIn, sessionToken, memberFilterFlag.isOn, isMember, accessToken, chatApiUrl, apiKey, safeDispatch])

  // Detect feature flag changes and update isMember variable accordingly
  useEffect(() => {
    const wasFlagOn = previousMemberFilterFlagRef.current
    const isFlagOn = memberFilterFlag.isOn
    const flagChanged = wasFlagOn !== isFlagOn

    if (flagChanged && sessionToken && state.sessionStarted) {
      if (isFlagOn && signedIn && isMember !== null) {
        // Flag turned ON: Send isMember variable for signed-in users only.
        // Anonymous user's membership status isn't confirmed, so their isMember is always '0' by default —
        // no explicit update needed. Membership status requires authentication.
        debug('Feature flag enabled - adding isMember variable:', isMember)
        updateConversationVariable({
          accessToken,
          sessionToken,
          chatApiUrl,
          apiKey,
          variableName: 'isMember',
          variableValue: isMember ? '1' : '0',
          overwrite: true,
        }).catch((error) => {
          debug('Failed to add isMember variable after flag enabled:', error)
        })
      } else if (!isFlagOn) {
        // Flag turned OFF: Reset isMember to "0" for all active sessions (signed-in and anonymous)
        debug('Feature flag disabled - setting isMember variable to "0"')
        updateConversationVariable({
          accessToken,
          sessionToken,
          chatApiUrl,
          apiKey,
          variableName: 'isMember',
          variableValue: '0',
          overwrite: true,
        }).catch((error) => {
          debug('Failed to update isMember variable after flag disabled:', error)
        })
      }
    }

    previousMemberFilterFlagRef.current = isFlagOn
    // eslint-disable-next-line react-hooks/exhaustive-deps -- state.sessionStarted is a guard condition, not a trigger
  }, [memberFilterFlag.isOn, sessionToken, signedIn, isMember, accessToken, chatApiUrl, apiKey])

  // Enhanced startSession: restore from cache if possible, else start new
  const startSession = useCallback(async () => {
    setLastApiInteraction(Date.now())

    // If API credentials are missing, initialize APIs first
    // This handles the case where resetAuthentication() was called during session expiration
    if (!apiKey || !accessToken || !chatApiUrl || initializing) {
      // Only trigger initialization if not already in progress
      if (!initializing && (!apiKey || !accessToken || !chatApiUrl)) {
        debug('API credentials missing - triggering initialization')
        // Trigger initialization and return - the effect in HelpChatbot will retry
        // once initialization completes and credentials are available
        initializeApis()
      } else {
        debug('APIs are still initializing - waiting...')
      }

      safeDispatch({ type: CONVERSATION_ACTION_TYPES.START_SESSION_LOADING })
      // Don't proceed further - let the effect retry once API is initialized
      return
    }

    safeDispatch({ type: CONVERSATION_ACTION_TYPES.START_SESSION_LOADING })

    try {
      // Restore from cache if available (cache is cleared on close)
      // Note: Language mismatch is checked before startSession is called (in HelpChatbot.js)
      // so we don't need to check for it here
      const cached = await getCachedChatbotSession(signedIn)

      if (cached?.sessionId && Array.isArray(cached.messages)) {
        setSessionToken(cached.sessionId)

        let sessionValid = true

        // Only validate session if there are actual messages to restore
        // Empty session doesn't need validation (no inactivity to reset)
        if (cached.messages.length > 0) {
          debug('Restoring session from cache - validating with Inbenta')

          // Validate session with Inbenta by sending empty message (ping)
          // This resets the inactivity timer and confirms the session still exists
          try {
            await sendMessage({
              accessToken,
              sessionToken: cached.sessionId,
              message: '',
              chatApiUrl,
              apiKey,
            })
            setLastApiInteraction(Date.now())
            debug('Session validated and reactivated successfully')
          } catch (pingError) {
            debug('Session validation failed - session expired on Inbenta backend:', pingError)
            // Session expired on Inbenta's side - clear cache and start fresh
            await clearChatbotSession(signedIn, true)
            debug('Cache cleared - falling through to start new session')
            sessionValid = false
          }
        }

        // Restore messages to UI if validation passed (or was skipped for empty session)
        if (sessionValid) {
          safeDispatch({
            type: 'RESTORE_CACHED_MESSAGES',
            payload: { messages: cached.messages },
          })
          safeDispatch({
            type: CONVERSATION_ACTION_TYPES.START_SESSION,
          })
          return
        }
      }

      // Start conversation
      const newSessionToken = await startConversation({
        accessToken,
        chatApiUrl,
        apiKey,
        isMember,
        isAuthenticated: memberFilterFlag.isOn ? signedIn : null,
        sendIsMemberVariable: memberFilterFlag.isOn,
      })
      setLastApiInteraction(Date.now())
      setSessionToken(newSessionToken)

      // Get speech-to-text key (non-blocking)
      try {
        const speechToTextKey = await getCachedSpeechToTextKey({
          accessToken,
          apiKey,
          sessionToken: newSessionToken,
          chatApiUrl,
        })
        setSpeechToTextKey(speechToTextKey)
      } catch (speechKeyError) {
        debug('Failed to get speech-to-text key, speech-to-text will be disabled:', speechKeyError)
      }

      // Get welcome message
      const response = await sendMessage({
        accessToken,
        sessionToken: newSessionToken,
        message: '',
        chatApiUrl,
        apiKey,
      })
      setLastApiInteraction(Date.now())

      const { mainMessage, options, subAnswers, hasRatings, rateCode, isAiGenerated } = handleAnswerType(response)
      let finalMessage = mainMessage || ''
      let finalOptions = options || []
      let finalSubAnswers = subAnswers || []
      const relatedTitle =
        response.answers?.find((answer) => answer?.parameters?.contents?.related?.relatedTitle)?.parameters?.contents
          ?.related?.relatedTitle || 'You might also be interested in: '

      // Translate welcome message if language is not English
      const translationParams = { apiKey, sessionToken: newSessionToken, chatApiUrl, accessToken }
      const {
        message: translatedMessage,
        options: translatedOptions,
        subAnswers: translatedSubAnswers,
      } = await translateBotResponse(
        response,
        finalMessage,
        finalOptions,
        finalSubAnswers,
        translationParams,
        'welcome-option'
      )

      finalMessage = translatedMessage
      finalOptions = translatedOptions
      finalSubAnswers = translatedSubAnswers

      // Combine translated subAnswers with main message for display
      let welcomeDisplayMessage = finalMessage
      if (finalSubAnswers.length > 0) {
        const subAnswerTexts = finalSubAnswers.map((subAnswer) => subAnswer.messageList?.join('') || '').filter(Boolean)
        if (subAnswerTexts.length > 0) {
          welcomeDisplayMessage = finalMessage + subAnswerTexts.join('')
        }
      }

      safeDispatch({
        type: CONVERSATION_ACTION_TYPES.ADD_WELCOME_MESSAGE,
        payload: {
          message: welcomeDisplayMessage,
          relatedContent: finalOptions,
          relatedTitle,
          hasRatings,
          rateCode,
          isAiGenerated,
        },
      })

      // Session is fully started when welcome message is ready
      safeDispatch({ type: CONVERSATION_ACTION_TYPES.START_SESSION })
    } catch (error) {
      debug('Conversation session error:', error)

      // Check if this is an authentication error and handle accordingly
      if (isAuthenticationError(error)) {
        const errorMessage = await handleAuthenticationError(error, 'session start')
        safeDispatch({
          type: CONVERSATION_ACTION_TYPES.SET_SESSION_ERROR,
          payload: { error: errorMessage },
        })
      } else {
        safeDispatch({
          type: CONVERSATION_ACTION_TYPES.SET_SESSION_ERROR,
          payload: {
            error: `Failed to start conversation: ${error.response?.status || error.message}`,
          },
        })
      }
    }
  }, [
    apiKey,
    accessToken,
    chatApiUrl,
    initializing,
    initializeApis,
    setSessionToken,
    setSpeechToTextKey,
    safeDispatch,
    isAuthenticationError,
    handleAuthenticationError,
    signedIn,
    isMember,
    memberFilterFlag.isOn,
  ])

  const endSession = useCallback(() => {
    safeDispatch({ type: CONVERSATION_ACTION_TYPES.END_SESSION })
    clearSession()
    clearChatbotSession(signedIn, false) // Preserve server prefs for cross-device recovery
  }, [safeDispatch, clearSession, signedIn])

  const expireSession = useCallback(
    (expirationMessage) => {
      safeDispatch({
        type: CONVERSATION_ACTION_TYPES.EXPIRE_SESSION,
        payload: { message: expirationMessage },
      })
      clearSession()
      clearChatbotSession(signedIn, false) // Preserve server prefs - other tabs/devices may still be active; getCachedChatbotSession self-cleans on next access
    },
    [safeDispatch, clearSession, signedIn]
  )

  const sendUserMessage = useCallback(
    async (message) => {
      if (!message.trim() || !sessionToken) {
        return
      }

      try {
        const translationParams = { apiKey, sessionToken, chatApiUrl, accessToken }
        const { messageToSend, displayMessage } = await translateUserMessage(message, translationParams)

        safeDispatch({
          type: CONVERSATION_ACTION_TYPES.SEND_MESSAGE_START,
          payload: { message: displayMessage },
        })

        // Update page_url on Inbenta if this tab's URL has changed since the last send
        const currentPageUrl = globalThis?.window?.location?.href || ''
        if (currentPageUrl && lastSentPageUrlRef.current !== currentPageUrl) {
          await updateConversationVariable({
            accessToken,
            sessionToken,
            chatApiUrl,
            apiKey,
            variableName: 'page_url',
            variableValue: currentPageUrl,
            overwrite: true,
          })
          lastSentPageUrlRef.current = currentPageUrl
          debug(`Updated page_url variable to: ${currentPageUrl}`)
        }

        // Update conversation variables with language filter for core10 non-English languages
        if (i18n.language && i18n.language !== 'en' && isCore10Language(i18n.language)) {
          const languageFilter = getLanguageFilter(i18n.language, message) // original user question
          const updateResult = await updateConversationVariable({
            accessToken,
            sessionToken,
            chatApiUrl,
            apiKey,
            variableName: 'sys_ai_search_filter',
            variableValue: JSON.stringify(languageFilter),
            overwrite: true,
          })

          if (updateResult === null) {
            debug('Failed to update conversation variable for language filter')
            // Continue with message sending even if variable update fails (graceful degradation)
          } else {
            debug(`Updated language filter for ${i18n.language} with original question: "${message}"`)
          }
        }

        await sendMessageAndProcess(messageToSend, translationParams, safeDispatch, CONVERSATION_ACTION_TYPES)
        setLastApiInteraction(Date.now())
      } catch (error) {
        debug('Error sending message:', error)

        if (error.isInbentaSessionExpired) {
          expireSession(
            t(
              'help-chatbot.bot-message.expiration-message',
              'This chat session has expired. To continue, please start a new chat.'
            )
          )
          return // Session is ended; no input to restore
        }
        if (isAuthenticationError(error)) {
          const errorMessage = await handleAuthenticationError(error, 'send message')
          safeDispatch({
            type: CONVERSATION_ACTION_TYPES.SEND_MESSAGE_ERROR,
            payload: { error: errorMessage },
          })
        } else {
          safeDispatch({
            type: CONVERSATION_ACTION_TYPES.SEND_MESSAGE_ERROR,
            payload: {
              error: `Failed to send message: ${error.response?.status || error.message}`,
            },
          })
        }
        throw error // Re-throw so ChatbotFooter can handle input restoration
      }
    },
    [
      sessionToken,
      apiKey,
      chatApiUrl,
      accessToken,
      safeDispatch,
      i18n.language,
      isAuthenticationError,
      expireSession,
      t,
      handleAuthenticationError,
    ]
  )

  const selectOption = useCallback(
    async (option) => {
      if (!sessionToken) {
        return
      }

      try {
        // Use the label for display and value for the actual message, but fallback to title if label is not present
        const displayText = option.label || option.title || option.value

        // Translate user message if language is not English
        const translationParams = { apiKey, sessionToken, chatApiUrl, accessToken }
        const { messageToSend: translatedUserMessage } = await translateUserMessage(displayText, translationParams)

        //  There are three possible values: message, option and direct call. Only one is used at a time. If you send more than one, the priority order is as follows: 1- direct call, 2- option, 3- message.
        const messagePayload = {
          message: translatedUserMessage,
        }

        // Dispatch with the message that should be displayed to the user
        safeDispatch({
          type: CONVERSATION_ACTION_TYPES.SEND_MESSAGE_START,
          payload: { message: displayText },
        })

        // Update page_url on Inbenta if this tab's URL has changed since the last send
        const currentPageUrl = globalThis?.window?.location?.href || ''
        if (currentPageUrl && lastSentPageUrlRef.current !== currentPageUrl) {
          await updateConversationVariable({
            accessToken,
            sessionToken,
            chatApiUrl,
            apiKey,
            variableName: 'page_url',
            variableValue: currentPageUrl,
            overwrite: true,
          })
          lastSentPageUrlRef.current = currentPageUrl
          debug(`Updated page_url variable to: ${currentPageUrl}`)
        }

        // Update conversation variables with language filter for core10 non-English languages
        if (i18n.language && i18n.language !== 'en' && isCore10Language(i18n.language)) {
          const languageFilter = getLanguageFilter(i18n.language, displayText) // original user selection
          const updateResult = await updateConversationVariable({
            accessToken,
            sessionToken,
            chatApiUrl,
            apiKey,
            variableName: 'sys_ai_search_filter',
            variableValue: JSON.stringify(languageFilter),
            overwrite: true,
          })

          if (updateResult === null) {
            debug('Failed to update conversation variable for language filter on option selection')
            // Continue with message sending even if variable update fails (graceful degradation)
          } else {
            debug(`Updated language filter for ${i18n.language} with original option: "${displayText}"`)
          }
        }

        await sendMessageAndProcess(messagePayload, translationParams, safeDispatch, CONVERSATION_ACTION_TYPES)
        setLastApiInteraction(Date.now())
      } catch (error) {
        debug('Error selecting option:', error)

        if (error.isInbentaSessionExpired) {
          expireSession(
            t(
              'help-chatbot.bot-message.expiration-message',
              'This chat session has expired. To continue, please start a new chat.'
            )
          )
          return // Session is ended; no input to restore
        }
        if (isAuthenticationError(error)) {
          const errorMessage = await handleAuthenticationError(error, 'select option')
          safeDispatch({
            type: CONVERSATION_ACTION_TYPES.SEND_MESSAGE_ERROR,
            payload: { error: errorMessage },
          })
        } else {
          safeDispatch({
            type: CONVERSATION_ACTION_TYPES.SEND_MESSAGE_ERROR,
            payload: {
              error: `Failed to select option: ${error.response?.status || error.message}`,
            },
          })
        }
        throw error
      }
    },
    [
      apiKey,
      accessToken,
      chatApiUrl,
      sessionToken,
      safeDispatch,
      i18n.language,
      isAuthenticationError,
      expireSession,
      t,
      handleAuthenticationError,
    ]
  )

  const handleTranscript = useCallback(
    (transcript) => {
      if (transcript.trim()) {
        sendUserMessage(transcript)
      }
    },
    [sendUserMessage]
  )

  const addBotMessage = useCallback(
    (message) => {
      safeDispatch({
        type: CONVERSATION_ACTION_TYPES.ADD_BOT_MESSAGE,
        payload: { message },
      })
    },
    [safeDispatch]
  )

  const clearLanguageMismatch = useCallback(() => {
    safeDispatch({ type: CONVERSATION_ACTION_TYPES.CLEAR_LANGUAGE_MISMATCH })
  }, [safeDispatch])

  const setLanguageMismatch = useCallback(
    (payload) => {
      safeDispatch({
        type: CONVERSATION_ACTION_TYPES.SET_LANGUAGE_MISMATCH,
        payload,
      })
    },
    [safeDispatch]
  )

  // Ping Inbenta to reset their server-side inactivity timer and sync our local timer.
  // Called when the user interacts with TTS or STT (actions that don't send a message but
  // constitute user activity). NOT called on bfcache restore — that reads localStorage instead.
  const keepAlive = useCallback(async () => {
    if (!sessionToken || !apiKey || !accessToken || !chatApiUrl) return

    try {
      const currentPageUrl = globalThis?.window?.location?.href || ''
      await updateConversationVariable({
        accessToken,
        sessionToken,
        chatApiUrl,
        apiKey,
        variableName: 'page_url',
        variableValue: currentPageUrl,
        overwrite: true,
      })
      lastSentPageUrlRef.current = currentPageUrl
      setLastApiInteraction(Date.now())
    } catch (error) {
      debug('keepAlive ping failed:', error)
    }
  }, [sessionToken, apiKey, accessToken, chatApiUrl])

  const syncMessages = useCallback(
    (messages) => {
      safeDispatch({
        type: CONVERSATION_ACTION_TYPES.SYNC_MESSAGES,
        payload: { messages },
      })
    },
    [safeDispatch]
  )

  // Set lastApiInteraction to a specific timestamp — used when syncing timer from another tab's broadcast
  const syncTimer = useCallback((timestamp) => {
    setLastApiInteraction(timestamp)
  }, [])

  const contextValue = useMemo(
    () => ({
      ...state,
      lastApiInteraction,
      actions: {
        startSession,
        endSession,
        expireSession,
        sendUserMessage,
        selectOption,
        handleTranscript,
        addBotMessage,
        keepAlive, // Internal: used by useHelpChatbotAudio for TTS/STT interactions
        syncMessages,
        syncTimer,
        clearError: () => safeDispatch({ type: CONVERSATION_ACTION_TYPES.CLEAR_ERROR }),
        clearLanguageMismatch,
        setLanguageMismatch,
      },
    }),
    [
      state,
      lastApiInteraction,
      startSession,
      endSession,
      expireSession,
      sendUserMessage,
      selectOption,
      handleTranscript,
      addBotMessage,
      keepAlive,
      syncMessages,
      syncTimer,
      safeDispatch,
      clearLanguageMismatch,
      setLanguageMismatch,
    ]
  )

  return (
    <HelpChatbotConversationContext.Provider value={contextValue}>{children}</HelpChatbotConversationContext.Provider>
  )
}

export function useHelpChatbotConversation() {
  const context = useContext(HelpChatbotConversationContext)

  if (!context) {
    throw new Error('useHelpChatbotConversation must be used within a HelpChatbotConversationProvider')
  }

  return context
}

HelpChatbotConversationProvider.propTypes = {
  children: PropTypes.node.isRequired,
}
