import { useMemo } from 'react'
import { useHelpChatbotApi } from './useHelpChatbotApi'
import { useHelpChatbotConversation } from './useHelpChatbotConversation'
import { useHelpChatbotAudio } from './useHelpChatbotAudio'

/**
 * Convenience hook that provides access to all help chatbot contexts.
 * This maintains backwards compatibility while allowing access to separated concerns.
 *
 * @returns {Object} Combined context with api, conversation, and audio state/actions
 */
export default function useHelpChatbot() {
  const api = useHelpChatbotApi()
  const conversation = useHelpChatbotConversation()
  const audio = useHelpChatbotAudio()

  const apiState = useMemo(
    () => ({
      apiKey: api.apiKey,
      accessToken: api.accessToken,
      chatApiUrl: api.chatApiUrl,
      sessionToken: api.sessionToken,
      speechToTextKey: api.speechToTextKey,
      initialized: api.initialized,
    }),
    [api.apiKey, api.accessToken, api.chatApiUrl, api.sessionToken, api.speechToTextKey, api.initialized]
  )

  const conversationState = useMemo(
    () => ({
      messages: conversation.messages,
      welcome: conversation.welcome,
      loading: api.initializing,
      sessionStarting: conversation.sessionStarting,
      sessionStarted: conversation.sessionStarted,
      sending: conversation.sending,
      error: conversation.error || api.error,
      lastApiInteraction: conversation.lastApiInteraction,
      languageMismatch: conversation.languageMismatch,
    }),
    [
      conversation.messages,
      conversation.welcome,
      api.initializing,
      conversation.sessionStarting,
      conversation.sessionStarted,
      conversation.sending,
      conversation.error,
      api.error,
      conversation.lastApiInteraction,
      conversation.languageMismatch,
    ]
  )

  const uiState = useMemo(
    () => ({
      isTextToSpeechEnabled: audio.textToSpeech.isEnabled,
      isLoadingAudio: audio.textToSpeech.isLoading,
      speechToText: audio.speechToText,
    }),
    [audio.textToSpeech.isEnabled, audio.textToSpeech.isLoading, audio.speechToText]
  )

  const speechToTextActions = useMemo(
    () => ({
      startListening: audio.speechToText.startListening,
      stopListening: audio.speechToText.stopListening,
      toggleListening: audio.speechToText.toggleListening,
    }),
    [audio.speechToText.startListening, audio.speechToText.stopListening, audio.speechToText.toggleListening]
  )

  const actions = useMemo(
    () => ({
      // API actions
      initializeApis: api.actions.initializeApis,

      // Conversation actions
      startSession: conversation.actions.startSession,
      endSession: conversation.actions.endSession,
      expireSession: conversation.actions.expireSession,
      sendUserMessage: conversation.actions.sendUserMessage,
      selectOption: conversation.actions.selectOption,
      addBotMessage: conversation.actions.addBotMessage,
      clearError: conversation.actions.clearError,
      clearLanguageMismatch: conversation.actions.clearLanguageMismatch,
      setLanguageMismatch: conversation.actions.setLanguageMismatch,
      syncMessages: conversation.actions.syncMessages,
      syncTimer: conversation.actions.syncTimer,

      // Audio actions
      toggleTextToSpeech: audio.textToSpeech.toggle,
      disableTextToSpeech: audio.textToSpeech.disable,
      handleStopAudio: audio.textToSpeech.stopAudio,
      speechToText: speechToTextActions,
    }),
    [
      api.actions.initializeApis,
      conversation.actions.startSession,
      conversation.actions.endSession,
      conversation.actions.expireSession,
      conversation.actions.sendUserMessage,
      conversation.actions.selectOption,
      conversation.actions.addBotMessage,
      conversation.actions.clearError,
      conversation.actions.clearLanguageMismatch,
      conversation.actions.setLanguageMismatch,
      conversation.actions.syncMessages,
      conversation.actions.syncTimer,
      audio.textToSpeech.toggle,
      audio.textToSpeech.disable,
      audio.textToSpeech.stopAudio,
      speechToTextActions,
    ]
  )

  return useMemo(
    () => ({
      // API state
      apiState,

      // Conversation state
      conversationState,

      // UI state (for backwards compatibility)
      uiState,

      // Combined actions
      actions,

      // Separated contexts for direct access when needed
      api,
      conversation,
      audio,
    }),
    [apiState, conversationState, uiState, actions, api, conversation, audio]
  )
}
