// cspell:words describedby
import React from 'react'
import PropTypes from 'prop-types'
import { useTranslation } from 'react-i18next'
import { Separator, Row, H4, Paragraph, Button, colors, LayoutBand } from '@fs/zion-ui'
import { NoticeWarning } from '@fs/zion-icon'
import { getLanguage } from '@fs/zion-standards'
import DialogContainer from './DialogContainer'

export default function LanguageChangeNotification({ previousLanguage, currentLanguage, onStartNewChat, onCancel }) {
  const { t } = useTranslation()
  const previousLangName = getLanguage(previousLanguage).primaryText
  const currentLangName = getLanguage(currentLanguage).primaryText
  // Static IDs are fine since only one instance exists per page
  const headingId = 'language-change-heading'
  const messageId = 'language-change-message'

  const helpText = t(
    'help-chatbot.language-change.help',
    'Language changed dialog. Choose how to proceed: Start a new chat in the current language or keep your existing chat by changing language back. Press Escape or Tab to navigate between options.'
  )

  return (
    <DialogContainer
      role="dialog"
      headingId={headingId}
      descriptionId={messageId}
      helpText={helpText}
      helpLabel={t('help-chatbot.language-change.help-label', 'Dialog help')}
      onEscape={onCancel}
      allowEscape
    >
      <LayoutBand marginY="lg">
        <Row alignX="center">
          <NoticeWarning size="md" color={colors.yellow50} background={colors.yellow03} aria-hidden="true" />
        </Row>
        <Separator />
        <H4 size="H5" centered balanced id={headingId}>
          {t('help-chatbot.language-change.title', 'Language Changed')}
        </H4>
        <Separator size="nano" />
        <Paragraph size="sm" centered balanced id={messageId}>
          {t(
            'help-chatbot.language-change.context',
            `Your current chat is in ${previousLangName}, but your language preference is now ${currentLangName}.`
          )}
        </Paragraph>
        <Separator />
        <Paragraph size="sm" weight="semibold" marginBottom="xs">
          {t('help-chatbot.language-change.keep-session', 'To keep this chat:')}
        </Paragraph>
        <Paragraph size="sm" marginBottom="0">
          {t('help-chatbot.language-change.keep-instruction-1', '1. Click Cancel below')}
        </Paragraph>
        <Paragraph size="sm" marginBottom="sm">
          {t('help-chatbot.language-change.keep-instruction-2', `2. Change your language back to ${previousLangName}`)}
        </Paragraph>
        <Paragraph size="sm" weight="semibold" marginBottom="xs">
          {t('help-chatbot.language-change.new-session', `To start fresh in ${currentLangName}:`)}
        </Paragraph>
        <Paragraph size="sm" marginBottom="md">
          {t('help-chatbot.language-change.new-instructions', 'Click "Start New Chat" below')}
        </Paragraph>
        <Separator />
        <Row gutters="xs" alignX="center">
          <Button onClick={onCancel} color="gray" emphasis="medium" data-testid="language-change-cancel">
            {t('help-chatbot.language-change.cancel', 'Cancel')}
          </Button>
          <Button onClick={onStartNewChat} emphasis="high" data-testid="language-change-new-chat">
            {t('help-chatbot.language-change.new-chat', 'Start New Chat')}
          </Button>
        </Row>
      </LayoutBand>
    </DialogContainer>
  )
}

LanguageChangeNotification.propTypes = {
  previousLanguage: PropTypes.string.isRequired,
  currentLanguage: PropTypes.string.isRequired,
  onStartNewChat: PropTypes.func.isRequired,
  onCancel: PropTypes.func.isRequired,
}
