// cspell:words describedby
import React from 'react'
import PropTypes from 'prop-types'
import { useTranslation } from 'react-i18next'
import { Separator, Row, H4, Paragraph, Button, colors, LayoutBand } from '@fs/zion-ui'
import { NoticeWarning, ContentCompose } from '@fs/zion-icon'
import DialogContainer from './DialogContainer'

export default function NewChatConfirmation({ onConfirm, onCancel, isSessionExpired }) {
  const { t } = useTranslation()
  // Static IDs are fine since only one instance exists per page
  const headingId = 'new-chat-heading'
  const messageId = 'new-chat-message'

  // Different content for session expiration vs. user-initiated new chat
  const heading = isSessionExpired
    ? t(
        'help-chatbot.bot-message.expiration-message',
        'This chat session has expired. To continue, please start a new chat.'
      )
    : t('help-chatbot.new-chat-confirmation.heading', 'Are you sure you want to start a new chat?')

  const message = isSessionExpired
    ? null
    : t(
        'help-chatbot.new-chat-confirmation.message',
        'If you start a new chat, your current conversation will not be saved.'
      )

  const helpText = isSessionExpired
    ? t(
        'help-chatbot.new-chat-confirmation.help-expired',
        'Session expired dialog. Press Enter or Space on New Chat button to continue, or Tab to navigate.'
      )
    : t(
        'help-chatbot.new-chat-confirmation.help',
        'New chat confirmation dialog. Choose Cancel to keep current conversation or New Chat to start over. Press Escape or Tab to navigate between options.'
      )

  return (
    <DialogContainer
      role={isSessionExpired ? 'alertdialog' : 'dialog'}
      headingId={headingId}
      descriptionId={message ? messageId : undefined}
      helpText={helpText}
      helpLabel={t('help-chatbot.new-chat-confirmation.help-label', 'Dialog help')}
      onEscape={!isSessionExpired ? onCancel : undefined}
      allowEscape={!isSessionExpired}
    >
      <LayoutBand marginY="lg">
        <Row alignX="center">
          <NoticeWarning size="md" color={colors.yellow50} background={colors.yellow03} aria-hidden="true" />
        </Row>
        <Separator />
        <H4 size="H5" centered balanced id={headingId}>
          {heading}
        </H4>
        {message && (
          <>
            <Separator size="nano" />
            <Paragraph size="sm" centered balanced id={messageId}>
              {message}
            </Paragraph>
          </>
        )}
        <Separator />
        <Row gutters="xs" alignX="center">
          {!isSessionExpired && (
            <Button
              onClick={onCancel}
              color="gray"
              emphasis="medium"
              aria-describedby={message ? messageId : undefined}
            >
              {t('common-ui:cancel.action', 'Cancel')}
            </Button>
          )}
          <Button
            onClick={onConfirm}
            color="gray"
            emphasis="high"
            Icon={ContentCompose}
            aria-describedby={message ? messageId : undefined}
          >
            {t('help-chatbot.new-chat', 'New Chat')}
          </Button>
        </Row>
      </LayoutBand>
    </DialogContainer>
  )
}

NewChatConfirmation.propTypes = {
  onConfirm: PropTypes.func.isRequired,
  onCancel: PropTypes.func.isRequired,
  isSessionExpired: PropTypes.bool,
}

NewChatConfirmation.defaultProps = {
  isSessionExpired: false,
}
