import Cache from '@fs/zion-cache'
import { getPreference, setPreference, deletePreference } from '@fs/zion-preferences'
import zionDebug from '@fs/zion-debug'
import { i18n } from '@fs/zion-locale'
import { SESSION_CONFIG } from '../config/session-config'

const debug = zionDebug('help:chatbot-session-cache')

const CHATBOT_CACHE_KEY = 'inbentaChatbotSession'
const CHATBOT_PREF_KEY = 'help-chatbot.session' // Server-side preference key
export const LAST_INTERACTION_STORAGE_KEY = 'helpChatbot_lastInteraction'

// Enable encryption to protect against direct IndexedDB access
// Uses @fs/zion-crypto with AES-CBC encryption
// Force dbName to 'fs' to maintain consistent cache location regardless of sign-in state
// This prevents cache data from being inaccessible when user signs in (which would change dbName to cisId)
const cache = new Cache({
  dbName: 'fs', // Critical: Keep consistent across sign-in transitions
  storeName: 'inbentaChatbot',
  encrypted: true,
  lifetime: SESSION_CONFIG.SIGNED_IN_TIMEOUT_MS, // Backup cleanup mechanism (30 min)
})

/**
 * Save chatbot session to dual storage:
 * - Local cache (IndexedDB) for fast access
 * - Server preferences (for signed-in users) for cross-device sync
 * @param {Object} params Session data
 * @param {string} params.sessionId The Inbenta Chatbot session ID
 * @param {Array} params.messages Array of message objects
 * @param {string} params.pageUrl Optional page URL
 * @param {boolean} params.signedIn Whether user is authenticated
 * @throws {Error} If sessionId or messages are invalid
 */
export async function saveChatbotSession({ sessionId, messages, pageUrl, signedIn = false }) {
  if (!sessionId || typeof sessionId !== 'string') {
    throw new TypeError('Invalid session data: sessionId (string) is required')
  }

  if (!Array.isArray(messages)) {
    throw new TypeError('Invalid session data: messages must be an array')
  }

  const data = {
    sessionId,
    messages,
    pageUrl: pageUrl || globalThis?.window?.location?.href || '',
    savedAt: Date.now(),
    language: i18n.language,
  }

  await cache.setItem(CHATBOT_CACHE_KEY, data)

  // For signed-in users: also save to server preferences (cross-device sync)
  if (signedIn) {
    try {
      await setPreference(CHATBOT_PREF_KEY, data)
      debug('Saved session to server preferences')
    } catch (error) {
      // Non-critical: local cache still works
      debug('Failed to save to server preferences:', error)
    }
  }
}

/**
 * Get cached chatbot session with expiration validation
 * Tries local cache first, falls back to server preferences for signed-in users
 * @param {boolean} signedIn - Whether user is authenticated
 * @returns {Promise<Object|null>} Cached session or null if expired/not found
 */
export async function getCachedChatbotSession(signedIn = false) {
  const timeoutMs = signedIn ? SESSION_CONFIG.SIGNED_IN_TIMEOUT_MS : SESSION_CONFIG.GUEST_TIMEOUT_MS

  let cached = await cache.getItem(CHATBOT_CACHE_KEY)

  // For signed-in users: fallback to server preferences if local cache miss
  if (!cached && signedIn) {
    try {
      cached = await getPreference(CHATBOT_PREF_KEY)
      if (cached) {
        debug('Restored session from server preferences')
        // Sync to local cache for faster subsequent access
        await cache.setItem(CHATBOT_CACHE_KEY, cached)
      }
    } catch (error) {
      debug('Failed to load from server preferences:', error)
    }
  }

  if (!cached) return null

  // If expired, create a new session
  const timeSinceSaved = Date.now() - (cached.savedAt || 0)

  if (timeSinceSaved > timeoutMs) {
    // clear both storages
    debug(`Session expired: ${timeSinceSaved}ms old (max ${timeoutMs}ms)`)
    await clearChatbotSession(signedIn, true)
    return null
  }

  // Check language mismatch
  const currentLanguage = i18n.language
  if (cached?.language !== currentLanguage) {
    debug(`Language mismatch: cached=${cached.language}, current=${currentLanguage}`)
    // Only persist the session if user messages exist
    const hasUserMessages = cached.messages?.some((msg) => msg.from && msg.from.toLowerCase().trim() === 'user')

    if (!hasUserMessages) {
      debug('No user messages in cached session - clearing and starting fresh')
      await clearChatbotSession(signedIn, true)
      return null
    }
    // Return session with the mismatch flag to let the user decide: new chat in new lang, or preserve the chat and return to the prev lang
    return {
      ...cached,
      languageMismatch: true,
      previousLanguage: cached.language,
      currentLanguage,
    }
  }

  return cached
}

/**
 * Clear chatbot session from local cache and optionally server preferences.
 * By default, preserves server preferences to enable cross-device session recovery.
 * @param {boolean} signedIn Whether user is authenticated
 * @param {boolean} clearServerPrefs Whether to also clear server preferences (default: false to preserve cross-device recovery)
 */
export async function clearChatbotSession(signedIn = false, clearServerPrefs = false) {
  // Always clear local cache
  await cache.removeItem(CHATBOT_CACHE_KEY)

  // Only clear server preferences if explicitly requested (e.g., session expired or user deletes chat)
  if (signedIn && clearServerPrefs) {
    try {
      await deletePreference(CHATBOT_PREF_KEY)
      debug('Cleared session from server preferences')
    } catch (error) {
      // Non-critical: local cache already cleared
      debug('Failed to clear server preferences:', error)
    }
  }
}

/**
 * Clear local cache only (preserves server preferences for cross-device recovery).
 * Should be called on sign-out to prevent data leakage between users on shared browsers.
 */
export async function clearLocalChatbotCache() {
  await cache.removeItem(CHATBOT_CACHE_KEY)
  debug('Cleared local chatbot cache')
}
