import { useState, useRef, useCallback, useEffect } from 'react'
import zionDebug from '@fs/zion-debug'
import { getTextToSpeech } from '../chatbot-services/chatbot-services'
import { playAudio, stopAudio } from '../utils/AudioManager'

const debug = zionDebug('help:zion:help-chatbot:useSpeech')

export function useTextToSpeech({ messages, accessToken, apiKey, sessionToken, chatApiUrl, isSTTActive = false }) {
  const [isTextToSpeechEnabled, setIsTextToSpeechEnabled] = useState(false)
  const [isLoadingAudio, setIsLoadingAudio] = useState(false)
  const lastSpokenMessageIdRef = useRef(null)

  const handleTextToSpeech = useCallback(async () => {
    const lastBotMessage = messages
      .slice()
      .reverse()
      .find((msg) => msg.from === 'bot' && msg.text && msg.text.trim())

    if (!lastBotMessage) return

    try {
      setIsLoadingAudio(true)

      let textToSpeak = lastBotMessage.text || ''

      // Add options to the text if they exist
      if (lastBotMessage.options && lastBotMessage.options.length > 0) {
        const optionsText = lastBotMessage.options
          .map((option, index) => `Option ${index + 1}: ${option.label}`)
          .join('. ')

        textToSpeak += `. ${optionsText}`
      }

      if (!textToSpeak.trim()) {
        setIsLoadingAudio(false)
        return
      }

      const audioData = await getTextToSpeech({
        text: textToSpeak,
        accessToken,
        apiKey,
        sessionToken,
        chatApiUrl,
      })

      const success = await playAudio(audioData)
      if (success) {
        lastSpokenMessageIdRef.current = lastBotMessage.id
      }
    } catch (err) {
      debug('Failed to play text to speech:', err)
    } finally {
      setIsLoadingAudio(false)
    }
  }, [messages, accessToken, apiKey, sessionToken, chatApiUrl])

  const handleStopAudio = useCallback(() => {
    stopAudio()
  }, [])

  const toggleTextToSpeech = useCallback(() => {
    const newSpeechState = !isTextToSpeechEnabled
    setIsTextToSpeechEnabled(newSpeechState)

    if (!newSpeechState) {
      handleStopAudio()
      // Reset the last spoken message ID so the same message can be played again when speech is re-enabled
      lastSpokenMessageIdRef.current = null
    }
  }, [isTextToSpeechEnabled, handleStopAudio])

  const disableTextToSpeech = useCallback(() => {
    setIsTextToSpeechEnabled(false)
  }, [])

  // Auto-speak new bot messages when TTS is enabled AND STT is not active
  useEffect(() => {
    if (!isTextToSpeechEnabled || isSTTActive) return

    const lastBotMessage = messages
      .slice()
      .reverse()
      .find((msg) => msg.from === 'bot' && msg.text && msg.text.trim())

    if (lastBotMessage && lastBotMessage.id !== lastSpokenMessageIdRef.current) {
      // Call handleTextToSpeech directly to avoid dependency loop
      const speakMessage = async () => {
        try {
          setIsLoadingAudio(true)

          let textToSpeak = lastBotMessage.text || ''

          // Add options to the text if they exist
          if (lastBotMessage.options && lastBotMessage.options.length > 0) {
            const optionsText = lastBotMessage.options
              .map((option, index) => `Option ${index + 1}: ${option.label}`)
              .join('. ')

            textToSpeak += `. ${optionsText}`
          }

          if (!textToSpeak.trim()) {
            setIsLoadingAudio(false)
            return
          }

          const audioData = await getTextToSpeech({
            text: textToSpeak,
            accessToken,
            apiKey,
            sessionToken,
            chatApiUrl,
          })

          const success = await playAudio(audioData)
          if (success) {
            lastSpokenMessageIdRef.current = lastBotMessage.id
          }
        } catch (err) {
          debug('Failed to play text to speech:', err)
        } finally {
          setIsLoadingAudio(false)
        }
      }

      speakMessage()
    }
  }, [messages, isTextToSpeechEnabled, isSTTActive, accessToken, apiKey, sessionToken, chatApiUrl])

  // Cleanup audio on unmount or page refresh
  useEffect(() => {
    const stopAudioOnUnload = () => {
      handleStopAudio()
    }

    window.addEventListener('beforeunload', stopAudioOnUnload)
    return () => {
      handleStopAudio()
      window.removeEventListener('beforeunload', stopAudioOnUnload)
    }
  }, [handleStopAudio])

  return {
    isTextToSpeechEnabled,
    toggleTextToSpeech,
    handleTextToSpeech,
    handleStopAudio,
    disableTextToSpeech,
    isLoadingAudio,
  }
}
