/**
 * Get the appropriate webhook path segment based on environment
 * @returns {string} 'prod' for production, 'staging' for integration/beta/local
 */
function getWebhookPath() {
  return targetEnv === 'prod' ? 'prod' : 'staging'
}

/**
 * Get the Inbenta environment value based on target environment
 * @returns {string} 'production' for prod, 'preproduction' for integration/beta/local
 */
function getInbentaEnvironment() {
  return targetEnv === 'prod' ? 'production' : 'preproduction'
}

/**
 * Generate language filter for sys_ai_search_filter variable
 * @param {string} language - User's language code (e.g., 'en', 'es', 'fr')
 * @returns {Object} Language filter object for Inbenta API
 */
function getBasicLanguageFilter(language) {
  if (!language || typeof language !== 'string' || language === 'en') {
    return { filters: [`LANGUAGE:'en'`] }
  }

  // For non-English languages, include both target language and English as fallback
  return {
    filters: [[`LANGUAGE:'${language}'`, `LANGUAGE:'en'`]],
  }
}

/**
 * Generate enhanced language filter for sys_ai_search_filter variable with original question support
 * @param {string} language - User's language code (e.g., 'en', 'es', 'fr')
 * @param {string} [originalQuestion] - Original user question before translation
 * @returns {Object} Language filter object for Inbenta API
 */
function getLanguageFilter(language, originalQuestion = null) {
  if (!isCore10Language(language) || language === 'en') {
    return {
      filters: [`LANGUAGE:'en'`],
    }
  }

  let normalizedLanguage = language
  if (language === 'zh-hant') {
    normalizedLanguage = 'zh' // Traditional Chinese (FamilySearch default for 'zh')
  }

  const filters = [
    [`LANGUAGE:'${normalizedLanguage}'`, `LANGUAGE:'en'`], // Language priority array
  ]

  if (originalQuestion?.trim()) {
    const sanitizedQuestion = originalQuestion
      .replaceAll("'", String.raw`\'`)
      .replaceAll('"', String.raw`\"`)
      .trim()

    filters.push(`original_question: '${sanitizedQuestion}'`)
  }

  return { filters }
}

/**
 * Build complete search filter combining language and member status
 * @param {string} language - User's language code
 * @param {string} [originalQuestion] - Original user question before translation
 * @param {boolean|null} [isMember] - Member status: true=member, false=non-member, null=unknown OR non-Zendesk instance
 * @returns {Object} Complete filter object for sys_ai_search_filter variable
 */
function buildSearchFilter(language, originalQuestion = null, isMember = null) {
  const aiSearchFilters = getLanguageFilter(language, originalQuestion)

  if (isMember === true) {
    // Members: Show articles labeled Member, Public, or with no LABELS attribute
    // LABELS:_null matches articles with no label from non-Zendesk feeds
    const showMemberArticles = ['LABELS:Member', 'LABELS:Public', 'LABELS:_null']
    aiSearchFilters.filters.push(showMemberArticles)
  } else if (isMember === false) {
    // Non-members/anonymous: Show articles labeled PublicOnly, Public, or with no LABELS attribute
    const showPublicArticles = ['LABELS:PublicOnly', 'LABELS:Public', 'LABELS:_null']
    aiSearchFilters.filters.push(showPublicArticles)
  }
  // isMember = null means either: unknown member status OR non-Zendesk instance - no LABELS filter applied

  debug('buildSearchFilter - isMember:', isMember, 'filters:', JSON.stringify(aiSearchFilters))
  return aiSearchFilters
}

/**
 * Check if a language is one of FamilySearch's core10 languages that support enhanced filtering
 * @param {string} language - Language code to check
 * @returns {boolean} True if language is in core10, false otherwise
 */
function isCore10Language(language) {
  const core10Languages = ['en', 'es', 'pt', 'de', 'fr', 'it', 'ja', 'ko', 'ru', 'zh']

  let normalizedLanguage = language
  if (language === 'zh-hant') {
    normalizedLanguage = 'zh' // Traditional Chinese maps to 'zh'
  }
  // Note: 'zh-hans' (Simplified Chinese) is NOT mapped - it should fail core10 check

  return normalizedLanguage && core10Languages.includes(normalizedLanguage)
}

/**
 * Normalize language code for Inbenta API lang parameter
 * Maps unsupported languages to 'en'
 * @param {string} language - User's language code
 * @returns {string} Normalized language code supported by Inbenta
 */
function normalizeInbentaLang(language) {
  if (!language || typeof language !== 'string') {
    return 'en'
  }

  // Language codes that are not supported by Inbenta and must be mapped to 'en'
  const unsupportedLanguages = [
    'hy', // Armenian
    'km', // Khmer
    'ceb', // Cebuano
    'fj', // Fijian
    'fa', // Persian
    'ht', // Haitian Creole
    'ms', // Malay
    'mm', // Burmese
    'mn', // Mongolian
    'pes', // Persian
    'sm', // Samoan
    'to', // Tongan
    'ka', // Georgian
    'gn', // Guarani
    'mg', // Malagasy
    'sw', // Swahili
  ]

  if (unsupportedLanguages.includes(language)) {
    return 'en'
  }

  return language
}

