/**
 * Generate standard Inbenta API headers with correct environment configuration
 * @param {Object} params - Header parameters
 * @param {string} params.accessToken - Access token
 * @param {string} params.apiKey - API key
 * @param {string} [params.sessionToken] - Session token (optional)
 * @returns {Object} Headers object with X-Inbenta-Env set correctly based on targetEnv
 */
function getInbentaHeaders({ accessToken, apiKey, sessionToken }) {
  const headers = {
    Authorization: `Bearer ${accessToken}`,
    'X-Inbenta-Key': apiKey,
    'X-Inbenta-Env': getInbentaEnvironment(),
    'Content-Type': 'application/json',
  }

  if (sessionToken) {
    headers['X-Inbenta-Session'] = `Bearer ${sessionToken}`
  }

  return headers
}

/**
 * Retry a fetch request with exponential backoff on 429 rate limit errors
 * @param {Function} fetchFn - Async function that returns a fetch Response
 * @param {Object} options - Retry options
 * @param {number} [options.maxRetries=3] - Maximum number of retry attempts
 * @param {number} [options.baseDelay=1000] - Base delay in milliseconds for exponential backoff
 * @param {string} [options.operation='API call'] - Operation name for logging
 * @returns {Promise<Response>} The fetch Response
 */
/* eslint-disable no-await-in-loop, no-continue -- Retry logic requires sequential awaits with continue for retry flow */
async function retryOnRateLimit(fetchFn, { maxRetries = 3, baseDelay = 1000, operation = 'API call' } = {}) {
  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      const response = await fetchFn()

      // If successful or non-retryable error, return immediately
      if (response.ok || response.status !== 429) {
        return response
      }

      // 429 rate limit error
      if (attempt < maxRetries) {
        const delay = baseDelay * 2 ** attempt
        debug(`Rate limit hit for ${operation}, retrying in ${delay}ms (attempt ${attempt + 1}/${maxRetries})`)

        splunk.warn({
          message: `Rate limit (429) encountered for ${operation}`,
          component: 'helpChatbot',
          correlationId: getCorrelationId(),
          attempt: attempt + 1,
          maxRetries,
          retryDelay: delay,
          httpStatus: 429,
        })

        await new Promise((resolve) => {
          setTimeout(resolve, delay)
        })
        continue
      }

      // Max retries reached with 429
      splunk.error({
        message: `Rate limit (429) max retries exceeded for ${operation}`,
        component: 'helpChatbot',
        correlationId: getCorrelationId(),
        attempts: maxRetries + 1,
        httpStatus: 429,
      })

      return response
    } catch (error) {
      if (attempt < maxRetries) {
        const delay = baseDelay * 2 ** attempt
        debug(`Network error for ${operation}, retrying in ${delay}ms (attempt ${attempt + 1}/${maxRetries}):`, error)
        await new Promise((resolve) => {
          setTimeout(resolve, delay)
        })
        continue
      }

      // Max retries reached with network error
      throw error
    }
  }

  // Should not reach here, but return a failed response as fallback
  return new Response(null, { status: 500, statusText: 'Internal retry logic error' })
}
/* eslint-enable no-await-in-loop, no-continue */

let refreshTimer = null

export function scheduleTokenRefresh(authData, setAccessToken) {
  if (refreshTimer !== null) {
    clearTimeout(refreshTimer)
    refreshTimer = null
  }

  // Calculate when to refresh (30 seconds before expiration)
  const currentTime = Date.now() / 1000
  const timeUntilExpiry = authData.expiration - currentTime

  if (timeUntilExpiry <= 0) {
    verbose('Token already expired, not scheduling refresh')
    return
  }

  const refreshDelay = Math.max((timeUntilExpiry - SESSION_CONFIG.REFRESH_BUFFER_SECONDS) * 1000, 0)

  verbose('Scheduling token refresh in %d ms (before expiration)', refreshDelay)

  refreshTimer = setTimeout(() => {
    verbose('Executing scheduled token refresh')
    tryRefreshingToken(authData, setAccessToken).catch((err) => {
      debug('Scheduled token refresh failed: %O', err)
    })
  }, refreshDelay)
}

async function tryRefreshingToken(authData, setAccessToken) {
  try {
    const newData = await refreshInbentaToken(authData.apiKey, authData.accessToken)
    if (newData && newData.accessToken && setAccessToken) {
      setAccessToken(newData.accessToken)
      verbose('Access token updated via scheduled refresh')
      if (newData.expiration) {
        scheduleTokenRefresh(
          { ...authData, accessToken: newData.accessToken, expiration: newData.expiration },
          setAccessToken
        )
      }
    } else {
      debug('Token refresh returned null or invalid data')
    }
  } catch (err) {
    debug('Scheduled token refresh failed: %O', err)
  }
}

async function logInbentaErrorToSplunk(message, response, otherVars = {}) {
  debug(message, response)
  const backup = response.clone() // need to clone because response can only be read once.
  splunk.error({
    message,
    component: 'helpChatbot',
    correlationId: getCorrelationId(),
    httpStatus: response.status,
    url: response.url,
    errorBody: await response.json().catch(async () => backup.text()),
    ...otherVars,
  })
}

export async function refreshInbentaToken(apiKey, accessToken) {
  try {
    const response = await retryOnRateLimit(
      () =>
        fetch('https://api.inbenta.io/v1/refreshToken', {
          method: 'POST',
          headers: {
            Authorization: `Bearer ${accessToken}`,
            'X-Inbenta-Key': apiKey,
          },
        }),
      { operation: 'refreshInbentaToken' }
    )

    if (!response.ok) {
      logInbentaErrorToSplunk('Error refreshing Inbenta token:', response)
      // Return null instead of throwing to prevent app crashes
      return null
    }

    return await response.json()
  } catch (error) {
    debug('Error refreshing Inbenta token:', error)
    return null
  }
}

export async function getChatApiUrl(accessToken, apiKey) {
  try {
    const response = await fetch('https://api.inbenta.io/v1/apis', {
      headers: {
        Authorization: `Bearer ${accessToken}`,
        'X-Inbenta-Key': apiKey,
      },
    })

    if (!response.ok) {
      logInbentaErrorToSplunk('Error fetching Inbenta Chat API URL:', response)
      return null
    }

    const data = await response.json()
    const chatBaseUrl = data?.apis?.chatbot

    if (!chatBaseUrl) {
      debug('Chat API URL not found in response')
      return null
    }

    return `${chatBaseUrl}/v1`
  } catch (error) {
    debug('Error fetching Inbenta Chat API URL:', error)
    return null
  }
}

export const updateConversationVariable = async ({
  accessToken,
  sessionToken,
  chatApiUrl,
  apiKey,
  variableName,
  variableValue,
  overwrite = true,
}) => {
  try {
    const response = await fetch(`${chatApiUrl}/conversation/variables`, {
      method: 'POST',
      headers: getInbentaHeaders({ accessToken, apiKey, sessionToken }),
      body: JSON.stringify({
        name: variableName,
        value: variableValue,
        override: overwrite,
      }),
    })

    if (!response.ok) {
      logInbentaErrorToSplunk('Error updating conversation variable:', response, {
        chatApiUrl,
        variableName,
      })
      return null
    }

    return await response.json()
  } catch (error) {
    debug('Error updating conversation variable:', error)
    return null
  }
}

export const startConversation = async ({
  accessToken,
  chatApiUrl,
  apiKey,
  isMember = null,
  isAuthenticated = null,
  sendIsMemberVariable = false,
}) => {
  try {
    const pageUrl = globalThis?.window?.location?.href || ''
    const userLanguage = i18n.language || 'en'
    const normalizedLang = normalizeInbentaLang(userLanguage)

    debug('startConversation - isMember parameter:', isMember, 'type:', typeof isMember)
    debug('startConversation - isAuthenticated parameter:', isAuthenticated, 'type:', typeof isAuthenticated)
    debug('startConversation - sendIsMemberVariable flag:', sendIsMemberVariable)

    const variables = [
      { name: 'sys_ai_consent', value: '1' },
      // Only apply LABELS filtering when using Zendesk instance (sendIsMemberVariable=true)
      // Non-Zendesk instances don't use LABELS and will ignore them, but we keep logic consistent
      {
        name: 'sys_ai_search_filter',
        value: JSON.stringify(buildSearchFilter(userLanguage, null, sendIsMemberVariable ? isMember : null)),
      },
      { name: 'page_url', value: pageUrl },
    ]

    // Add isMember variable for intent filtering (Zendesk instances only)
    // Sending this variable to non-Zendesk instances will crash the session
    if (sendIsMemberVariable && isMember !== null) {
      variables.push({ name: 'isMember', value: isMember ? '1' : '0' })
      debug('startConversation - Adding isMember variable:', isMember ? '1' : '0')
    }

    // Add isAuthenticated variable for session tracking (independent of isMember)
    if (isAuthenticated !== null) {
      variables.push({ name: 'isAuthenticated', value: isAuthenticated ? '1' : '0' })
      debug('startConversation - Adding isAuthenticated variable:', isAuthenticated ? '1' : '0')
    }

    const res = await retryOnRateLimit(
      () =>
        fetch(`${chatApiUrl}/conversation`, {
          method: 'POST',
          headers: getInbentaHeaders({ accessToken, apiKey }),
          body: JSON.stringify({
            forms: { errorRetries: 3, allowUserToAbandonForm: true },
            answers: { maxRelatedContents: 6 },
            environment: getInbentaEnvironment(),
            lang: normalizedLang,
            debug: false,
            variables,
          }),
        }),
      { operation: 'startConversation' }
    )

    if (!res.ok) {
      logInbentaErrorToSplunk('Error starting Inbenta chatbot conversation', res, { chatApiUrl })
      return null
    }

    const data = await res.json()
    return data?.sessionToken || null
  } catch (error) {
    debug('Error starting conversation:', error)
    return null
  }
}

export const sendMessage = async ({ accessToken, sessionToken, message, chatApiUrl, apiKey }) => {
  try {
    // If message is an object with message and option properties, send it directly
    // Otherwise, wrap string messages in a message property
    const payload = typeof message === 'object' && message !== null && 'message' in message ? message : { message }

    const res = await retryOnRateLimit(
      () =>
        fetch(`${chatApiUrl}/conversation/message`, {
          method: 'POST',
          headers: getInbentaHeaders({ accessToken, apiKey, sessionToken }),
          body: JSON.stringify(payload),
        }),
      { operation: 'sendMessage' }
    )

    if (!res.ok) {
      const resClone = res.clone()
      const errorBody = await resClone.json().catch(() => null)
      logInbentaErrorToSplunk('Error sending Inbenta chatbot message', res, { chatApiUrl })
      if (errorBody?.errors?.some((e) => e.message === 'Session expired')) {
        const err = new Error('Inbenta session expired')
        err.isInbentaSessionExpired = true
        throw err
      }
      return null
    }

    return await res.json()
  } catch (error) {
    if (error.isInbentaSessionExpired) throw error
    debug('Error sending message:', error)
    return null
  }
}

export async function trackInbentaEvent({ accessToken, apiKey, sessionToken, chatApiUrl, clickCode }) {
  const response = await fetch(`${chatApiUrl}/inbtrck/events`, {
    method: 'POST',
    headers: getInbentaHeaders({ accessToken, apiKey, sessionToken }),
    body: JSON.stringify({ type: 'click', data: { code: clickCode } }),
  })

  if (!response.ok) {
    logInbentaErrorToSplunk('Error posting Inbenta event:', response, { chatApiUrl, clickCode })
    throw new Error(`HTTP error! status: ${response.status}`)
  }

  return response.json()
}

