export async function trackAiRatingEvent({ accessToken, apiKey, sessionToken, chatApiUrl, value, comment = '' }) {
  // Format as per requirements:
  // - "positive" or "positive|comment" for positive ratings
  // - "negative|comment" or "negative|" for negative ratings
  let ratingValue
  if (value === 'positive') {
    ratingValue = comment.trim() ? `positive|${comment}` : 'positive'
  } else {
    ratingValue = `negative|${comment}`
  }

  const customData = {
    value: ratingValue,
  }

  const requestBody = { type: 'custom', data: customData }
  debug('AI rating request body:', requestBody)

  const response = await fetch(`${chatApiUrl}/inbtrck/events`, {
    method: 'POST',
    headers: getInbentaHeaders({ accessToken, apiKey, sessionToken }),
    body: JSON.stringify(requestBody),
  })

  debug('AI rating response status:', response.status)

  // Debug headers safely (may not have entries method in tests)
  try {
    if (response.headers && typeof response.headers.entries === 'function') {
      debug('AI rating response headers:', Object.fromEntries(response.headers.entries()))
    } else {
      debug('AI rating response headers: [debug unavailable in test mode]')
    }
  } catch (error) {
    debug('AI rating response headers: [debug error]', error.message)
  }

  if (!response.ok) {
    logInbentaErrorToSplunk('Error posting AI rating event:', response, { chatApiUrl, ratingValue })
    throw new Error(`HTTP error! status: ${response.status}`)
  }

  // Check if response has content before trying to parse JSON
  const contentType = response.headers.get('content-type')
  if (contentType && contentType.includes('application/json')) {
    const text = await response.text()
    debug('AI rating response text:', text)
    const result = text ? JSON.parse(text) : {}
    debug('AI rating parsed response:', result)
    return result
  }

  // If not JSON, just return success indicator
  debug('AI rating non-JSON response, returning success indicator')
  return { success: true }
}

