// RAG 2.0: getSources function is obsolete - sources now come from subAnswers[0].context array

/**
 * Detect language from FamilySearch URL path
 * @param {string} url - FamilySearch URL
 * @returns {string|null} Language code detected from URL or null if not found
 */
function detectLanguageFromUrl(url) {
  if (!url || typeof url !== 'string') {
    return null
  }

  try {
    const urlObj = new URL(url)

    if (!urlObj.hostname.includes('familysearch.org')) {
      return null
    }

    // Extract language from path like /en/wiki/, /de/wiki/, etc.
    const pathParts = urlObj.pathname.split('/').filter(Boolean)

    if (pathParts.length > 0) {
      const firstPart = pathParts[0].toLowerCase()

      const knownLanguages = ['en', 'es', 'pt', 'de', 'fr', 'it', 'ja', 'ko', 'ru', 'zh']
      if (knownLanguages.includes(firstPart)) {
        return firstPart
      }
    }

    // This isn't great. Check with Inbenta to add a knowledge base language prop
    // Default to English if no language code detected but is FamilySearch domain
    return 'en'
  } catch (error) {
    debug('Error parsing URL for language detection:', error)
    return null
  }
}

/**
 * Determine if response is already in target language based on source URLs
 * @param {Array} sources - Array of source objects with URL properties
 * @param {string} targetLanguage - Target language code
 * @returns {boolean} True if response appears to be in target language
 */
function isResponseInTargetLanguage(sources, targetLanguage) {
  if (!sources || !sources.length || !targetLanguage) {
    return false
  }

  // Check if majority of sources are from target language knowledge base
  const languageDetections = sources.map((source) => detectLanguageFromUrl(source.url)).filter(Boolean)

  if (languageDetections.length === 0) {
    return false
  }

  const languageCounts = languageDetections.reduce((counts, lang) => {
    counts[lang] = (counts[lang] || 0) + 1
    return counts
  }, {})

  const mostCommonLanguage = Object.keys(languageCounts).reduce((a, b) =>
    languageCounts[a] > languageCounts[b] ? a : b
  )

  debug(`Source language detection: ${JSON.stringify(languageCounts)}, target: ${targetLanguage}`)

  return mostCommonLanguage === targetLanguage
}

/**
 * Safely strip HTML tags from content while preserving text
 * @param {string} html - HTML content to sanitize
 * @returns {string} Plain text content
 */
function sanitizeHtmlContent(html) {
  if (!html || typeof html !== 'string') {
    return ''
  }

  try {
    const parser = new DOMParser()
    const doc = parser.parseFromString(html, 'text/html')

    return doc.body.textContent || doc.body.innerText || ''
  } catch (error) {
    // Fallback: return empty string instead of using vulnerable regex
    debug('Error sanitizing HTML content:', error)
    return ''
  }
}

/**
 * Extract sources from RAG 2.0 AI-generated answer response
 * Sources are now embedded in subAnswers[0].context array instead of separate getSources API call
 * @param {Object} messageResponse - Response from sendMessage API call
 * @returns {Array} Array of source objects with title, url, clickCode, and answer properties
 */
export function extractSourcesFromResponse(messageResponse) {
  try {
    if (!messageResponse?.answers?.length) {
      debug('No answers found in message response')
      return []
    }

    // Look for AI-generated content in subAnswers
    const firstAnswer = messageResponse.answers[0]
    if (!firstAnswer?.subAnswers?.length) {
      debug('No subAnswers found in first answer')
      return []
    }

    const firstSubAnswer = firstAnswer.subAnswers[0]
    if (!firstSubAnswer?.context?.length) {
      debug('No context found in first subAnswer')
      return []
    }

    const sources = firstSubAnswer.context.map((contextItem, index) => ({
      id: `source_${index}`,
      title: sanitizeHtmlContent(contextItem.title) || 'Unknown Source',
      url: contextItem.url || null,
      clickCode: contextItem.clickCode || null,
      answer: sanitizeHtmlContent(contextItem.answer) || '',
      sourceType: 'ai_generated', // Mark as RAG 2.0 source
      detectedLanguage: detectLanguageFromUrl(contextItem.url), // Add language detection
    }))

    debug(`Extracted ${sources.length} sources from RAG 2.0 response with HTML sanitization`)
    return sources
  } catch (error) {
    debug('Error extracting sources from response:', error)
    return []
  }
}

