export async function getTextToSpeech({ text, accessToken, apiKey, sessionToken, chatApiUrl }) {
  try {
    const webhookPath = getWebhookPath()
    const response = await fetch(
      `https://familysearchrag-webhook-${webhookPath}.u01.inbenta.services/chat/textToSpeech`,
      {
        method: 'POST',
        headers: {
          'X-Inbenta-Access-Token': `Bearer ${accessToken}`,
          'X-Inbenta-API-Key': apiKey,
          'X-Inbenta-Session-Token': sessionToken,
          'X-Inbenta-API-Url': chatApiUrl,
          'X-Inbenta-Token': 'VXt8EVKS1cPb2njz6RbrrP8eL6jvOhWZ',
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ text, language: i18n.language || 'en' }),
      }
    )

    if (!response.ok) {
      logInbentaErrorToSplunk('Error fetching text-to-speech:', response, { chatApiUrl })
      return null
    }

    return await response.arrayBuffer()
  } catch (error) {
    debug('Error fetching text-to-speech:', error)
    return null
  }
}

/**
 * Extract user message from messageData
 * @param {string|Object} messageData - User message data
 * @returns {string} User message text
 */
function extractUserMessage(messageData) {
  const userMessage = typeof messageData === 'string' ? messageData : messageData?.message || ''

  if (!userMessage) {
    throw new Error('No user message found to translate')
  }

  return userMessage
}

/**
 * Extract main message content from bot response answers
 * @param {Object} messageData - Bot response data
 * @returns {string} Main message content
 */
function extractBotMainMessage(messageData) {
  if (!messageData?.answers?.length) {
    throw new Error('No answer data found in messageData')
  }

  // Extract the main message from answers that have non-empty content (including those with subAnswers)
  const answersWithContent = messageData.answers.filter(
    (answer) =>
      (answer?.messageList?.length > 0 && answer.messageList.some((msg) => msg && msg.trim())) ||
      answer?.subAnswers?.length > 0
  )

  const answersWithValidStructure = messageData.answers.filter(
    (answer) =>
      (answer?.messageList?.length > 0 && answer.messageList.some((msg) => msg && msg.trim())) ||
      answer?.subAnswers?.length > 0
  )

  if (!answersWithValidStructure.length) {
    throw new Error('No message content found to translate')
  }

  let mainMessage = ''
  if (answersWithContent.length > 0) {
    mainMessage = answersWithContent
      .filter((answer) => answer?.messageList?.length > 0)
      .map((answer) => answer.messageList.join(''))
      .join('')
  }

  // If main messageList is empty but we have subAnswers, that's acceptable for translation
  return mainMessage
}

/**
 * Extract options from bot response answers
 * @param {Object} messageData - Bot response data
 * @returns {Array} Options array
 */
function extractBotOptions(messageData) {
  if (!messageData?.answers?.length) {
    return []
  }

  const allOptions = []

  messageData.answers.forEach((answer) => {
    if (answer?.options?.length > 0) {
      // Extract just the labels from options for translation
      const optionLabels = answer.options.map((option) => option.label || option.value || '')
      allOptions.push(...optionLabels.filter(Boolean))
    }
  })

  return allOptions
}

function extractRelatedContent(messageData) {
  const allRelatedContents = []
  let relatedTitle = ''

  messageData.answers.forEach((answer) => {
    // Extract nested related content
    const relatedData = answer?.parameters?.contents?.related
    if (relatedData) {
      const nestedContents = relatedData.relatedContents?.map((content) => content.title) || []
      allRelatedContents.push(...nestedContents)

      if (!relatedTitle && relatedData.relatedTitle) {
        relatedTitle = relatedData.relatedTitle
      }
    }
  })

  return { relatedContents: allRelatedContents, relatedTitle }
}

/**
 * Extract subAnswers from bot response answers
 * @param {Object} messageData - Bot response data
 * @returns {Array} Array of subAnswer messages
 */
function extractBotSubAnswers(messageData) {
  if (!messageData?.answers?.length) {
    return []
  }

  const allSubAnswers = []

  messageData.answers.forEach((answer) => {
    if (answer?.subAnswers?.length > 0) {
      const subAnswerMessages = answer.subAnswers
        .map((subAnswer) => {
          return subAnswer.messageList?.join('') || ''
        })
        .filter(Boolean)

      allSubAnswers.push(...subAnswerMessages)
    }
  })

  return allSubAnswers
}

/**
 * Create base translation structure
 * @param {string} message - Main message content
 * @param {string} relatedTitle - Related content title
 * @param {Array} relatedContents - Related content items
 * @returns {Object} Base translation structure
 */
function createBaseTranslation(message, relatedTitle = '', relatedContents = []) {
  return {
    message,
    options: [],
    listValues: [],
    relatedTitle,
    relatedContents,
    sideWindowTitle: null,
    sideWindowContent: null,
    subAnswers: [],
  }
}

/**
 * Create translation payload for user messages
 * @param {string|Object} messageData - User message data
 * @param {string} sourceLang - Source language
 * @param {string} targetLang - Target language
 * @param {boolean} isA - Is answer flag
 * @returns {Object} Translation payload
 */
function createUserTranslationPayload(messageData, sourceLang, targetLang, isA) {
  const userMessage = extractUserMessage(messageData)
  const translation = createBaseTranslation(userMessage)

  return {
    translation,
    source_lang: sourceLang,
    target_lang: targetLang,
    is_user_question: true,
    is_a: isA,
  }
}

/**
 * Create translation payload for bot responses
 * @param {Object} messageData - Bot response data
 * @param {string} sourceLang - Source language
 * @param {string} targetLang - Target language
 * @param {boolean} isA - Is answer flag
 * @returns {Object} Translation payload
 */
function createBotTranslationPayload(messageData, sourceLang, targetLang, isA) {
  const mainMessage = extractBotMainMessage(messageData)
  const { relatedContents, relatedTitle } = extractRelatedContent(messageData)
  const options = extractBotOptions(messageData)
  const subAnswers = extractBotSubAnswers(messageData)
  const translation = createBaseTranslation(mainMessage, relatedTitle, relatedContents)

  // Add options and subAnswers to the translation
  translation.options = options
  translation.subAnswers = subAnswers

  return {
    translation,
    source_lang: sourceLang,
    target_lang: targetLang,
    is_user_question: false,
    is_a: isA,
  }
}

/**
 * Make translation API request
 * @param {Object} payload - Translation payload
 * @param {Object} authParams - Authentication parameters
 * @returns {Promise<Object>} Translation response
 */
async function makeTranslationRequest(payload, { apiKey, sessionToken, chatApiUrl, accessToken }) {
  const webhookPath = getWebhookPath()
  const response = await fetch(`https://familysearch-mbot-${webhookPath}.u01.inbenta.services/translate/chatbot`, {
    method: 'POST',
    headers: {
      'X-Inbenta-API-Key': apiKey,
      'X-Inbenta-Session-Token': sessionToken,
      'X-Inbenta-API-Url': chatApiUrl,
      'X-Inbenta-Token': `Bearer ${accessToken}`,
      'multilingual-bot-token': 'f110c656385e7f97bb3899b6dad50c29fe3402f9733e57531dc864f7eaaa36d6',
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(payload),
  })

  if (!response.ok) {
    throw new Error(`HTTP error! status: ${response.status}`)
  }

  return response.json()
}

export async function translateChatbot({
  messageData,
  sourceLang = 'en',
  targetLang,
  isUserQuestion = false,
  isA = false,
  apiKey,
  sessionToken,
  chatApiUrl,
  accessToken,
}) {
  try {
    const translationPayload = isUserQuestion
      ? createUserTranslationPayload(messageData, sourceLang, targetLang, isA)
      : createBotTranslationPayload(messageData, sourceLang, targetLang, isA)

    return await makeTranslationRequest(translationPayload, {
      apiKey,
      sessionToken,
      chatApiUrl,
      accessToken,
    })
  } catch (error) {
    debug('Error translating chatbot message:', error)
    splunk.error({
      message: 'Error translating chatbot message:',
      component: 'helpChatbot',
      correlationId: getCorrelationId(),
      errorName: error.name,
      errorMessage: error.message,
      errorStack: error.stack,
      ...(error.cause &&
        typeof error.cause === 'object' && {
          errorCauseName: error.cause.name,
          errorCauseMessage: error.cause.message,
        }),
    })
    throw error
  }
}
