import React, { useRef, useEffect, useMemo, useCallback } from 'react'
import PropTypes from 'prop-types'
import { VisuallyHidden } from '@reach/visually-hidden'
import { formatRelative } from '@fs/zion-locale/date-fns'
import { useTranslation } from 'react-i18next'
import { Card, Cell, colors, FlowGrid, Grid, H3, Paragraph, Row, Separator, ActionChip } from '@fs/zion-ui'
import { NoticeLoadingMessage, Arrow } from '@fs/zion-icon'
import { Link, buildLangUrl } from '@fs/zion-router'
import { SafeInnerHtml, useResizeObserver } from '@fs/zion-frontend-friends'
import useHelpChatbot from './context/useHelpChatbot'
import MessageRating from './components/MessageRating'
import AiMessageRating from './components/AiMessageRating'
import WelcomeScreen, { WelcomeScreenSkeleton } from './WelcomeScreen'
import { extractStandaloneLinks } from './utils/extractLinks'
import { aiResponseCss } from './styles/aiMessageStyles'

// External link arrow icon - rotated 315deg to point upper-right
const ExternalLinkArrow = (props) => (
  <span
    style={{
      display: 'inline-flex',
      alignItems: 'center',
      justifyContent: 'center',
      transform: 'rotate(-45deg)',
      marginInlineStart: '2px',
    }}
  >
    <Arrow {...props} />
  </span>
)

const getArticleLabelId = (messageIndex) => `help-chatbot-message-label-${messageIndex}`

const MessageList = React.memo(function MessageList({ sessionPrecheckLoading }) {
  const { t } = useTranslation()
  const {
    apiState,
    conversationState: { messages, sending, sessionStarting },
    actions: { selectOption },
  } = useHelpChatbot()
  const lastMessageRef = useRef(null)

  // Determine if we're in the welcome state - true by default until user sends a message
  const isWelcomeState = messages.length === 0 || !messages.some((msg) => msg.from === 'user')

  const isIOS = useMemo(() => {
    if (typeof navigator === 'undefined' || typeof window === 'undefined') {
      return false
    }
    return /iPad|iPhone|iPod/.test(navigator.userAgent) && !window.MSStream
  }, [])

  const scrollToLastMessage = useCallback(() => {
    if (lastMessageRef.current) {
      lastMessageRef.current.scrollIntoView({
        behavior: isIOS ? 'auto' : 'smooth',
        block: 'start',
      })
    }
  }, [isIOS])

  useEffect(() => {
    scrollToLastMessage()
  }, [messages, sending, scrollToLastMessage])

  useResizeObserver(lastMessageRef, scrollToLastMessage)

  // If we're in the welcome state, render the WelcomeScreen or skeleton
  if (isWelcomeState) {
    // Show skeleton while session precheck is loading or session is starting
    if (sessionPrecheckLoading || sessionStarting) {
      return <WelcomeScreenSkeleton />
    }
    // Show actual welcome screen once loaded
    if (!sending) {
      const welcomeMsg = messages[0]
      return (
        <WelcomeScreen
          welcomeMessage={welcomeMsg?.text}
          options={welcomeMsg?.options || []}
          onSelectOption={selectOption}
        />
      )
    }
  }

  return (
    <section
      role="feed"
      aria-busy={sending || sessionStarting}
      aria-label={t('help-chatbot.message-list.aria-label', 'Chat conversation')}
    >
      <FlowGrid gutters="sm">
        {messages.map((msg, index) => {
          const timestampMatch = msg.id?.match(/-(\d+)$/)
          const currentTimestamp = timestampMatch ? new Date(Number(timestampMatch[1])) : null
          const isLastMessage = index === messages.length - 1
          const labelId = getArticleLabelId(index)

          const { cleanedHtml, links } =
            msg.from === 'bot' ? extractStandaloneLinks(msg.text) : { cleanedHtml: msg.text, links: [] }

          return (
            <article
              key={msg.id || msg.text}
              tabIndex={-1}
              aria-posinset={index + 1}
              aria-setsize={-1}
              aria-labelledby={labelId}
              data-index={index}
            >
              <VisuallyHidden id={labelId}>
                {t('help-chatbot.message.aria-label', 'Message from {from}', {
                  from: msg.from === 'user' ? t('help-chatbot.you', 'you') : t('help-chatbot.assistant', 'chatbot'),
                })}
              </VisuallyHidden>
              {msg.from === 'user' ? (
                cleanedHtml &&
                cleanedHtml.trim() && (
                  <Grid>
                    <Cell columns={2}>
                      <Separator size="hide" />
                    </Cell>
                    <Cell columns={10}>
                      <Row
                        alignX={msg.from === 'user' ? 'end' : 'start'}
                        gutters="xxs"
                        ref={isLastMessage ? lastMessageRef : null}
                      >
                        <Cell growX />
                        <Card backgroundColor={colors.gray02} edges="none" margins="xxs">
                          <SafeInnerHtml
                            dirtyInput={cleanedHtml}
                            className={aiResponseCss}
                            options={{
                              ALLOWED_TAGS: ['p', 'a', 'strong', 'em', 'b', 'i', 'br', 'ul', 'ol', 'li'],
                              ALLOWED_ATTR: ['href', 'target'],
                              ALLOW_DATA_ATTR: false,
                            }}
                          />
                        </Card>
                      </Row>
                    </Cell>
                  </Grid>
                )
              ) : (
                <Grid gutters="none">
                  <Cell columns={12}>
                    <Row
                      alignX={msg.from === 'user' ? 'end' : 'start'}
                      gutters="xxs"
                      ref={isLastMessage ? lastMessageRef : null}
                    >
                      <Cell growX>
                        <FlowGrid gutters="xxs">
                          {cleanedHtml && cleanedHtml.trim() && (
                            <Cell>
                              <SafeInnerHtml
                                dirtyInput={cleanedHtml}
                                className={aiResponseCss}
                                options={{
                                  ALLOWED_TAGS: ['p', 'a', 'strong', 'em', 'b', 'i', 'br', 'ul', 'ol', 'li'],
                                  ALLOWED_ATTR: ['href', 'target'],
                                  ALLOW_DATA_ATTR: false,
                                }}
                              />
                              {msg.sources && msg.sources.length > 0 && (
                                <>
                                  <Separator size="xxs" />
                                  <H3 size="H6">{t('help-chatbot.sources', 'Sources:')}</H3>
                                  {msg.sources
                                    .filter((source) => source.url)
                                    .map((source) => (
                                      <Link
                                        key={source.url || source.title}
                                        to={buildLangUrl(source.url)}
                                        target="_blank"
                                        size="xs"
                                      >
                                        {source.title}
                                      </Link>
                                    ))}
                                </>
                              )}
                            </Cell>
                          )}

                          {msg.from === 'bot' && links.length > 0 && (
                            <Row gutters="xxs" wrap>
                              {links.map((link, linkIndex) => (
                                <ActionChip
                                  key={link.url}
                                  label={link.text}
                                  to={link.url}
                                  external
                                  target="_blank"
                                  Icon={ExternalLinkArrow}
                                  iconAtEnd
                                  data-testid={`chatbot-message-link-${linkIndex}`}
                                />
                              ))}
                            </Row>
                          )}
                          {/* Render rating card as separate component after main message */}
                          {msg.from === 'bot' && msg.hasRatings && msg.rateCode && (
                            <MessageRating rateCode={msg.rateCode} apiParams={apiState} />
                          )}
                          {/* Render AI rating card for AI-generated answers */}
                          {msg.from === 'bot' && msg.isAiGenerated && <AiMessageRating apiParams={apiState} />}

                          {msg.from === 'bot' && msg?.options && msg.options.length > 0 && (
                            <Row
                              gutters="sm"
                              wrap
                              data-testid="chatbot-message-options"
                              data-option-count={msg.options.length}
                              alignX="end"
                            >
                              {msg.options.map((option, optionIndex) => (
                                <ActionChip
                                  key={option.value || option.label}
                                  label={option.label}
                                  onClick={() => selectOption(option)}
                                  data-testid={`chatbot-message-option-${optionIndex}`}
                                  color="gray"
                                />
                              ))}
                            </Row>
                          )}
                        </FlowGrid>
                        {currentTimestamp && (
                          <VisuallyHidden>
                            <Separator size="nano" />
                            <Row alignX="start">
                              <Paragraph size="xs" secondary>
                                {formatRelative(currentTimestamp, currentTimestamp)}
                              </Paragraph>
                            </Row>
                          </VisuallyHidden>
                        )}
                      </Cell>
                    </Row>
                  </Cell>
                </Grid>
              )}
              {msg.from === 'user' && currentTimestamp && (
                <VisuallyHidden>
                  <Separator size="nano" />
                  <Row alignX="end">
                    <Paragraph size="xs" secondary>
                      {formatRelative(currentTimestamp, currentTimestamp)}
                    </Paragraph>
                  </Row>
                </VisuallyHidden>
              )}
            </article>
          )
        })}

        {/* Show the loading message when sending or when session is starting */}
        {(sending || sessionStarting) && (
          <article
            tabIndex={-1}
            aria-posinset={messages.length + 1}
            aria-setsize={-1}
            aria-labelledby="loading-message-label"
            data-index={messages.length}
          >
            <div
              id="loading-message-label"
              style={{ position: 'absolute', insetInlineStart: '-10000px', width: '1px', height: '1px' }}
            >
              {t('help-chatbot.loading.aria-label', 'Chatbot is typing')}
            </div>
            <Row gutters="xxs" ref={messages.length === 0 ? lastMessageRef : null}>
              <Card backgroundColor={colors.gray02} edges="none" margins="nano">
                <NoticeLoadingMessage size="sm" />
              </Card>
            </Row>
          </article>
        )}
      </FlowGrid>
    </section>
  )
})

MessageList.propTypes = {
  sessionPrecheckLoading: PropTypes.bool,
}

MessageList.defaultProps = {
  sessionPrecheckLoading: false,
}

export default MessageList
