import { useState, useRef, useCallback, useEffect } from 'react'
import zionDebug from '@fs/zion-debug'
import { splunk } from '@fs/zion-splunk-logger'
import { isPlaying, stopAudio } from '../utils/AudioManager'

const debug = zionDebug('help:zion:help-chatbot:useSpeechToText')
const AUD_SAMPLE_RATE = 16000

export function useSpeechToText({ speechToTextKey, onTranscript, showStatusOverlay }) {
  const [isListening, setIsListening] = useState(false)
  const [isSupported, setIsSupported] = useState(false)
  const [transcriptionText, setTranscriptionText] = useState('')

  const webSocketRef = useRef(null)
  const mediaRecorderRef = useRef(null)
  const sessionRef = useRef({
    accumulator: '',
    isActive: false,
  })

  // Check browser support
  useEffect(() => {
    const mediaDevicesSupported = !!(navigator.mediaDevices && navigator.mediaDevices.getUserMedia)
    const supportedStatus = mediaDevicesSupported && !!speechToTextKey
    setIsSupported(supportedStatus)
  }, [speechToTextKey])

  const endSession = useCallback(() => {
    if (webSocketRef.current) {
      webSocketRef.current.close()
      webSocketRef.current = null
    }

    // Stop audio capture
    if (mediaRecorderRef.current) {
      const { stream, context, processor } = mediaRecorderRef.current
      if (stream) {
        stream.getTracks().forEach((track) => track.stop())
      }
      if (processor) {
        processor.disconnect()
      }
      if (context) {
        context.close()
      }
      mediaRecorderRef.current = null
    }

    sessionRef.current.isActive = false
    sessionRef.current.accumulator = ''
    setIsListening(false)
    setTranscriptionText('')
  }, [])

  const finishSession = useCallback(() => {
    if (!sessionRef.current.isActive) return

    const finalText = sessionRef.current.accumulator.trim()

    if (finalText && onTranscript) {
      onTranscript(finalText)
    }

    endSession()
  }, [onTranscript, endSession])

  const handleWebSocketMessage = useCallback(
    (data) => {
      if (data.message === 'RecognitionStarted') {
        return
      }

      if (data.message === 'AddTranscript' && data.metadata?.transcript) {
        const transcriptText = data.metadata.transcript
        sessionRef.current.accumulator += `${transcriptText} `
        const fullText = sessionRef.current.accumulator.trim()
        setTranscriptionText(fullText)
      }

      if (data.message === 'EndOfUtterance') {
        finishSession()
      }

      if (data.message === 'EndOfTranscript') {
        finishSession()
      }
    },
    [finishSession]
  )

  const connectWebSocket = useCallback(async () => {
    if (!speechToTextKey) {
      return false
    }

    try {
      const wsUrl = `wss://eu2.rt.speechmatics.com/v2?jwt=${encodeURIComponent(speechToTextKey)}`
      webSocketRef.current = new WebSocket(wsUrl)

      return new Promise((resolve, reject) => {
        webSocketRef.current.onopen = () => {
          const config = {
            message: 'StartRecognition',
            transcription_config: {
              language: 'en',
              operating_point: 'enhanced',
              enable_partials: false, // for accuracy and simplicity
              max_delay_mode: 'flexible',
              max_delay: 1.5,
              conversation_config: {
                end_of_utterance_silence_trigger: 1,
              },
            },
            audio_format: {
              type: 'raw',
              encoding: 'pcm_f32le',
              sample_rate: AUD_SAMPLE_RATE,
            },
          }

          webSocketRef.current.send(JSON.stringify(config))
          resolve(true)
        }

        webSocketRef.current.onerror = (error) => {
          debug('WebSocket connection error:', error)
          splunk.error({ message: 'WebSocket connection error:', component: 'helpChatbot', error })
          reject(error)
        }

        webSocketRef.current.onmessage = (event) => {
          try {
            const data = JSON.parse(event.data)
            handleWebSocketMessage(data)
          } catch (error) {
            debug('Error parsing WebSocket message:', error)
          }
        }

        webSocketRef.current.onclose = () => {
          if (sessionRef.current.isActive) {
            endSession()
          }
        }
      })
    } catch (error) {
      splunk.error({ message: 'Error creating WebSocket connection:', component: 'helpChatbot', error })
      debug('Error creating WebSocket connection:', error)
      return false
    }
  }, [speechToTextKey, handleWebSocketMessage, endSession])

  const startAudioCapture = useCallback(async () => {
    try {
      // Check browser compatibility for audio capture features
      if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        debug('Browser does not support getUserMedia')
        return null
      }

      if (typeof AudioContext === 'undefined' && globalThis.webkitAudioContext === 'undefined') {
        debug('Browser does not support AudioContext')
        return null
      }

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true })

      // Set up MediaRecorder with 16kHz PCM
      const AudioContextClass = typeof AudioContext === 'undefined' ? globalThis.webkitAudioContext : AudioContext
      const context = new AudioContextClass({ sampleRate: AUD_SAMPLE_RATE })

      const source = context.createMediaStreamSource(stream)
      // Using createScriptProcessor for audio processing (deprecated but widely supported)
      // Modern alternative would be AudioWorkletNode but requires more complex setup
      const processor = context.createScriptProcessor(4096, 1, 1)

      processor.onaudioprocess = (event) => {
        if (webSocketRef.current && webSocketRef.current.readyState === WebSocket.OPEN) {
          const audioData = event.inputBuffer.getChannelData(0)
          webSocketRef.current.send(audioData.buffer)
        }
      }

      source.connect(processor)
      processor.connect(context.destination)

      return { stream, context, processor }
    } catch (error) {
      debug('Error starting audio capture:', error)
      throw error
    }
  }, [])

  const startSession = useCallback(async () => {
    if (sessionRef.current.isActive) {
      return
    }

    if (!isSupported) {
      if (showStatusOverlay) {
        showStatusOverlay({
          message: 'Speech recognition is not supported or speech key is missing.',
        })
      }
      return
    }

    // Stop TTS if playing to avoid audio interference
    if (isPlaying()) {
      stopAudio()
    }

    try {
      const connected = await connectWebSocket()
      if (!connected) {
        throw new Error('Failed to connect WebSocket')
      }

      const audioCapture = await startAudioCapture()
      if (!audioCapture) {
        throw new Error('Audio capture not supported in this browser')
      }
      mediaRecorderRef.current = audioCapture

      // Initialize session
      sessionRef.current.isActive = true
      sessionRef.current.accumulator = ''
      setIsListening(true)
      setTranscriptionText('')
    } catch (error) {
      debug('❌ Error starting session:', error)
      if (showStatusOverlay) {
        showStatusOverlay({
          message: 'Could not start speech recognition. Please check microphone permissions.',
        })
      }
      endSession()
    }
  }, [connectWebSocket, startAudioCapture, showStatusOverlay, endSession, isSupported])

  // Public interfaces
  const startListening = useCallback(() => {
    startSession()
  }, [startSession])

  const stopListening = useCallback(() => {
    if (sessionRef.current.isActive) {
      finishSession()
    } else {
      endSession()
    }
  }, [finishSession, endSession])

  const toggleListening = useCallback(() => {
    if (isListening) {
      stopListening()
    } else {
      startListening()
    }
  }, [isListening, startListening, stopListening])

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      endSession()
    }
  }, [endSession])

  return {
    isListening,
    isSupported,
    transcriptionText,
    startListening,
    stopListening,
    toggleListening,
    usingAdvancedRecognition: true, // Using Speechmatics instead of browser API
  }
}
