// cspell:words describedby
import React, { useEffect, useRef } from 'react'
import PropTypes from 'prop-types'
import { useTranslation } from 'react-i18next'
import { VisuallyHidden } from '@reach/visually-hidden'
import { css } from '@linaria/core'

// Remove default dialog border and use static positioning
// Static positioning ensures dialog stays in normal flow for BorderScroller to handle scrolling
const dialogStyles = css`
  border: none;
  position: static;
`

/**
 * Reusable dialog container with focus management and keyboard navigation
 * Provides consistent behavior for all chatbot dialogs
 */
export default function DialogContainer({
  children,
  role,
  headingId,
  descriptionId,
  helpText,
  helpLabel,
  onEscape,
  allowEscape,
}) {
  const { t } = useTranslation()
  const dialogRef = useRef()

  // Focus management for dialog
  useEffect(() => {
    if (dialogRef.current) {
      // Focus the dialog container for screen reader announcement
      dialogRef.current.focus()
    }
  }, [])

  // Handle Escape key globally to avoid assigning keyboard events to non-interactive elements
  useEffect(() => {
    if (!allowEscape || !onEscape) return undefined

    const onKeyDown = (e) => {
      if (e.key === 'Escape') {
        onEscape()
      }
    }
    globalThis.addEventListener('keydown', onKeyDown)
    return () => {
      globalThis.removeEventListener('keydown', onKeyDown)
    }
  }, [allowEscape, onEscape])

  return (
    <dialog
      ref={dialogRef}
      className={dialogStyles}
      role={role}
      aria-labelledby={headingId}
      aria-describedby={descriptionId}
      aria-modal="true"
      tabIndex={-1}
      open
    >
      {/* Help content for VoiceOver VO+H command */}
      <VisuallyHidden>
        <aside aria-label={helpLabel || t('help-chatbot.dialog.help-label', 'Dialog help')}>{helpText}</aside>
      </VisuallyHidden>

      {children}
    </dialog>
  )
}

DialogContainer.propTypes = {
  children: PropTypes.node.isRequired,
  role: PropTypes.oneOf(['dialog', 'alertdialog']),
  headingId: PropTypes.string.isRequired,
  descriptionId: PropTypes.string,
  helpText: PropTypes.string.isRequired,
  helpLabel: PropTypes.string,
  onEscape: PropTypes.func,
  allowEscape: PropTypes.bool,
}

DialogContainer.defaultProps = {
  role: 'dialog',
  descriptionId: undefined,
  helpLabel: undefined,
  onEscape: undefined,
  allowEscape: true,
}
