import { useEffect } from 'react'
import { clearChatbotSession } from '../chatbot-services/chatbotSessionCache'

/**
 * Security hook: Track active tabs and clear cache when last tab closes (guest users only)
 *
 * Uses sessionStorage (per-tab) + localStorage (shared) for reference counting.
 * Prevents unauthorized access to cached messages on shared/public computers.
 *
 * Architecture:
 * - sessionStorage: Stores unique tab ID (dies with tab)
 * - localStorage: Stores active tab count (shared across tabs)
 * - beforeunload event: Decrements count and clears cache if last tab
 *
 * Security Rationale:
 * This is critical for public Family History Centers where multiple users
 * share computers. If a user minimizes the chatbot and walks away, cached
 * messages could be exposed to the next user. This hook ensures cache is
 * cleared when all tabs close.
 *
 * @param {boolean} signedIn - Whether user is authenticated (only runs for guests)
 */
export function useGuestTabSecurity(signedIn) {
  useEffect(() => {
    // Only run for guest users
    if (signedIn) return undefined

    // Verify browser APIs are available
    if (globalThis?.window === 'undefined' || !globalThis.localStorage || !globalThis.sessionStorage) {
      return undefined
    }

    const TAB_COUNT_KEY = 'helpChatbot_activeTabCount'
    const TAB_ID_KEY = 'helpChatbot_tabId'

    // Generate unique tab ID (stored in sessionStorage - dies with tab)
    const tabId = `tab_${globalThis.crypto.randomUUID()}`
    globalThis.sessionStorage.setItem(TAB_ID_KEY, tabId)

    // Increment tab count (stored in localStorage - shared across tabs)
    const currentCount = Number.parseInt(globalThis.localStorage.getItem(TAB_COUNT_KEY) || '0', 10)
    globalThis.localStorage.setItem(TAB_COUNT_KEY, String(currentCount + 1))

    const handleBeforeUnload = () => {
      // Decrement tab count
      const count = Number.parseInt(globalThis.localStorage.getItem(TAB_COUNT_KEY) || '1', 10)
      const newCount = Math.max(0, count - 1)

      if (newCount === 0) {
        // Last tab closing - clear the cache for security
        clearChatbotSession(signedIn)
        globalThis.localStorage.removeItem(TAB_COUNT_KEY)
      } else {
        // Other tabs still open - just decrement
        globalThis.localStorage.setItem(TAB_COUNT_KEY, String(newCount))
      }
    }

    globalThis.window.addEventListener('beforeunload', handleBeforeUnload)

    return () => {
      // Cleanup on component unmount (not browser close)
      globalThis.window.removeEventListener('beforeunload', handleBeforeUnload)
      // Note: Don't decrement count here - only on actual beforeunload
      // to avoid race conditions with other tabs
    }
  }, [signedIn])
}
