import React from 'react'
import PropTypes from 'prop-types'
import { HelpChatbotApiProvider } from './useHelpChatbotApi'
import { HelpChatbotConversationProvider } from './useHelpChatbotConversation'
import { HelpChatbotAudioProvider } from './useHelpChatbotAudio'

/**
 * Combined provider that manages all help chatbot functionality.
 * This provider composes the API, conversation, and audio providers
 * in the correct order to maintain dependencies.
 */
export function HelpChatbotProvider({ children }) {
  return (
    <HelpChatbotApiProvider>
      <HelpChatbotConversationProvider>
        <HelpChatbotAudioProvider>{children}</HelpChatbotAudioProvider>
      </HelpChatbotConversationProvider>
    </HelpChatbotApiProvider>
  )
}

HelpChatbotProvider.propTypes = {
  children: PropTypes.node.isRequired,
}
