import React, { useCallback, useEffect, useRef, useMemo, useState } from 'react'
import PropTypes from 'prop-types'
import { useTranslation } from 'react-i18next'
import { SupplementalOverlay } from '@fs/zion-ui/quarks-authorized-use-only'
import { colors, LayoutBand, Row, Alert, Separator, H2, IconButton } from '@fs/zion-ui'
import { trackEvent } from '@fs/zion-analytics'
import { ArrowCaret, ContentCompose } from '@fs/zion-icon'
import { VisuallyHidden } from '@reach/visually-hidden'
import { useUser } from '@fs/zion-user'
import { useEvent } from '@fs/zion-frontend-friends'
import useHelpChatbot from './context/useHelpChatbot'
import { HelpChatbotProvider } from './context/HelpChatbotProvider'
import MessageList from './MessageList'
import HelpChatbotFooter from './ChatbotFooter'
import HelpChatbotMessageAnnouncer from './HelpChatbotMessageAnnouncer'
import NewChatConfirmation from './components/NewChatConfirmation'
import LanguageChangeNotification from './components/LanguageChangeNotification'
import { resetAudioState } from './utils/AudioManager'
import {
  clearChatbotSession,
  getCachedChatbotSession,
  LAST_INTERACTION_STORAGE_KEY,
} from './chatbot-services/chatbotSessionCache'
import useChatbotSessionExpiration from './hooks/useChatbotSessionExpiration'
import { useGuestTabSecurity } from './hooks/useGuestTabSecurity'
import { initializeScreenReaderDetection } from './utils/screenReaderDetection'
import useChatbotSessionBroadcast from './hooks/useChatbotSessionBroadcast'

const HelpChatbotContent = React.memo(function HelpChatbotContent({ overlay, minimized, sessionPreCheck }) {
  const { t } = useTranslation()
  const { signedIn } = useUser()
  const { isOpen, transitioning } = overlay
  const { apiState, conversationState, actions, api } = useHelpChatbot()
  const sessionStartedRef = useRef(false)
  const { initialized } = apiState
  const { loading, error, sessionStarted, lastApiInteraction, messages, languageMismatch } = conversationState
  const {
    startSession,
    endSession,
    expireSession,
    handleStopAudio,
    disableTextToSpeech,
    clearLanguageMismatch,
    syncMessages,
    syncTimer,
  } = actions
  const [warningShown, setWarningShown] = useState(false)
  const [showNewChatConfirmation, setShowNewChatConfirmation] = useState(false)

  // Welcome state is true by default until user sends a message
  const isWelcomeState = !messages || messages.length === 0 || !messages.some((msg) => msg.from === 'user')

  // Detect if session has expired by checking for expiration message
  const sessionExpired = messages && messages.some((msg) => msg.id?.startsWith('bot-expired-'))

  // Cross-tab session sync: broadcast state changes and receive them from other open tabs
  const { broadcastExpire, broadcastSignedOut } = useChatbotSessionBroadcast({
    messages,
    sessionStarted,
    lastApiInteraction,
    signedIn,
    syncMessages,
    expireSession,
    setLastApiInteraction: syncTimer,
  })

  // Wrap expireSession so any expiration in this tab is broadcast to all other tabs
  const expireSessionAndBroadcast = useCallback(
    (expirationMessage) => {
      broadcastExpire(expirationMessage)
      expireSession(expirationMessage)
    },
    [broadcastExpire, expireSession]
  )

  // Broadcast sign-out to other tabs when detected in this tab
  const previousSignedInRef = useRef(signedIn)
  useEffect(() => {
    const wasSignedIn = previousSignedInRef.current
    if (wasSignedIn && !signedIn) {
      broadcastSignedOut()
    }
    previousSignedInRef.current = signedIn
  }, [signedIn, broadcastSignedOut])

  useChatbotSessionExpiration({
    sessionStarted,
    isOpen,
    loading,
    error,
    lastApiInteraction,
    addBotMessage: actions.addBotMessage,
    endSession,
    expireSession: expireSessionAndBroadcast,
    setWarningShown,
    warningShown,
    clearChatbotSession: () => clearChatbotSession(signedIn),
    resetAuthentication: api.actions.resetAuthentication,
  })

  // Reset warningShown when user activity occurs or session changes
  // lastApiInteraction updates only on real user actions (sending messages, selecting options)
  // This prevents bot messages (like the warning itself) from resetting the timer
  useEffect(() => {
    setWarningShown(false)
  }, [sessionStarted, lastApiInteraction])

  // Handle session startup when overlay opens, using precheck data for immediate decisions
  useEffect(() => {
    if (!isOpen || !initialized) return

    // If already showing language mismatch notification or session already started, don't check again
    if (languageMismatch || sessionStarted || sessionStartedRef.current) return
    // If precheck is still loading, wait for it
    if (sessionPreCheck?.isLoading) return

    if (sessionPreCheck && !sessionPreCheck.isLoading) {
      if (sessionPreCheck.hasLanguageMismatch) {
        actions.setLanguageMismatch({
          previousLanguage: sessionPreCheck.previousLanguage,
          currentLanguage: sessionPreCheck.currentLanguage,
          cachedSession: sessionPreCheck.cachedSession,
        })
        return
      }

      // No mismatch - proceed with session start
      if (!loading && !error) {
        sessionStartedRef.current = true
        startSession()
      }
    }
  }, [
    isOpen,
    initialized,
    loading,
    error,
    startSession,
    signedIn,
    actions,
    languageMismatch,
    sessionStarted,
    sessionPreCheck,
  ])

  // Handle cleanup when overlay closes
  useEffect(() => {
    if (!isOpen) {
      sessionStartedRef.current = false
      handleStopAudio()
      resetAudioState()
      disableTextToSpeech()

      // End session and clear local cache only when fully closed
      // Preserve server preferences for cross-device recovery
      if (!transitioning) {
        endSession()
        clearChatbotSession(signedIn, false)
      }
    }
  }, [isOpen, transitioning, handleStopAudio, disableTextToSpeech, endSession, signedIn])

  useEffect(() => {
    return () => {
      handleStopAudio()
      resetAudioState()
    }
  }, [handleStopAudio])

  // Security: Clear cache when last tab closes (guest users only)
  useGuestTabSecurity(signedIn)

  // On bfcache page restore (user pressed back after clicking a chatbot link),
  // sync the local timer from localStorage and refresh messages from the session cache.
  // No API call needed — other tabs' interactions already kept the server-side session alive.
  // Without this, the expiration timer resumes with a stale in-memory timestamp and may fire immediately.
  useEffect(() => {
    const handlePageShow = async (event) => {
      if (!event.persisted || !sessionStarted) return
      try {
        const stored = globalThis.localStorage?.getItem(LAST_INTERACTION_STORAGE_KEY)
        if (stored) syncTimer(Number(stored))
      } catch (e) {
        console.warn('localStorage unavailable — timer stays as-is', e)
      }
      try {
        const cached = await getCachedChatbotSession(signedIn)
        if (cached?.messages?.length) syncMessages(cached.messages)
      } catch (e) {
        console.warn('Cache unavailable — messages stay as-is', e)
      }
    }
    globalThis.window?.addEventListener('pageshow', handlePageShow)
    return () => globalThis.window?.removeEventListener('pageshow', handlePageShow)
  }, [sessionStarted, syncTimer, syncMessages, signedIn])

  // Initialize screen reader detection for adaptive accessibility
  useEffect(() => {
    initializeScreenReaderDetection()
  }, [])

  // Handler for reset button - show confirmation dialog
  const handleResetChatClick = useEvent(() => {
    setShowNewChatConfirmation(true)
  })

  // Handler to confirm new chat
  const handleConfirmNewChat = useEvent(() => {
    setShowNewChatConfirmation(false)
    endSession()
    clearChatbotSession(signedIn, true) // Clear both local and server to prevent context pollution
    sessionStartedRef.current = false
    startSession()
    handleStopAudio()
    resetAudioState()
    disableTextToSpeech()
  })

  const handleCancelNewChat = useEvent(() => {
    setShowNewChatConfirmation(false)
  })

  const handleLanguageChangeStartNewChat = useEvent(async () => {
    await clearChatbotSession(signedIn, true)
    clearLanguageMismatch()
    startSession()
  })

  const handleLanguageChangeCancel = useEvent(() => {
    // Keep session intact - if user switches language back, it will restore
    clearLanguageMismatch()
    overlay.close()
  })

  // Minimize handler - useEvent provides stable reference without dependency array
  const handleMinimize = useEvent((e) => {
    trackEvent({ event_name: 'help-chatbot-minimized' })
    overlay.close(e)
  })

  let alertMessage
  if (sessionExpired) {
    alertMessage = t(
      'help-chatbot.bot-message.expiration-message',
      'This chat session has expired. To continue, please start a new chat.'
    )
  } else if (error) {
    alertMessage = t(
      'help-chatbot.message-list.alert.error',
      "Sorry. There was a connection problem. Try refreshing the page. If it still doesn't work, try again later."
    )
  } else {
    alertMessage = t('help-chatbot.message-list.alert.close-notice', 'Chats are not saved once this chat is closed')
  }

  const headerElement = useMemo(() => <H2 size="H5">{t('help-overlay-button.text', 'Help Assistant')}</H2>, [t])

  const footerElement = useMemo(
    () => (showNewChatConfirmation || sessionExpired ? null : <HelpChatbotFooter isWelcomeState={isWelcomeState} />),
    [isWelcomeState, showNewChatConfirmation, sessionExpired]
  )

  const supplementalButtons = useMemo(
    () => [
      <IconButton
        key="reset"
        Icon={ContentCompose}
        title={t('help-chatbot.new-chat', 'New Chat')}
        onClick={handleResetChatClick}
      />,
    ],
    [handleResetChatClick, t]
  )

  const closeAffordanceProps = useMemo(
    () => ({
      key: 'minimize',
      Icon: ArrowCaret,
      iconDirection: 'down',
      title: t('help-chatbot.minimize', 'Minimize'),
      onClick: handleMinimize,
    }),
    [handleMinimize, t]
  )

  if (!isOpen && !transitioning) return null
  if (minimized) return null

  return (
    <SupplementalOverlay
      overlayKey="helpChatbot"
      headerColor="gray"
      {...overlay}
      header={headerElement}
      footer={footerElement}
      supplementalButtons={supplementalButtons}
      closeAffordanceProps={closeAffordanceProps}
      defaultWidth={410}
      defaultHeight={600}
    >
      {/* Help content accessible via screen reader help commands */}
      <VisuallyHidden>
        <aside aria-label={t('help-chatbot.help-label', 'Help information')} tabIndex={-1}>
          {t(
            'help-chatbot.help-content',
            'Help Chatbot Assistant: This AI-powered assistant helps with FamilySearch questions. Type your question about features, research, or account issues, then press Enter. Use Tab key to navigate quick option buttons. Press Escape key to close the chatbot. Note: AI responses may contain errors, verify important information.'
          )}
        </aside>
      </VisuallyHidden>

      <HelpChatbotMessageAnnouncer />
      {languageMismatch && (
        <LanguageChangeNotification
          previousLanguage={languageMismatch.previousLanguage}
          currentLanguage={languageMismatch.currentLanguage}
          onStartNewChat={handleLanguageChangeStartNewChat}
          onCancel={handleLanguageChangeCancel}
        />
      )}

      {!languageMismatch && (showNewChatConfirmation || sessionExpired) && (
        <NewChatConfirmation
          onConfirm={handleConfirmNewChat}
          onCancel={handleCancelNewChat}
          isSessionExpired={sessionExpired}
        />
      )}

      {!languageMismatch && !showNewChatConfirmation && !sessionExpired && (
        <LayoutBand marginY="xs" marginX="md" maxWidth="xxs" color={colors.gray00}>
          {error && (
            <>
              <Row key="close-alert" alignX="end" gutters="xxs">
                <Alert type="error" dismissable growX>
                  {alertMessage}
                </Alert>
              </Row>
              <Separator />
            </>
          )}
          {!error && <MessageList sessionPrecheckLoading={sessionPreCheck?.isLoading} />}
        </LayoutBand>
      )}
    </SupplementalOverlay>
  )
})

HelpChatbotContent.propTypes = {
  overlay: PropTypes.shape({
    isOpen: PropTypes.bool.isRequired,
    transitioning: PropTypes.bool.isRequired,
    close: PropTypes.func.isRequired,
    handleClick: PropTypes.func.isRequired,
  }).isRequired,
  minimized: PropTypes.bool.isRequired,
  sessionPreCheck: PropTypes.shape({
    isLoading: PropTypes.bool,
    hasValidSession: PropTypes.bool,
    hasLanguageMismatch: PropTypes.bool,
    previousLanguage: PropTypes.string,
    currentLanguage: PropTypes.string,
    cachedSession: PropTypes.object,
    recheckSession: PropTypes.func,
  }),
}

HelpChatbotContent.defaultProps = {
  sessionPreCheck: null,
}

export default function HelpChatbot({ overlay, sessionPreCheck }) {
  const [minimized, setMinimized] = useState(false)

  // Reset minimized when overlay is opened
  useEffect(() => {
    if (overlay.isOpen) {
      setMinimized(false)
    }
  }, [overlay.isOpen])

  if ((overlay.isOpen || overlay.transitioning) && !minimized) {
    return (
      <HelpChatbotProvider>
        <HelpChatbotContent overlay={overlay} minimized={minimized} sessionPreCheck={sessionPreCheck} />
      </HelpChatbotProvider>
    )
  }
  return null
}

HelpChatbot.propTypes = {
  overlay: PropTypes.shape({
    isOpen: PropTypes.bool.isRequired,
    transitioning: PropTypes.bool.isRequired,
  }).isRequired,
  sessionPreCheck: PropTypes.shape({
    isLoading: PropTypes.bool,
    hasValidSession: PropTypes.bool,
    hasLanguageMismatch: PropTypes.bool,
    previousLanguage: PropTypes.string,
    currentLanguage: PropTypes.string,
    cachedSession: PropTypes.object,
    recheckSession: PropTypes.func,
  }),
}

HelpChatbot.defaultProps = {
  sessionPreCheck: null,
}
